const sourceCache = {"GameplayCore/Field/ArenaRandomReflectWallBuilder.cs": "using System;\nusing System.Collections.Generic;\nusing UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Field\n{\n    public sealed class ArenaRandomReflectWallBuilder : MonoBehaviour\n    {\n        [Header(\"References\")]\n        [SerializeField] private ArenaBoundaryBuilder _boundaryBuilder;\n        [SerializeField] private ElementFieldGrid _fieldGrid;\n        [SerializeField] private Transform _fieldSpace;\n        [SerializeField] private Transform _wallRoot;\n        [SerializeField] private GameObject _wallPrefab;\n\n        [Header(\"Seed\")]\n        [SerializeField] private int _seed = 12345;\n        [SerializeField] private bool _buildOnAwake;\n        [SerializeField] private bool _randomizeSeedOnAwake;\n\n        [Header(\"Wall Count\")]\n        [SerializeField, Min(0)] private int _minWallCount = 1;\n        [SerializeField, Min(0)] private int _maxWallCount = 5;\n\n        [Header(\"Cell Size\")]\n        [SerializeField, Min(1)] private int _minHorizontalCells = 4;\n        [SerializeField, Min(1)] private int _maxHorizontalCells = 6;\n        [SerializeField, Min(1)] private int _verticalCells = 2;\n\n        [Header(\"Placement Rules\")]\n        [SerializeField, Min(0)] private int _edgePaddingCells = 2;\n        [SerializeField, Min(0)] private int _reservedCellPadding = 3;\n        [SerializeField, Min(0)] private int _wallSpacingCells = 1;\n        [SerializeField, Min(1)] private int _maxPlacementAttemptsPerWall = 40;\n        [SerializeField] private Vector2Int[] _reservedCells =\n        {\n            new Vector2Int(4, 2),\n            new Vector2Int(13, 4),\n            new Vector2Int(13, 43)\n        };\n\n        [Header(\"Wall Settings\")]\n        [SerializeField, Min(0.01f)] private float _wallHeight = 1.5f;\n        [SerializeField] private bool _clearExistingGeneratedWalls = true;\n        [SerializeField] private bool _overrideGeneratedWallLayer = true;\n        [SerializeField] private string _generatedWallLayerName = \"Wall\";\n\n        [Header(\"Material Tiling\")]\n        [SerializeField] private bool _fitGeneratedWallMaterialTiling = true;\n        [SerializeField, Min(0.01f)] private float _wallMaterialWorldUnitsPerTile = 1f;\n\n        private const string GeneratedWallPrefix = \"GeneratedRandomReflectWall_\";\n        private readonly List<RectInt> _placedWallRects = new();\n\n        private void Reset()\n        {\n            _boundaryBuilder = GetComponent<ArenaBoundaryBuilder>();\n            _fieldGrid = FindFirstObjectByType<ElementFieldGrid>();\n            _fieldSpace = _fieldGrid != null ? _fieldGrid.FieldSpace : transform;\n            _wallRoot = _fieldSpace != null ? _fieldSpace : transform;\n        }\n\n        private void Awake()\n        {\n            if (_buildOnAwake)\n            {\n                int seed = _randomizeSeedOnAwake\n                    ? UnityEngine.Random.Range(int.MinValue, int.MaxValue)\n                    : _seed;\n\n                BuildRandomWalls(seed);\n            }\n        }\n\n        [ContextMenu(\"Build Random Reflect Walls\")]\n        public void BuildRandomWalls()\n        {\n            BuildRandomWalls(_seed);\n        }\n\n        public void BuildRandomWalls(int seed)\n        {\n            _seed = seed;\n            ResolveReferences();\n\n            if (_fieldGrid == null)\n            {\n                Debug.LogWarning(\"[ArenaRandomReflectWallBuilder] ElementFieldGrid is missing.\");\n                return;\n            }\n\n            if (_fieldSpace == null)\n            {\n                Debug.LogWarning(\"[ArenaRandomReflectWallBuilder] FieldSpace is missing.\");\n                return;\n            }\n\n            if (_wallPrefab == null)\n            {\n                Debug.LogWarning(\"[ArenaRandomReflectWallBuilder] Wall prefab is missing.\");\n                return;\n            }\n\n            if (_wallRoot == null)\n            {\n                _wallRoot = _fieldSpace;\n            }\n\n            if (_clearExistingGeneratedWalls)\n            {\n                ClearGeneratedWalls();\n            }\n\n            _placedWallRects.Clear();\n\n            System.Random random = new System.Random(seed);\n            int minCount = Mathf.Max(0, _minWallCount);\n            int maxCount = Mathf.Max(minCount, _maxWallCount);\n            int targetCount = random.Next(minCount, maxCount + 1);\n            int generatedCount = 0;\n\n            for (int i = 0; i < targetCount; i++)\n            {\n                if (!TryFindWallRect(random, out RectInt wallRect))\n                {\n                    continue;\n                }\n\n                CreateWall(generatedCount, wallRect);\n                _placedWallRects.Add(wallRect);\n                generatedCount++;\n            }\n\n            Debug.Log(\n                $\"[ArenaRandomReflectWallBuilder] Built random reflect walls. \" +\n                $\"Seed: {seed}, Requested: {targetCount}, Generated: {generatedCount}\");\n        }\n\n        public void ConfigureFromBoundaryBuilder(ArenaBoundaryBuilder boundaryBuilder)\n        {\n            if (boundaryBuilder == null)\n            {\n                return;\n            }\n\n            _boundaryBuilder = boundaryBuilder;\n            ResolveReferences();\n        }\n\n        public void SetGeneratedWallLayerName(string layerName)\n        {\n            if (string.IsNullOrWhiteSpace(layerName))\n            {\n                return;\n            }\n\n            _generatedWallLayerName = layerName;\n        }\n\n        [ContextMenu(\"Clear Random Reflect Walls\")]\n        public void ClearGeneratedWalls()\n        {\n            ResolveReferences();\n\n            if (_wallRoot == null)\n            {\n                return;\n            }\n\n            for (int i = _wallRoot.childCount - 1; i >= 0; i--)\n            {\n                Transform child = _wallRoot.GetChild(i);\n                if (!child.name.StartsWith(GeneratedWallPrefix, StringComparison.Ordinal))\n                {\n                    continue;\n                }\n\n                if (Application.isPlaying)\n                {\n                    Destroy(child.gameObject);\n                }\n                else\n                {\n                    DestroyImmediate(child.gameObject);\n                }\n            }\n\n            _placedWallRects.Clear();\n        }\n\n        private void ResolveReferences()\n        {\n            if (_boundaryBuilder == null)\n            {\n                _boundaryBuilder = GetComponent<ArenaBoundaryBuilder>();\n            }\n\n            if (_fieldGrid == null)\n            {\n                _fieldGrid = _boundaryBuilder != null && _boundaryBuilder.FieldGrid != null\n                    ? _boundaryBuilder.FieldGrid\n                    : GetComponent<ElementFieldGrid>();\n            }\n\n            if (_fieldGrid == null)\n            {\n                _fieldGrid = ElementFieldGrid.Instance != null\n                    ? ElementFieldGrid.Instance\n                    : FindFirstObjectByType<ElementFieldGrid>();\n            }\n\n            if (_fieldSpace == null && _fieldGrid != null)\n            {\n                _fieldSpace = _boundaryBuilder != null && _boundaryBuilder.FieldSpace != null\n                    ? _boundaryBuilder.FieldSpace\n                    : _fieldGrid.FieldSpace;\n            }\n\n            if (_wallRoot == null)\n            {\n                _wallRoot = _boundaryBuilder != null && _boundaryBuilder.WallRoot != null\n                    ? _boundaryBuilder.WallRoot\n                    : _fieldSpace != null ? _fieldSpace : transform;\n            }\n\n            if (_wallPrefab == null && _boundaryBuilder != null)\n            {\n                _wallPrefab = _boundaryBuilder.WallPrefab;\n            }\n\n            if (_boundaryBuilder != null && string.IsNullOrWhiteSpace(_generatedWallLayerName))\n            {\n                _generatedWallLayerName = _boundaryBuilder.GeneratedWallLayerName;\n            }\n\n            if (_boundaryBuilder != null)\n            {\n                _fitGeneratedWallMaterialTiling = _boundaryBuilder.FitGeneratedWallMaterialTiling;\n                _wallMaterialWorldUnitsPerTile = _boundaryBuilder.WallMaterialWorldUnitsPerTile;\n            }\n        }\n\n        private bool TryFindWallRect(System.Random random, out RectInt wallRect)\n        {\n            Vector2Int cellCount = _fieldGrid.CellCount;\n            int horizontalCells = Mathf.Max(1, _maxHorizontalCells);\n            int verticalCells = Mathf.Max(1, _verticalCells);\n            int edgePadding = Mathf.Max(0, _edgePaddingCells);\n\n            if (cellCount.x <= edgePadding * 2 + horizontalCells ||\n                cellCount.y <= edgePadding * 2 + verticalCells)\n            {\n                wallRect = default;\n                return false;\n            }\n\n            for (int attempt = 0; attempt < _maxPlacementAttemptsPerWall; attempt++)\n            {\n                int width = random.Next(\n                    Mathf.Max(1, _minHorizontalCells),\n                    Mathf.Max(_minHorizontalCells, _maxHorizontalCells) + 1);\n                int height = verticalCells;\n                int x = random.Next(edgePadding, cellCount.x - edgePadding - width + 1);\n                int y = random.Next(edgePadding, cellCount.y - edgePadding - height + 1);\n\n                RectInt candidate = new RectInt(x, y, width, height);\n                if (!CanPlaceWall(candidate))\n                {\n                    continue;\n                }\n\n                wallRect = candidate;\n                return true;\n            }\n\n            wallRect = default;\n            return false;\n        }\n\n        private bool CanPlaceWall(RectInt candidate)\n        {\n            if (OverlapsReservedCells(candidate))\n            {\n                return false;\n            }\n\n            RectInt paddedCandidate = Expand(candidate, _wallSpacingCells);\n\n            for (int i = 0; i < _placedWallRects.Count; i++)\n            {\n                if (Overlaps(paddedCandidate, _placedWallRects[i]))\n                {\n                    return false;\n                }\n            }\n\n            return true;\n        }\n\n        private bool OverlapsReservedCells(RectInt candidate)\n        {\n            RectInt paddedCandidate = Expand(candidate, _reservedCellPadding);\n\n            if (_reservedCells == null)\n            {\n                return false;\n            }\n\n            for (int i = 0; i < _reservedCells.Length; i++)\n            {\n                Vector2Int reservedCell = _reservedCells[i];\n                if (!_fieldGrid.IsValidCell(reservedCell))\n                {\n                    continue;\n                }\n\n                if (paddedCandidate.Contains(reservedCell))\n                {\n                    return true;\n                }\n            }\n\n            return false;\n        }\n\n        private void CreateWall(int index, RectInt wallRect)\n        {\n            GameObject wall = Instantiate(_wallPrefab, _wallRoot);\n            wall.name = $\"{GeneratedWallPrefix}{index}_{wallRect.x}_{wallRect.y}_{wallRect.width}x{wallRect.height}\";\n            wall.transform.localRotation = Quaternion.identity;\n            Vector3 localScale = GetWallLocalScale(wallRect);\n            wall.transform.localPosition = GetWallLocalPosition(wallRect);\n            wall.transform.localScale = localScale;\n            ApplyGeneratedWallLayer(wall);\n            ApplyGeneratedWallMaterialTiling(wall, localScale);\n        }\n\n        private void ApplyGeneratedWallMaterialTiling(GameObject wall, Vector3 localScale)\n        {\n            if (!_fitGeneratedWallMaterialTiling || wall == null)\n            {\n                return;\n            }\n\n            GeneratedWallMaterialTiling tiling = wall.GetComponent<GeneratedWallMaterialTiling>();\n            if (tiling == null)\n            {\n                tiling = wall.AddComponent<GeneratedWallMaterialTiling>();\n            }\n\n            tiling.Apply(localScale, _wallMaterialWorldUnitsPerTile);\n        }\n\n        private Vector3 GetWallLocalPosition(RectInt wallRect)\n        {\n            Vector2 fieldSize = _fieldGrid.FieldWorldSize;\n            Vector2 cellSize = _fieldGrid.CellWorldSize;\n\n            float centerX = -fieldSize.x * 0.5f + (wallRect.x + wallRect.width * 0.5f) * cellSize.x;\n            float centerZ = -fieldSize.y * 0.5f + (wallRect.y + wallRect.height * 0.5f) * cellSize.y;\n\n            return new Vector3(centerX, _wallHeight * 0.5f, centerZ);\n        }\n\n        private Vector3 GetWallLocalScale(RectInt wallRect)\n        {\n            Vector2 cellSize = _fieldGrid.CellWorldSize;\n            return new Vector3(\n                wallRect.width * cellSize.x,\n                _wallHeight,\n                wallRect.height * cellSize.y\n            );\n        }\n\n        private void ApplyGeneratedWallLayer(GameObject wall)\n        {\n            if (!_overrideGeneratedWallLayer || wall == null || string.IsNullOrWhiteSpace(_generatedWallLayerName))\n            {\n                return;\n            }\n\n            int layer = ResolveGeneratedWallLayer();\n            if (layer < 0)\n            {\n                Debug.LogWarning($\"[ArenaRandomReflectWallBuilder] Wall layer not found. Requested: {_generatedWallLayerName}\");\n                return;\n            }\n\n            SetLayerRecursively(wall.transform, layer);\n        }\n\n        private int ResolveGeneratedWallLayer()\n        {\n            int configuredLayer = LayerMask.NameToLayer(_generatedWallLayerName);\n            if (configuredLayer >= 0)\n            {\n                return configuredLayer;\n            }\n\n            int pvpWallLayer = LayerMask.NameToLayer(\"PvpWall\");\n            if (pvpWallLayer >= 0)\n            {\n                return pvpWallLayer;\n            }\n\n            int pvpwallLayer = LayerMask.NameToLayer(\"Pvpwall\");\n            if (pvpwallLayer >= 0)\n            {\n                return pvpwallLayer;\n            }\n\n            return LayerMask.NameToLayer(\"Wall\");\n        }\n\n        private static RectInt Expand(RectInt rect, int padding)\n        {\n            int safePadding = Mathf.Max(0, padding);\n            return new RectInt(\n                rect.x - safePadding,\n                rect.y - safePadding,\n                rect.width + safePadding * 2,\n                rect.height + safePadding * 2\n            );\n        }\n\n        private static bool Overlaps(RectInt a, RectInt b)\n        {\n            return a.xMin < b.xMax &&\n                   a.xMax > b.xMin &&\n                   a.yMin < b.yMax &&\n                   a.yMax > b.yMin;\n        }\n\n        private static void SetLayerRecursively(Transform target, int layer)\n        {\n            target.gameObject.layer = layer;\n\n            for (int i = 0; i < target.childCount; i++)\n            {\n                SetLayerRecursively(target.GetChild(i), layer);\n            }\n        }\n    }\n}\n", "GameplayCore/Field/ArenaTerrainPainter.cs": "using Shield_Shot.GameplayCore.Monster.Difficulty;\nusing Shield_Shot.GameplayCore.Monster.Stage;\nusing System.Collections.Generic;\nusing UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Field\n{\n    public class ArenaTerrainPainter : MonoBehaviour\n    {\n        [Header(\"References\")]\n        [SerializeField] private ElementFieldGrid _fieldGrid;\n        [SerializeField] private Terrain _terrain;\n        [SerializeField] private ArenaTerrainThemeSO _theme;\n        [SerializeField] private List<ArenaTerrainThemeSO> _themeDB;\n\n        [Header(\"Generate\")]\n        [SerializeField] private bool _fillGridWithBaseTerrain = true;\n        [SerializeField] private bool _resizeTerrainToField = true;\n        [SerializeField] private bool _alignSurfaceToFieldPlane = true;\n        [SerializeField] private float _targetSurfaceYOffset;\n        [SerializeField, Min(16)] private int _alphamapResolution = 256;\n\n        [Header(\"Theme Generation\")]\n        [SerializeField] private int _seed = 12345;\n        [SerializeField] private bool _randomizeSeed;\n\n        [Header(\"Test Pond\")]\n        [SerializeField] private Vector2Int _pondCenterCell = new Vector2Int(-1, -1);\n        [SerializeField, Min(1)] private int _pondRadiusCells = 3;\n        [SerializeField, Min(0)] private int _pondBankWidthCells = 1;\n        [SerializeField] private bool _usePondBankTerrain;\n        [SerializeField] private TerrainElementType _pondBankTerrain = TerrainElementType.Mud;\n        [SerializeField, Min(0f)] private float _pondDepth = 0.45f;\n        [SerializeField, Range(0f, 1f)] private float _pondFloorBlend = 0.35f;\n        [SerializeField, Range(0f, 1f)] private float _pondEdgeNoise = 0.35f;\n        [SerializeField] private bool _autoRaiseBaseHeightForPonds = true;\n        [SerializeField, Range(0f, 1f)] private float _baseHeight = 0f;\n        [SerializeField] private Transform _waterSurfaceRoot;\n\n        [Header(\"Water Surface\")]\n        [SerializeField] private bool _useProceduralWaterSurface = true;\n        [SerializeField, Range(8, 96)] private int _waterSurfaceSegments = 40;\n        [SerializeField, Range(0f, 0.5f)] private float _waterSurfaceEdgeNoise = 0.18f;\n        [SerializeField, Range(0f, 1f)] private float _waterFillDepthRatio = 0.55f;\n        [SerializeField] private Material _iceWaterSurfaceMaterial;\n\n        private readonly Dictionary<TerrainElementType, int> _layerIndexByTerrain = new();\n        private readonly List<GameObject> _spawnedWaterSurfaces = new();\n        private readonly List<Vector2Int> _generatedPondCenters = new();\n        private readonly List<int> _generatedPondRadii = new();\n\n        private void Reset()\n        {\n            _fieldGrid = FindFirstObjectByType<ElementFieldGrid>();\n            _terrain = GetComponent<Terrain>();\n\n            if (_terrain == null)\n            {\n                _terrain = FindFirstObjectByType<Terrain>();\n            }\n        }\n\n        private void OnEnable()\n        {\n            ElementFieldGrid grid = ResolveGrid();\n            if (grid != null)\n            {\n                grid.TerrainChanged += HandleTerrainChanged;\n            }\n        }\n\n        private void OnDisable()\n        {\n            ElementFieldGrid grid = ResolveGrid();\n            if (grid != null)\n            {\n                grid.TerrainChanged -= HandleTerrainChanged;\n            }\n        }\n\n        [ContextMenu(\"Generate Theme Terrain\")]\n        public void GenerateThemeTerrain()\n        {\n            ElementFieldGrid grid = ResolveGrid();\n            TerrainData terrainData = PrepareTerrainForGeneration(grid, resetGridTerrain: true);\n\n            if (grid == null || terrainData == null)\n            {\n                return;\n            }\n\n            int seed = _randomizeSeed ? Random.Range(int.MinValue, int.MaxValue) : _seed;\n            Random.InitState(seed);\n\n            int pondCount = GeneratePondsFromTheme(grid);\n\n            PaintAlphamap(grid, terrainData);\n            SculptWaterCells(grid, terrainData);\n            RebuildGeneratedWaterSurfaces(grid, terrainData);\n\n            Debug.Log(\n                $\"[ArenaTerrainPainter] Generated theme terrain. \" +\n                $\"Seed: {seed}, Ponds: {pondCount}\"\n            );\n        }\n\n\n        public void ValidateTheme()\n        {\n            if (_themeDB == null || _themeDB.Count == 0)\n            {\n                return;\n            }\n\n            switch (StageManager.Instance.CurrentBiom)\n            {\n                case ChapterBiom.Grassland:\n                    _theme = _themeDB.Find(theme => theme.ThemeName == \"Grassland\");\n                    break;\n                case ChapterBiom.Desert:\n                    _theme = _themeDB.Find(theme => theme.ThemeName == \"Desert\");\n                    break;\n                case ChapterBiom.Swamp:\n                    _theme = _themeDB.Find(theme => theme.ThemeName == \"Swamp\");\n                    break;\n            }\n\n            GenerateThemeTerrain();\n        }\n\n        public void GenerateThemeTerrain(int seed)\n        {\n            _seed = seed;\n            _randomizeSeed = false;\n            GenerateThemeTerrain();\n        }\n\n        private int GeneratePondsFromTheme(ElementFieldGrid grid)\n        {\n            ArenaTerrainThemeSO.PondRule rule = _theme.Pond;\n            _generatedPondCenters.Clear();\n            _generatedPondRadii.Clear();\n\n            if (!rule.Enabled)\n            {\n                return 0;\n            }\n\n            int minCount = Mathf.Max(0, rule.MinCount);\n            int maxCount = Mathf.Max(minCount, rule.MaxCount);\n            int count = Random.Range(minCount, maxCount + 1);\n\n            List<Vector2Int> centers = new();\n            int generatedCount = 0;\n\n            for (int i = 0; i < count; i++)\n            {\n                int minRadius = Mathf.Max(1, rule.MinRadiusCells);\n                int maxRadius = Mathf.Max(minRadius, rule.MaxRadiusCells);\n                int radius = Random.Range(minRadius, maxRadius + 1);\n\n                if (!TryFindPondCenter(grid, centers, rule, radius, out Vector2Int center))\n                {\n                    continue;\n                }\n\n                ApplyPondTerrainCells(grid, center, radius);\n                centers.Add(center);\n                _generatedPondCenters.Add(center);\n                _generatedPondRadii.Add(radius);\n                generatedCount++;\n            }\n\n            return generatedCount;\n        }\n\n        private bool TryFindPondCenter(\n    ElementFieldGrid grid,\n    List<Vector2Int> existingCenters,\n    ArenaTerrainThemeSO.PondRule rule,\n    int radiusCells,\n    out Vector2Int center)\n        {\n            Vector2Int cellCount = grid.CellCount;\n            int minDistance = Mathf.Max(0, rule.MinDistanceCells);\n            int margin = Mathf.Max(0, radiusCells + (_usePondBankTerrain ? _pondBankWidthCells : 0));\n\n            if (cellCount.x <= margin * 2 || cellCount.y <= margin * 2)\n            {\n                center = default;\n                return false;\n            }\n\n            for (int attempt = 0; attempt < 50; attempt++)\n            {\n                Vector2Int candidate = new Vector2Int(\n                    Random.Range(margin, cellCount.x - margin),\n                    Random.Range(margin, cellCount.y - margin)\n                );\n\n                bool tooClose = false;\n\n                for (int i = 0; i < existingCenters.Count; i++)\n                {\n                    if (Vector2Int.Distance(candidate, existingCenters[i]) < minDistance)\n                    {\n                        tooClose = true;\n                        break;\n                    }\n                }\n\n                if (tooClose)\n                {\n                    continue;\n                }\n\n                center = candidate;\n                return true;\n            }\n\n            center = default;\n            return false;\n        }\n\n        private void ApplyPondTerrainCells(ElementFieldGrid grid, Vector2Int centerCell)\n        {\n            ApplyPondTerrainCells(grid, centerCell, _pondRadiusCells);\n        }\n        private void ApplyPondTerrainCells(\n    ElementFieldGrid grid,\n    Vector2Int centerCell,\n    int radiusCells)\n        {\n            int pondRadius = Mathf.Max(1, radiusCells);\n            int bankWidth = _usePondBankTerrain ? Mathf.Max(0, _pondBankWidthCells) : 0;\n            int totalRadius = pondRadius + bankWidth;\n\n            for (int x = -totalRadius; x <= totalRadius; x++)\n            {\n                for (int y = -totalRadius; y <= totalRadius; y++)\n                {\n                    Vector2Int coord = centerCell + new Vector2Int(x, y);\n\n                    if (!grid.IsValidCell(coord))\n                    {\n                        continue;\n                    }\n\n                    float distance = new Vector2(x, y).magnitude;\n                    float edgeNoise = (Hash01(centerCell.x, centerCell.y, coord.x, coord.y) - 0.5f) *\n                                      _pondEdgeNoise * Mathf.Max(1f, pondRadius);\n                    float waterRadius = pondRadius + edgeNoise;\n\n                    if (distance <= waterRadius)\n                    {\n                        grid.SetTerrainCell(coord, TerrainElementType.Water);\n                        continue;\n                    }\n\n                    if (_usePondBankTerrain && distance <= totalRadius)\n                    {\n                        grid.SetTerrainCell(coord, _pondBankTerrain);\n                    }\n                }\n            }\n        }\n\n        [ContextMenu(\"Apply Theme To Terrain\")]\n        public void ApplyThemeToTerrain()\n        {\n            ElementFieldGrid grid = ResolveGrid();\n            TerrainData terrainData = PrepareTerrainForGeneration(grid, resetGridTerrain: _fillGridWithBaseTerrain);\n\n            if (terrainData == null)\n            {\n                return;\n            }\n\n            Debug.Log(\n                $\"[ArenaTerrainPainter] Applied terrain theme. Theme: {_theme.ThemeName}, \" +\n                $\"BaseTerrain: {_theme.BaseTerrain}, Alphamap: {terrainData.alphamapWidth}x{terrainData.alphamapHeight}\"\n            );\n        }\n\n        [ContextMenu(\"Generate Test Pond\")]\n        public void GenerateTestPond()\n        {\n            ElementFieldGrid grid = ResolveGrid();\n            TerrainData terrainData = PrepareTerrainForGeneration(grid, resetGridTerrain: true);\n\n            if (grid == null || terrainData == null)\n            {\n                return;\n            }\n\n            Vector2Int centerCell = ResolvePondCenterCell(grid);\n            ApplyPondTerrainCells(grid, centerCell);\n            PaintAlphamap(grid, terrainData);\n            SculptPond(grid, terrainData, centerCell);\n            RebuildWaterSurface(grid, terrainData, centerCell);\n\n            Debug.Log(\n                $\"[ArenaTerrainPainter] Generated test pond. Center: {centerCell}, \" +\n                $\"RadiusCells: {_pondRadiusCells}, BankCells: {_pondBankWidthCells}, Depth: {_pondDepth:0.00}\"\n            );\n        }\n\n        [ContextMenu(\"Reset Arena Terrain\")]\n        public void ResetArenaTerrain()\n        {\n            ElementFieldGrid grid = ResolveGrid();\n            TerrainData terrainData = PrepareTerrainForGeneration(grid, resetGridTerrain: true);\n\n            if (terrainData == null)\n            {\n                return;\n            }\n\n            Debug.Log(\n                $\"[ArenaTerrainPainter] Reset arena terrain. Theme: {_theme.ThemeName}, \" +\n                $\"BaseTerrain: {_theme.BaseTerrain}\"\n            );\n        }\n\n        [ContextMenu(\"Clear Generated Water Surfaces\")]\n        public void ClearGeneratedWaterSurfaces()\n        {\n            for (int i = _spawnedWaterSurfaces.Count - 1; i >= 0; i--)\n            {\n                GameObject surface = _spawnedWaterSurfaces[i];\n\n                if (surface == null)\n                {\n                    continue;\n                }\n\n                if (Application.isPlaying)\n                {\n                    Destroy(surface);\n                }\n                else\n                {\n                    DestroyImmediate(surface);\n                }\n            }\n\n            _spawnedWaterSurfaces.Clear();\n        }\n\n        private TerrainData PrepareTerrainForGeneration(ElementFieldGrid grid, bool resetGridTerrain)\n        {\n            if (grid == null)\n            {\n                Debug.LogWarning(\"[ArenaTerrainPainter] ElementFieldGrid is missing.\");\n                return null;\n            }\n\n            if (_terrain == null)\n            {\n                Debug.LogWarning(\"[ArenaTerrainPainter] Terrain is missing.\");\n                return null;\n            }\n\n            if (_theme == null)\n            {\n                Debug.LogWarning(\"[ArenaTerrainPainter] ArenaTerrainThemeSO is missing.\");\n                return null;\n            }\n\n            TerrainData terrainData = _terrain.terrainData;\n\n            if (terrainData == null)\n            {\n                Debug.LogWarning(\"[ArenaTerrainPainter] TerrainData is missing.\");\n                return null;\n            }\n\n            ClearGeneratedWaterSurfaces();\n\n            if (resetGridTerrain)\n            {\n                grid.FillTerrain(_theme.BaseTerrain);\n            }\n\n            ConfigureTerrainData(grid, terrainData);\n\n            if (!ConfigureTerrainLayers(terrainData))\n            {\n                return null;\n            }\n\n            ResetTerrainHeights(terrainData);\n            PaintAlphamap(grid, terrainData);\n\n            return terrainData;\n        }\n\n        private ElementFieldGrid ResolveGrid()\n        {\n            if (_fieldGrid == null)\n            {\n                _fieldGrid = ElementFieldGrid.Instance != null\n                    ? ElementFieldGrid.Instance\n                    : FindFirstObjectByType<ElementFieldGrid>();\n            }\n\n            return _fieldGrid;\n        }\n\n        private void ConfigureTerrainData(ElementFieldGrid grid, TerrainData terrainData)\n        {\n            if (_resizeTerrainToField)\n            {\n                Vector2 fieldSize = grid.FieldWorldSize;\n                Vector3 terrainSize = terrainData.size;\n                terrainData.size = new Vector3(fieldSize.x, terrainSize.y, fieldSize.y);\n\n                Vector3 fieldCenter = grid.FieldCenter;\n                _terrain.transform.position = new Vector3(\n                    fieldCenter.x - fieldSize.x * 0.5f,\n                    _terrain.transform.position.y,\n                    fieldCenter.z - fieldSize.y * 0.5f\n                );\n            }\n\n            if (_alignSurfaceToFieldPlane)\n            {\n                Vector3 terrainPosition = _terrain.transform.position;\n                float baseHeight = ResolvePondBaseHeight(terrainData);\n                float targetSurfaceY = grid.FieldCenter.y + _targetSurfaceYOffset;\n                terrainPosition.y = targetSurfaceY - baseHeight * terrainData.size.y;\n                _terrain.transform.position = terrainPosition;\n            }\n\n            if (terrainData.alphamapResolution != _alphamapResolution)\n            {\n                terrainData.alphamapResolution = _alphamapResolution;\n            }\n        }\n\n        private bool ConfigureTerrainLayers(TerrainData terrainData)\n        {\n            _layerIndexByTerrain.Clear();\n\n            ArenaTerrainThemeSO.TerrainLayerEntry[] entries = _theme.TerrainLayers;\n\n            if (entries == null || entries.Length == 0)\n            {\n                Debug.LogWarning(\"[ArenaTerrainPainter] Theme terrain layers are empty.\");\n                return false;\n            }\n\n            List<TerrainLayer> layers = new();\n\n            for (int i = 0; i < entries.Length; i++)\n            {\n                ArenaTerrainThemeSO.TerrainLayerEntry entry = entries[i];\n\n                if (entry.Layer == null || _layerIndexByTerrain.ContainsKey(entry.Terrain))\n                {\n                    continue;\n                }\n\n                _layerIndexByTerrain.Add(entry.Terrain, layers.Count);\n                layers.Add(entry.Layer);\n            }\n\n            if (layers.Count == 0)\n            {\n                Debug.LogWarning(\"[ArenaTerrainPainter] No valid TerrainLayer entries found.\");\n                return false;\n            }\n\n            if (!_layerIndexByTerrain.ContainsKey(_theme.BaseTerrain))\n            {\n                Debug.LogWarning(\n                    $\"[ArenaTerrainPainter] Base terrain layer is missing. \" +\n                    $\"BaseTerrain: {_theme.BaseTerrain}. Add a TerrainLayer entry for the base terrain.\"\n                );\n                return false;\n            }\n\n            terrainData.terrainLayers = layers.ToArray();\n            return true;\n        }\n\n        private Vector2Int ResolvePondCenterCell(ElementFieldGrid grid)\n        {\n            if (grid.IsValidCell(_pondCenterCell))\n            {\n                return _pondCenterCell;\n            }\n\n            Vector2Int cellCount = grid.CellCount;\n            return new Vector2Int(\n                Mathf.Max(0, cellCount.x / 2),\n                Mathf.Max(0, cellCount.y / 2)\n            );\n        }\n\n        private void SculptPond(\n            ElementFieldGrid grid,\n            TerrainData terrainData,\n            Vector2Int centerCell)\n        {\n            int heightmapResolution = terrainData.heightmapResolution;\n            float[,] heights = terrainData.GetHeights(0, 0, heightmapResolution, heightmapResolution);\n            Vector3 pondCenter = grid.CellToWorld(centerCell);\n            float cellSize = grid.CellSize;\n            float pondRadius = Mathf.Max(cellSize, _pondRadiusCells * cellSize);\n            float bankWidth = Mathf.Max(cellSize * 0.25f, _pondBankWidthCells * cellSize);\n            float totalRadius = pondRadius + bankWidth;\n            float normalizedDepth = _pondDepth / Mathf.Max(0.001f, terrainData.size.y);\n\n            for (int y = 0; y < heightmapResolution; y++)\n            {\n                for (int x = 0; x < heightmapResolution; x++)\n                {\n                    Vector3 worldPosition = HeightmapToWorldPosition(x, y, heightmapResolution, terrainData);\n                    Vector2 flatDelta = new Vector2(\n                        worldPosition.x - pondCenter.x,\n                        worldPosition.z - pondCenter.z\n                    );\n                    float distance = flatDelta.magnitude;\n\n                    if (distance > totalRadius)\n                    {\n                        continue;\n                    }\n\n                    float targetDepth = distance <= pondRadius\n                        ? normalizedDepth\n                        : normalizedDepth * Mathf.SmoothStep(1f, 0f, (distance - pondRadius) / bankWidth);\n\n                    heights[y, x] = Mathf.Max(0f, heights[y, x] - targetDepth * Mathf.Lerp(1f, _pondFloorBlend, distance / totalRadius));\n                }\n            }\n\n            terrainData.SetHeights(0, 0, heights);\n        }\n        private void SculptWaterCells(ElementFieldGrid grid, TerrainData terrainData)\n        {\n            if (_generatedPondCenters.Count == 0)\n            {\n                return;\n            }\n\n            int heightmapResolution = terrainData.heightmapResolution;\n            float[,] heights = terrainData.GetHeights(0, 0, heightmapResolution, heightmapResolution);\n\n            float cellSize = grid.CellSize;\n            float bankWidth = Mathf.Max(cellSize * 0.25f, _pondBankWidthCells * cellSize);\n            float normalizedDepth = _pondDepth / Mathf.Max(0.001f, terrainData.size.y);\n            float baseHeight = ResolvePondBaseHeight(terrainData);\n\n            for (int y = 0; y < heightmapResolution; y++)\n            {\n                for (int x = 0; x < heightmapResolution; x++)\n                {\n                    Vector3 worldPosition = HeightmapToWorldPosition(x, y, heightmapResolution, terrainData);\n                    float lowestTargetHeight = baseHeight;\n\n                    for (int i = 0; i < _generatedPondCenters.Count; i++)\n                    {\n                        Vector2Int centerCell = _generatedPondCenters[i];\n                        int radiusCells = i < _generatedPondRadii.Count ? _generatedPondRadii[i] : _pondRadiusCells;\n                        Vector3 pondCenter = grid.CellToWorld(centerCell);\n                        float pondRadius = Mathf.Max(cellSize, radiusCells * cellSize);\n                        float totalRadius = pondRadius + bankWidth;\n                        Vector2 delta = new Vector2(\n                            worldPosition.x - pondCenter.x,\n                            worldPosition.z - pondCenter.z\n                        );\n                        float distance = delta.magnitude;\n\n                        if (distance > totalRadius)\n                        {\n                            continue;\n                        }\n\n                        float depth01;\n\n                        if (distance <= pondRadius)\n                        {\n                            depth01 = 1f;\n                        }\n                        else\n                        {\n                            float bankT = (distance - pondRadius) / Mathf.Max(0.001f, bankWidth);\n                            depth01 = Mathf.SmoothStep(1f, 0f, bankT);\n                        }\n\n                        float floorBlend = Mathf.Lerp(1f, _pondFloorBlend, distance / Mathf.Max(0.001f, totalRadius));\n                        float targetHeight = baseHeight - normalizedDepth * depth01 * floorBlend;\n                        lowestTargetHeight = Mathf.Min(lowestTargetHeight, targetHeight);\n                    }\n\n                    heights[y, x] = Mathf.Min(heights[y, x], Mathf.Max(0f, lowestTargetHeight));\n                }\n            }\n\n            terrainData.SetHeights(0, 0, heights);\n        }\n        private void ResetTerrainHeights(TerrainData terrainData)\n        {\n            int heightmapResolution = terrainData.heightmapResolution;\n            float[,] heights = new float[heightmapResolution, heightmapResolution];\n            float baseHeight = ResolvePondBaseHeight(terrainData);\n\n            for (int y = 0; y < heightmapResolution; y++)\n            {\n                for (int x = 0; x < heightmapResolution; x++)\n                {\n                    heights[y, x] = baseHeight;\n                }\n            }\n\n            terrainData.SetHeights(0, 0, heights);\n        }\n\n        private List<Vector3> CollectWaterCellWorldPositions(ElementFieldGrid grid)\n        {\n            List<Vector3> positions = new();\n            Vector2Int cellCount = grid.CellCount;\n\n            for (int x = 0; x < cellCount.x; x++)\n            {\n                for (int y = 0; y < cellCount.y; y++)\n                {\n                    Vector2Int coord = new Vector2Int(x, y);\n\n                    if (!grid.TryGetCellData(coord, out ElementFieldCellData data) ||\n                        data.TerrainElement != TerrainElementType.Water)\n                    {\n                        continue;\n                    }\n\n                    positions.Add(grid.CellToWorld(coord));\n                }\n            }\n\n            return positions;\n        }\n\n        private float ResolvePondBaseHeight(TerrainData terrainData)\n        {\n            if (!_autoRaiseBaseHeightForPonds)\n            {\n                return _baseHeight;\n            }\n\n            float normalizedDepth = _pondDepth / Mathf.Max(0.001f, terrainData.size.y);\n            return Mathf.Clamp01(Mathf.Max(_baseHeight, normalizedDepth + 0.02f));\n        }\n\n        private Vector3 HeightmapToWorldPosition(\n            int x,\n            int y,\n            int resolution,\n            TerrainData terrainData)\n        {\n            float normalizedX = resolution > 1 ? x / (float)(resolution - 1) : 0f;\n            float normalizedZ = resolution > 1 ? y / (float)(resolution - 1) : 0f;\n            Vector3 terrainPosition = _terrain.transform.position;\n            Vector3 terrainSize = terrainData.size;\n\n            return new Vector3(\n                terrainPosition.x + normalizedX * terrainSize.x,\n                terrainPosition.y,\n                terrainPosition.z + normalizedZ * terrainSize.z\n            );\n        }\n\n        private void RebuildWaterSurface(\n            ElementFieldGrid grid,\n            TerrainData terrainData,\n            Vector2Int centerCell)\n        {\n            if (_theme.WaterSurfacePrefab == null)\n            {\n                return;\n            }\n\n            ClearGeneratedWaterSurfaces();\n\n            Transform parent = _waterSurfaceRoot != null ? _waterSurfaceRoot : transform;\n            Vector3 pondCenter = grid.CellToWorld(centerCell);\n            float cellSize = grid.CellSize;\n            float diameter = Mathf.Max(cellSize, _pondRadiusCells * cellSize * 2f);\n            float terrainHeight = _terrain.SampleHeight(pondCenter) + _terrain.transform.position.y;\n            Vector3 waterPosition = new Vector3(\n                pondCenter.x,\n                terrainHeight + _theme.WaterSurfaceYOffset,\n                pondCenter.z\n            );\n\n            GameObject waterSurface = Instantiate(_theme.WaterSurfacePrefab, waterPosition, Quaternion.identity, parent);\n            waterSurface.name = $\"WaterSurface_Pond_{centerCell.x}_{centerCell.y}\";\n            FitWaterSurfaceToDiameter(waterSurface, diameter);\n            _spawnedWaterSurfaces.Add(waterSurface);\n            ApplyWaterSurfaceMaterialForTerrain(grid, waterSurface, centerCell);\n        }\n\n        private void RebuildGeneratedWaterSurfaces(ElementFieldGrid grid, TerrainData terrainData)\n        {\n            if (_theme.WaterSurfacePrefab == null)\n            {\n                return;\n            }\n\n            ClearGeneratedWaterSurfaces();\n\n            for (int i = 0; i < _generatedPondCenters.Count; i++)\n            {\n                Vector2Int center = _generatedPondCenters[i];\n                int radius = i < _generatedPondRadii.Count ? _generatedPondRadii[i] : _pondRadiusCells;\n                SpawnWaterSurface(grid, terrainData, center, radius);\n            }\n\n            RefreshFrozenWaterSurfaceMaterials(grid);\n        }\n\n        private void SpawnWaterSurface(\n            ElementFieldGrid grid,\n            TerrainData terrainData,\n            Vector2Int centerCell,\n            int radiusCells)\n        {\n            Transform parent = _waterSurfaceRoot != null ? _waterSurfaceRoot : transform;\n            Vector3 pondCenter = grid.CellToWorld(centerCell);\n            float cellSize = grid.CellSize;\n            float diameter = Mathf.Max(cellSize, radiusCells * cellSize * 2f);\n            float terrainHeight = ResolveWaterSurfaceHeight(terrainData);\n            Vector3 waterPosition = new Vector3(\n                pondCenter.x,\n                terrainHeight + _theme.WaterSurfaceYOffset,\n                pondCenter.z\n            );\n\n            if (_useProceduralWaterSurface && TryGetWaterSurfaceMaterial(out Material waterMaterial))\n            {\n                GameObject proceduralSurface = CreateProceduralWaterSurface(\n                    waterPosition,\n                    diameter,\n                    centerCell,\n                    waterMaterial,\n                    parent\n                );\n                _spawnedWaterSurfaces.Add(proceduralSurface);\n                ApplyWaterSurfaceMaterialForTerrain(grid, proceduralSurface, centerCell);\n                return;\n            }\n\n            GameObject waterSurface = Instantiate(_theme.WaterSurfacePrefab, waterPosition, Quaternion.identity, parent);\n            waterSurface.name = $\"WaterSurface_Pond_{centerCell.x}_{centerCell.y}\";\n            FitWaterSurfaceToDiameter(waterSurface, diameter);\n            _spawnedWaterSurfaces.Add(waterSurface);\n            ApplyWaterSurfaceMaterialForTerrain(grid, waterSurface, centerCell);\n        }\n\n        private bool TryGetWaterSurfaceMaterial(out Material material)\n        {\n            material = null;\n\n            if (_theme.WaterSurfacePrefab == null)\n            {\n                return false;\n            }\n\n            Renderer renderer = _theme.WaterSurfacePrefab.GetComponentInChildren<Renderer>();\n\n            if (renderer == null || renderer.sharedMaterial == null)\n            {\n                return false;\n            }\n\n            material = renderer.sharedMaterial;\n            return true;\n        }\n\n        private GameObject CreateProceduralWaterSurface(\n            Vector3 waterPosition,\n            float diameter,\n            Vector2Int centerCell,\n            Material waterMaterial,\n            Transform parent)\n        {\n            GameObject waterSurface = new GameObject($\"WaterSurface_Pond_{centerCell.x}_{centerCell.y}\");\n            waterSurface.transform.SetParent(parent, false);\n            waterSurface.transform.position = waterPosition;\n\n            MeshFilter meshFilter = waterSurface.AddComponent<MeshFilter>();\n            MeshRenderer meshRenderer = waterSurface.AddComponent<MeshRenderer>();\n            meshRenderer.sharedMaterial = waterMaterial;\n\n            int segments = Mathf.Max(8, _waterSurfaceSegments);\n            Vector3[] vertices = new Vector3[segments + 1];\n            Vector2[] uvs = new Vector2[vertices.Length];\n            int[] triangles = new int[segments * 3];\n            float radius = diameter * 0.5f;\n\n            vertices[0] = Vector3.zero;\n            uvs[0] = new Vector2(0.5f, 0.5f);\n\n            for (int i = 0; i < segments; i++)\n            {\n                float angle = (i / (float)segments) * Mathf.PI * 2f;\n                float noise = Hash01(centerCell.x, centerCell.y, i, 97) - 0.5f;\n                float edgeRadius = radius * (1f + noise * _waterSurfaceEdgeNoise);\n                float x = Mathf.Cos(angle) * edgeRadius;\n                float z = Mathf.Sin(angle) * edgeRadius;\n\n                vertices[i + 1] = new Vector3(x, 0f, z);\n                uvs[i + 1] = new Vector2(\n                    0.5f + x / Mathf.Max(0.001f, diameter),\n                    0.5f + z / Mathf.Max(0.001f, diameter)\n                );\n\n                int triangleIndex = i * 3;\n                triangles[triangleIndex] = 0;\n                triangles[triangleIndex + 1] = i == segments - 1 ? 1 : i + 2;\n                triangles[triangleIndex + 2] = i + 1;\n            }\n\n            Mesh mesh = new Mesh\n            {\n                name = waterSurface.name + \"_Mesh\",\n                vertices = vertices,\n                uv = uvs,\n                triangles = triangles\n            };\n            mesh.RecalculateNormals();\n            mesh.RecalculateBounds();\n            meshFilter.sharedMesh = mesh;\n\n            return waterSurface;\n        }\n\n        private float ResolveWaterSurfaceHeight(TerrainData terrainData)\n        {\n            float baseWorldHeight = _terrain.transform.position.y + ResolvePondBaseHeight(terrainData) * terrainData.size.y;\n            float fillDepth = _pondDepth * Mathf.Clamp01(_waterFillDepthRatio);\n            return baseWorldHeight - fillDepth;\n        }\n\n        private void FitWaterSurfaceToDiameter(GameObject waterSurface, float diameter)\n        {\n            if (waterSurface == null)\n            {\n                return;\n            }\n\n            if (!TryGetRendererBounds(waterSurface, out Bounds bounds))\n            {\n                waterSurface.transform.localScale = new Vector3(diameter, 1f, diameter);\n                return;\n            }\n\n            float currentWidth = Mathf.Max(0.001f, bounds.size.x);\n            float currentDepth = Mathf.Max(0.001f, bounds.size.z);\n            Vector3 scale = waterSurface.transform.localScale;\n\n            scale.x *= diameter / currentWidth;\n            scale.z *= diameter / currentDepth;\n            waterSurface.transform.localScale = scale;\n        }\n\n        private static bool TryGetRendererBounds(GameObject target, out Bounds bounds)\n        {\n            Renderer[] renderers = target.GetComponentsInChildren<Renderer>();\n            bounds = default;\n            bool hasBounds = false;\n\n            for (int i = 0; i < renderers.Length; i++)\n            {\n                Renderer renderer = renderers[i];\n\n                if (renderer == null)\n                {\n                    continue;\n                }\n\n                if (!hasBounds)\n                {\n                    bounds = renderer.bounds;\n                    hasBounds = true;\n                    continue;\n                }\n\n                bounds.Encapsulate(renderer.bounds);\n            }\n\n            return hasBounds;\n        }\n\n        private void HandleTerrainChanged(Vector2Int coord, ElementFieldCellData data)\n        {\n            if (data.TerrainElement != TerrainElementType.Ice)\n            {\n                return;\n            }\n\n            ElementFieldGrid grid = ResolveGrid();\n            if (grid != null)\n            {\n                RefreshFrozenWaterSurfaceMaterials(grid);\n            }\n        }\n\n        private void RefreshFrozenWaterSurfaceMaterials(ElementFieldGrid grid)\n        {\n            if (grid == null || _iceWaterSurfaceMaterial == null)\n            {\n                return;\n            }\n\n            RefreshWaterSurfaceListFromHierarchy();\n\n            for (int i = 0; i < _spawnedWaterSurfaces.Count; i++)\n            {\n                GameObject surface = _spawnedWaterSurfaces[i];\n                if (surface == null)\n                {\n                    continue;\n                }\n\n                if (!DoesSurfaceTouchFrozenTerrain(grid, surface))\n                {\n                    continue;\n                }\n\n                ApplyWaterSurfaceMaterial(surface, _iceWaterSurfaceMaterial);\n            }\n        }\n\n        private void ApplyWaterSurfaceMaterialForTerrain(\n            ElementFieldGrid grid,\n            GameObject waterSurface,\n            Vector2Int centerCell)\n        {\n            if (grid == null ||\n                waterSurface == null ||\n                _iceWaterSurfaceMaterial == null ||\n                !grid.TryGetCellData(centerCell, out ElementFieldCellData data) ||\n                data.TerrainElement != TerrainElementType.Ice)\n            {\n                return;\n            }\n\n            ApplyWaterSurfaceMaterial(waterSurface, _iceWaterSurfaceMaterial);\n        }\n\n        private void RefreshWaterSurfaceListFromHierarchy()\n        {\n            Transform root = _waterSurfaceRoot != null ? _waterSurfaceRoot : transform;\n            AddWaterSurfacesFromTransforms(root.GetComponentsInChildren<Transform>(true));\n\n            Renderer[] sceneRenderers = FindObjectsByType<Renderer>(\n                FindObjectsInactive.Include,\n                FindObjectsSortMode.None\n            );\n\n            for (int i = 0; i < sceneRenderers.Length; i++)\n            {\n                Renderer sceneRenderer = sceneRenderers[i];\n                if (sceneRenderer == null)\n                {\n                    continue;\n                }\n\n                Transform surfaceTransform = FindWaterSurfaceRoot(sceneRenderer.transform);\n                if (surfaceTransform == null)\n                {\n                    continue;\n                }\n\n                GameObject surface = surfaceTransform.gameObject;\n                if (!_spawnedWaterSurfaces.Contains(surface))\n                {\n                    _spawnedWaterSurfaces.Add(surface);\n                }\n            }\n        }\n\n        private void AddWaterSurfacesFromTransforms(Transform[] transforms)\n        {\n            if (transforms == null)\n            {\n                return;\n            }\n\n            for (int i = 0; i < transforms.Length; i++)\n            {\n                Transform child = transforms[i];\n                if (child == null ||\n                    !child.name.StartsWith(\"WaterSurface_Pond_\", System.StringComparison.Ordinal))\n                {\n                    continue;\n                }\n\n                GameObject surface = child.gameObject;\n                if (!_spawnedWaterSurfaces.Contains(surface))\n                {\n                    _spawnedWaterSurfaces.Add(surface);\n                }\n            }\n        }\n\n        private static Transform FindWaterSurfaceRoot(Transform transform)\n        {\n            Transform current = transform;\n            while (current != null)\n            {\n                if (current.name.StartsWith(\"WaterSurface_Pond_\", System.StringComparison.Ordinal))\n                {\n                    return current;\n                }\n\n                current = current.parent;\n            }\n\n            return null;\n        }\n\n        private bool DoesSurfaceTouchFrozenTerrain(ElementFieldGrid grid, GameObject surface)\n        {\n            if (grid == null || surface == null)\n            {\n                return false;\n            }\n\n            if (!TryGetRendererBounds(surface, out Bounds bounds))\n            {\n                return grid.TryGetCellData(surface.transform.position, out ElementFieldCellData centerData) &&\n                       centerData.TerrainElement == TerrainElementType.Ice;\n            }\n\n            Bounds xzBounds = FlattenBoundsToFieldPlane(bounds);\n            Vector2Int cellCount = grid.CellCount;\n            for (int x = 0; x < cellCount.x; x++)\n            {\n                for (int y = 0; y < cellCount.y; y++)\n                {\n                    Vector2Int coord = new Vector2Int(x, y);\n                    if (!grid.TryGetCellData(coord, out ElementFieldCellData data) ||\n                        data.TerrainElement != TerrainElementType.Ice)\n                    {\n                        continue;\n                    }\n\n                    Vector3 cellPosition = grid.CellToWorld(coord);\n                    if (xzBounds.Contains(cellPosition))\n                    {\n                        return true;\n                    }\n                }\n            }\n\n            return false;\n        }\n\n        private static Bounds FlattenBoundsToFieldPlane(Bounds bounds)\n        {\n            Vector3 center = bounds.center;\n            Vector3 size = bounds.size;\n\n            center.y = 0f;\n            size.y = 10000f;\n\n            return new Bounds(center, size);\n        }\n\n        private static void ApplyWaterSurfaceMaterial(GameObject waterSurface, Material material)\n        {\n            if (waterSurface == null || material == null)\n            {\n                return;\n            }\n\n            Renderer[] renderers = waterSurface.GetComponentsInChildren<Renderer>(true);\n            for (int i = 0; i < renderers.Length; i++)\n            {\n                Renderer targetRenderer = renderers[i];\n                if (targetRenderer != null)\n                {\n                    targetRenderer.sharedMaterial = material;\n                }\n            }\n        }\n\n        private void PaintAlphamap(ElementFieldGrid grid, TerrainData terrainData)\n        {\n            int width = terrainData.alphamapWidth;\n            int height = terrainData.alphamapHeight;\n            int layerCount = terrainData.alphamapLayers;\n            float[,,] alphamaps = new float[height, width, layerCount];\n            int fallbackLayer = ResolveFallbackLayer();\n\n            for (int y = 0; y < height; y++)\n            {\n                for (int x = 0; x < width; x++)\n                {\n                    Vector3 worldPosition = AlphamapToWorldPosition(x, y, width, height, terrainData);\n                    TerrainElementType terrain = ResolveTerrainAtWorldPosition(grid, worldPosition);\n                    int layerIndex = ResolveLayerIndex(terrain, fallbackLayer);\n\n                    alphamaps[y, x, layerIndex] = 1f;\n                }\n            }\n\n            terrainData.SetAlphamaps(0, 0, alphamaps);\n        }\n\n        private Vector3 AlphamapToWorldPosition(\n            int x,\n            int y,\n            int width,\n            int height,\n            TerrainData terrainData)\n        {\n            float normalizedX = width > 1 ? x / (float)(width - 1) : 0f;\n            float normalizedZ = height > 1 ? y / (float)(height - 1) : 0f;\n            Vector3 terrainPosition = _terrain.transform.position;\n            Vector3 terrainSize = terrainData.size;\n\n            return new Vector3(\n                terrainPosition.x + normalizedX * terrainSize.x,\n                terrainPosition.y,\n                terrainPosition.z + normalizedZ * terrainSize.z\n            );\n        }\n\n        private TerrainElementType ResolveTerrainAtWorldPosition(\n            ElementFieldGrid grid,\n            Vector3 worldPosition)\n        {\n            if (grid.TryGetCellData(worldPosition, out ElementFieldCellData data))\n            {\n                return data.TerrainElement;\n            }\n\n            return _theme.BaseTerrain;\n        }\n\n        private int ResolveFallbackLayer()\n        {\n            if (_layerIndexByTerrain.TryGetValue(_theme.BaseTerrain, out int baseLayer))\n            {\n                return baseLayer;\n            }\n\n            return 0;\n        }\n\n        private int ResolveLayerIndex(TerrainElementType terrain, int fallbackLayer)\n        {\n            if (_layerIndexByTerrain.TryGetValue(terrain, out int layerIndex))\n            {\n                return layerIndex;\n            }\n\n            return fallbackLayer;\n        }\n\n        private static float Hash01(int a, int b, int c, int d)\n        {\n            unchecked\n            {\n                int hash = 17;\n                hash = hash * 31 + a;\n                hash = hash * 31 + b;\n                hash = hash * 31 + c;\n                hash = hash * 31 + d;\n                hash ^= hash << 13;\n                hash ^= hash >> 17;\n                hash ^= hash << 5;\n                return Mathf.Abs(hash % 10000) / 9999f;\n            }\n        }\n    }\n}\n", "GameplayCore/Field/ElementFieldCellData.cs": "using UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Field\n{\n    public struct ElementFieldCellData\n    {\n        public Vector2Int Coord;\n        public TerrainElementType TerrainElement;\n        public ElementType CurrentElement;\n        public int ElementLevel;\n        public float RemainingTime;\n        public ElementReactionType LastReactionType;\n\n        public bool IsActive => CurrentElement != ElementType.None && RemainingTime > 0f;\n\n        public ElementFieldCellData(Vector2Int coord, TerrainElementType terrainElement)\n        {\n            Coord = coord;\n            TerrainElement = terrainElement;\n            CurrentElement = ElementType.None;\n            ElementLevel = 1;\n            RemainingTime = 0f;\n            LastReactionType = ElementReactionType.None;\n        }\n\n        public void Clear()\n        {\n            CurrentElement = ElementType.None;\n            ElementLevel = 1;\n            RemainingTime = 0f;\n            LastReactionType = ElementReactionType.None;\n        }\n    }\n}\n", "GameplayCore/Field/ElementFieldEffectSystem.cs": "using System.Collections.Generic;\nusing Shield_Shot.GameplayCore.Monster.Status;\nusing Shield_Shot.GameplayCore.Render;\nusing UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Field\n{\n    public class ElementFieldEffectSystem : MonoBehaviour\n    {\n        private enum BoundsSampleMode\n        {\n            Auto,\n            Center,\n            FivePoints,\n            NinePoints\n        }\n\n        private const string BurnStatusID = \"Burn\";\n        private const string ShockStatusID = \"Shock\";\n        private const string SlowStatusID = \"Slow\";\n        private const string FrozenStatusID = \"Frozen\";\n        private const string ToxicSmokeStatusID = \"ToxicSmoke\";\n\n        [Header(\"References\")]\n        [SerializeField] private ElementFieldGrid _fieldGrid;\n\n        [Header(\"Target Registration\")]\n        [SerializeField] private bool _autoFindTargets;\n        [SerializeField, Min(0.05f)] private float _targetRefreshInterval = 1f;\n\n        [Header(\"Target Sampling\")]\n        [SerializeField] private BoundsSampleMode _boundsSampleMode = BoundsSampleMode.Auto;\n        [SerializeField, Min(0.1f)] private float _largeTargetCellSpan = 1.5f;\n        [SerializeField] private bool _includeTriggerColliders = true;\n        [SerializeField] private ElementType[] _elementPriority =\n        {\n            ElementType.Fire,\n            ElementType.Lightning,\n            ElementType.Poison,\n            ElementType.Ice\n        };\n\n        [Header(\"Apply\")]\n        [SerializeField, Min(0.05f)] private float _applyInterval = 0.35f;\n\n        [Header(\"Burn\")]\n        [SerializeField] private float _burnDuration = 1f;\n        [SerializeField] private float _burnTickInterval = 0.5f;\n        [SerializeField] private float _burnDamagePerTick = 2f;\n\n        [Header(\"Shock\")]\n        [SerializeField] private float _shockDuration = 0.8f;\n        [SerializeField] private float _shockTickInterval = 0.4f;\n        [SerializeField] private float _shockDamagePerTick = 2f;\n\n        [Header(\"Slow\")]\n        [SerializeField] private float _slowDuration = 1f;\n        [SerializeField, Range(0f, 1f)] private float _slowMultiplier = 0.5f;\n\n        [Header(\"Frozen\")]\n        [SerializeField] private float _frozenDuration = 1.5f;\n\n        [Header(\"Toxic Smoke\")]\n        [SerializeField] private float _toxicDuration = 1.5f;\n        [SerializeField] private float _toxicTickInterval = 0.5f;\n        [SerializeField] private float _toxicDamagePerTick = 2f;\n\n        [Header(\"VFX\")]\n        [SerializeField] private VFXType _tickVfxType = VFXType.Hit;\n        [SerializeField] private float _vfxAutoReleaseTime = 1.5f;\n\n        [Header(\"Debug\")]\n        [SerializeField] private int _debugTargetCount;\n\n        private readonly List<StatusEffectController> _targets = new();\n        private readonly Dictionary<int, float> _nextApplyTimeByTarget = new();\n        private readonly Dictionary<int, Collider[]> _collidersByTarget = new();\n        private readonly Vector3[] _samplePoints = new Vector3[9];\n\n        private float _nextTargetRefreshTime;\n\n        public int TargetCount => _targets.Count;\n\n        private void Reset()\n        {\n            _fieldGrid = FindFirstObjectByType<ElementFieldGrid>();\n        }\n\n        private void Update()\n        {\n            ElementFieldGrid grid = ResolveFieldGrid();\n\n            if (grid == null)\n            {\n                return;\n            }\n\n            if (_autoFindTargets && Time.time >= _nextTargetRefreshTime)\n            {\n                RefreshTargetsFromScene();\n                _nextTargetRefreshTime = Time.time + _targetRefreshInterval;\n            }\n            _debugTargetCount = _targets.Count;\n\n            ApplyFieldEffects(grid);\n        }\n\n        public void RegisterTarget(StatusEffectController target)\n        {\n            if (target == null)\n            {\n                return;\n            }\n\n            if (_targets.Contains(target))\n            {\n                return;\n            }\n\n            _targets.Add(target);\n            CacheTargetColliders(target);\n            _debugTargetCount = _targets.Count;\n        }\n\n        public void UnregisterTarget(StatusEffectController target)\n        {\n            if (target == null)\n            {\n                return;\n            }\n\n            _targets.Remove(target);\n            int targetId = target.GetInstanceID();\n            _nextApplyTimeByTarget.Remove(targetId);\n            _collidersByTarget.Remove(targetId);\n            _debugTargetCount = _targets.Count;\n        }\n\n        [ContextMenu(\"Refresh Targets From Scene\")]\n        public void RefreshTargetsFromScene()\n        {\n            _targets.Clear();\n            _nextApplyTimeByTarget.Clear();\n            _collidersByTarget.Clear();\n\n            StatusEffectController[] foundTargets =\n                FindObjectsByType<StatusEffectController>(FindObjectsSortMode.None);\n\n            for (int i = 0; i < foundTargets.Length; i++)\n            {\n                StatusEffectController target = foundTargets[i];\n\n                if (target != null && target.isActiveAndEnabled)\n                {\n                    RegisterTarget(target);\n                }\n            }\n\n            Debug.Log($\"[ElementFieldEffectSystem] Refreshed targets. Count: {_targets.Count}\");\n        }\n\n        private ElementFieldGrid ResolveFieldGrid()\n        {\n            if (_fieldGrid == null)\n            {\n                _fieldGrid = ElementFieldGrid.Instance != null\n                    ? ElementFieldGrid.Instance\n                    : FindFirstObjectByType<ElementFieldGrid>();\n            }\n\n            return _fieldGrid;\n        }\n\n        private void ApplyFieldEffects(ElementFieldGrid grid)\n        {\n            for (int i = _targets.Count - 1; i >= 0; i--)\n            {\n                StatusEffectController target = _targets[i];\n\n                if (target == null || !target.isActiveAndEnabled)\n                {\n                    RemoveTargetAt(i);\n                    continue;\n                }\n\n                int targetId = target.GetInstanceID();\n\n                if (_nextApplyTimeByTarget.TryGetValue(targetId, out float nextApplyTime) &&\n                    Time.time < nextApplyTime)\n                {\n                    continue;\n                }\n\n                if (!TryFindBestEffectCell(grid, target, out ElementFieldCellData cellData))\n                {\n                    continue;\n                }\n\n                if (!TryCreateStatusEffect(cellData, out StatusEffectData effect))\n                {\n                    continue;\n                }\n\n                target.ApplyOrRefresh(effect);\n                _nextApplyTimeByTarget[targetId] = Time.time + _applyInterval;\n            }\n        }\n\n        private bool TryFindBestEffectCell(\n            ElementFieldGrid grid,\n            StatusEffectController target,\n            out ElementFieldCellData bestCellData)\n        {\n            int sampleCount = BuildSamplePoints(grid, target);\n            if (TryFindBestActiveCell(grid, sampleCount, out bestCellData))\n            {\n                return true;\n            }\n\n            return TryFindFrozenTerrainCell(grid, sampleCount, out bestCellData);\n        }\n\n        private bool TryFindBestActiveCell(\n            ElementFieldGrid grid,\n            int sampleCount,\n            out ElementFieldCellData bestCellData)\n        {\n            int bestPriority = int.MaxValue;\n            bestCellData = default;\n\n            for (int i = 0; i < sampleCount; i++)\n            {\n                if (!grid.TryGetCellData(_samplePoints[i], out ElementFieldCellData cellData) ||\n                    !cellData.IsActive)\n                {\n                    continue;\n                }\n\n                int priority = GetElementPriority(cellData.CurrentElement);\n\n                if (priority >= bestPriority)\n                {\n                    continue;\n                }\n\n                bestPriority = priority;\n                bestCellData = cellData;\n\n                if (bestPriority == 0)\n                {\n                    return true;\n                }\n            }\n\n            return bestPriority < int.MaxValue;\n        }\n\n        private bool TryFindFrozenTerrainCell(\n            ElementFieldGrid grid,\n            int sampleCount,\n            out ElementFieldCellData bestCellData)\n        {\n            for (int i = 0; i < sampleCount; i++)\n            {\n                if (!grid.TryGetCellData(_samplePoints[i], out ElementFieldCellData cellData) ||\n                    cellData.TerrainElement != TerrainElementType.Ice)\n                {\n                    continue;\n                }\n\n                bestCellData = cellData;\n                bestCellData.CurrentElement = ElementType.Ice;\n                bestCellData.RemainingTime = _slowDuration;\n                bestCellData.LastReactionType = ElementReactionType.None;\n                return true;\n            }\n\n            bestCellData = default;\n            return false;\n        }\n\n        private int BuildSamplePoints(ElementFieldGrid grid, StatusEffectController target)\n        {\n            if (!TryGetTargetBounds(target, out Bounds bounds))\n            {\n                _samplePoints[0] = target.transform.position;\n                return 1;\n            }\n\n            BoundsSampleMode sampleMode = ResolveSampleMode(grid, bounds);\n            Vector3 center = bounds.center;\n            Vector3 min = bounds.min;\n            Vector3 max = bounds.max;\n\n            _samplePoints[0] = center;\n\n            if (sampleMode == BoundsSampleMode.Center)\n            {\n                return 1;\n            }\n\n            _samplePoints[1] = new Vector3(min.x, center.y, center.z);\n            _samplePoints[2] = new Vector3(max.x, center.y, center.z);\n            _samplePoints[3] = new Vector3(center.x, center.y, min.z);\n            _samplePoints[4] = new Vector3(center.x, center.y, max.z);\n\n            if (sampleMode == BoundsSampleMode.FivePoints)\n            {\n                return 5;\n            }\n\n            _samplePoints[5] = new Vector3(min.x, center.y, min.z);\n            _samplePoints[6] = new Vector3(min.x, center.y, max.z);\n            _samplePoints[7] = new Vector3(max.x, center.y, min.z);\n            _samplePoints[8] = new Vector3(max.x, center.y, max.z);\n\n            return 9;\n        }\n\n        private BoundsSampleMode ResolveSampleMode(ElementFieldGrid grid, Bounds bounds)\n        {\n            if (_boundsSampleMode != BoundsSampleMode.Auto)\n            {\n                return _boundsSampleMode;\n            }\n\n            Vector2 cellSize = grid.CellWorldSize;\n            float targetWidthInCells = bounds.size.x / Mathf.Max(0.001f, cellSize.x);\n            float targetDepthInCells = bounds.size.z / Mathf.Max(0.001f, cellSize.y);\n            float maxCellSpan = Mathf.Max(targetWidthInCells, targetDepthInCells);\n\n            return maxCellSpan >= _largeTargetCellSpan\n                ? BoundsSampleMode.NinePoints\n                : BoundsSampleMode.FivePoints;\n        }\n\n        private bool TryGetTargetBounds(StatusEffectController target, out Bounds bounds)\n        {\n            int targetId = target.GetInstanceID();\n\n            if (!_collidersByTarget.TryGetValue(targetId, out Collider[] colliders) ||\n                colliders == null ||\n                colliders.Length == 0)\n            {\n                colliders = CacheTargetColliders(target);\n            }\n\n            bool hasBounds = false;\n            bounds = default;\n\n            for (int i = 0; i < colliders.Length; i++)\n            {\n                Collider targetCollider = colliders[i];\n\n                if (targetCollider == null ||\n                    !targetCollider.enabled ||\n                    (!_includeTriggerColliders && targetCollider.isTrigger))\n                {\n                    continue;\n                }\n\n                if (!hasBounds)\n                {\n                    bounds = targetCollider.bounds;\n                    hasBounds = true;\n                    continue;\n                }\n\n                bounds.Encapsulate(targetCollider.bounds);\n            }\n\n            return hasBounds;\n        }\n\n        private Collider[] CacheTargetColliders(StatusEffectController target)\n        {\n            Collider[] colliders = target.GetComponentsInChildren<Collider>();\n            _collidersByTarget[target.GetInstanceID()] = colliders;\n            return colliders;\n        }\n\n        private int GetElementPriority(ElementType element)\n        {\n            if (_elementPriority == null)\n            {\n                return int.MaxValue;\n            }\n\n            for (int i = 0; i < _elementPriority.Length; i++)\n            {\n                if (_elementPriority[i] == element)\n                {\n                    return i;\n                }\n            }\n\n            return int.MaxValue - 1;\n        }\n\n        private void RemoveTargetAt(int index)\n        {\n            StatusEffectController target = _targets[index];\n\n            if (target != null)\n            {\n                int targetId = target.GetInstanceID();\n                _nextApplyTimeByTarget.Remove(targetId);\n                _collidersByTarget.Remove(targetId);\n            }\n\n            _targets.RemoveAt(index);\n            _debugTargetCount = _targets.Count;\n        }\n\n        private bool TryCreateStatusEffect(ElementFieldCellData cellData, out StatusEffectData effect)\n        {\n            switch (cellData.CurrentElement)\n            {\n                case ElementType.Fire:\n                    effect = new StatusEffectData(\n                        statusID: BurnStatusID,\n                        type: StatusEffectType.Burn,\n                        duration: _burnDuration,\n                        tickInterval: _burnTickInterval,\n                        damagePerTick: _burnDamagePerTick,\n                        source: this,\n                        showDamagePopup: true,\n                        tickVfxType: _tickVfxType,\n                        vfxAutoReleaseTime: _vfxAutoReleaseTime\n                    );\n                    return true;\n\n                case ElementType.Lightning:\n                    effect = new StatusEffectData(\n                        statusID: ShockStatusID,\n                        type: StatusEffectType.Shock,\n                        duration: _shockDuration,\n                        tickInterval: _shockTickInterval,\n                        damagePerTick: _shockDamagePerTick,\n                        source: this,\n                        showDamagePopup: true,\n                        tickVfxType: _tickVfxType,\n                        vfxAutoReleaseTime: _vfxAutoReleaseTime\n                    );\n                    return true;\n\n                case ElementType.Ice:\n                    if (cellData.LastReactionType == ElementReactionType.Freeze)\n                    {\n                        effect = new StatusEffectData(\n                            statusID: FrozenStatusID,\n                            type: StatusEffectType.Frozen,\n                            duration: _frozenDuration,\n                            source: this,\n                            showDamagePopup: false,\n                            tickVfxType: VFXType.None\n                        );\n                        return true;\n                    }\n\n                    effect = new StatusEffectData(\n                        statusID: SlowStatusID,\n                        type: StatusEffectType.Slow,\n                        duration: _slowDuration,\n                        slowMultiplier: _slowMultiplier,\n                        source: this,\n                        showDamagePopup: false,\n                        tickVfxType: VFXType.None\n                    );\n                    return true;\n\n                case ElementType.Poison:\n                    effect = new StatusEffectData(\n                        statusID: ToxicSmokeStatusID,\n                        type: StatusEffectType.Poison,\n                        duration: _toxicDuration,\n                        tickInterval: _toxicTickInterval,\n                        damagePerTick: _toxicDamagePerTick,\n                        source: this,\n                        showDamagePopup: true,\n                        tickVfxType: _tickVfxType,\n                        vfxAutoReleaseTime: _vfxAutoReleaseTime\n                    );\n                    return true;\n            }\n\n            effect = default;\n            return false;\n        }\n    }\n}\n", "GameplayCore/Field/ElementFieldGrid.cs": "using System;\nusing System.Collections;\nusing System.Collections.Generic;\nusing UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Field\n{\n    public class ElementFieldGrid : MonoBehaviour\n    {\n        public static ElementFieldGrid Instance { get; private set; }\n\n        public event Action<Vector2Int, ElementFieldCellData, ElementReactionResult> CellChanged;\n        public event Action<Vector2Int, ElementFieldCellData> CellCleared;\n        public event Action<Vector2Int, ElementFieldCellData> TerrainChanged;\n\n        [Header(\"Design Space\")]\n        [SerializeField] private Vector2Int _designResolution = new Vector2Int(1080, 1920);\n        [SerializeField] private Vector2Int _cellCount = new Vector2Int(27, 48);\n        [SerializeField, Min(1f)] private float _pixelsPerWorldUnit = 100f;\n        [SerializeField] private Transform _fieldSpace;\n\n        [Header(\"Cell\")]\n        [SerializeField] private ElementFieldCell _cellPrefab;\n        [SerializeField] private bool _generateCellObjects = false;\n        [SerializeField] private bool _syncDebugCellObjects = true;\n\n        [Header(\"Generated Cells\")]\n        [SerializeField] private Transform _cellRoot;\n\n        [Header(\"Terrain Provider\")]\n        [SerializeField] private ElementFieldTerrainProvider _terrainProvider;\n\n        [Header(\"Terrain Rules\")]\n        [SerializeField] private bool _useTerrainRules = true;\n        [SerializeField, Range(0f, 0.5f)] private float _sandEdgeBand = 0.08f;\n        [SerializeField] private Rect _waterRect = new Rect(0.4f, 0.45f, 0.2f, 0.1f);\n        [SerializeField] private Rect _grassRect = new Rect(0.15f, 0.15f, 0.2f, 0.2f);\n\n        [Header(\"Reaction Debug\")]\n        [SerializeField] private bool _logReactionPaint = true;\n\n        [Header(\"Ongoing Reactions\")]\n        [SerializeField] private bool _refreshHotWindFireWhileActive = true;\n        [SerializeField, Min(0.05f)] private float _hotWindFireRefreshInterval = 0.35f;\n        [SerializeField, Min(0.05f)] private float _hotWindFireBaseDuration = 0.9f;\n\n        private readonly Dictionary<Vector2Int, ElementFieldCell> _cells = new();\n        private readonly Dictionary<Vector2Int, float> _nextHotWindFireRefreshTimeByCell = new();\n        private readonly HashSet<Vector2Int> _activeCells = new();\n        private readonly List<Vector2Int> _activeCellBuffer = new();\n        private readonly List<Vector2Int> _spreadCellBuffer = new();\n        private readonly Queue<Vector2Int> _terrainFloodQueue = new();\n        private readonly HashSet<Vector2Int> _terrainFloodVisited = new();\n        private ElementFieldCellData[,] _cellData;\n\n        public Vector2 FieldWorldSize => new Vector2(\n            _designResolution.x / _pixelsPerWorldUnit,\n            _designResolution.y / _pixelsPerWorldUnit\n        );\n\n        public Vector2Int CellCount => _cellCount;\n        public Transform FieldSpace => _fieldSpace != null ? _fieldSpace : transform;\n        public Vector3 FieldCenter => FieldSpace.TransformPoint(Vector3.zero);\n\n        public Vector2 CellWorldSize => new Vector2(\n            FieldWorldSize.x / Mathf.Max(1, _cellCount.x),\n            FieldWorldSize.y / Mathf.Max(1, _cellCount.y)\n        );\n\n        public float CellSize => Mathf.Min(CellWorldSize.x, CellWorldSize.y);\n\n        private void Awake()\n        {\n            if (Instance != null && Instance != this)\n            {\n                Destroy(gameObject);\n                return;\n            }\n\n            Instance = this;\n\n            if (_fieldSpace == null)\n            {\n                _fieldSpace = transform;\n            }\n\n            if (_cellRoot == null)\n            {\n                _cellRoot = transform;\n            }\n\n            if (_terrainProvider == null)\n            {\n                _terrainProvider = FindFirstObjectByType<ElementFieldTerrainProvider>();\n            }\n\n            BuildGrid();\n        }\n\n        private void Update()\n        {\n            TickActiveCells(Time.deltaTime);\n        }\n        private void Reset()\n        {\n            _terrainProvider = FindFirstObjectByType<ElementFieldTerrainProvider>();\n        }\n        private void BuildGrid()\n        {\n            _cells.Clear();\n            _activeCells.Clear();\n            _activeCellBuffer.Clear();\n            _terrainFloodQueue.Clear();\n            _terrainFloodVisited.Clear();\n            _nextHotWindFireRefreshTimeByCell.Clear();\n            RefreshTerrainProviderAreas();\n            _cellData = new ElementFieldCellData[\n                Mathf.Max(1, _cellCount.x),\n                Mathf.Max(1, _cellCount.y)\n            ];\n\n            for (int x = 0; x < _cellData.GetLength(0); x++)\n            {\n                for (int y = 0; y < _cellData.GetLength(1); y++)\n                {\n                    Vector2Int coord = new Vector2Int(x, y);\n                    _cellData[x, y] = new ElementFieldCellData(coord, ResolveTerrain(coord));\n                }\n            }\n\n            if (!_generateCellObjects)\n            {\n                return;\n            }\n\n            if (_cellPrefab == null)\n            {\n                Debug.LogWarning(\"[ElementFieldGrid] Cell prefab is missing.\");\n                return;\n            }\n\n            for (int x = 0; x < _cellCount.x; x++)\n            {\n                for (int y = 0; y < _cellCount.y; y++)\n                {\n                    Vector2Int coord = new Vector2Int(x, y);\n                    CreateDebugCellObject(coord);\n                }\n            }\n        }\n\n        public void Paint(Vector3 worldPosition, ElementType element, float duration)\n        {\n            Paint(worldPosition, new ElementPaintContext(element), duration);\n        }\n\n        public void Paint(Vector3 worldPosition, ElementPaintContext paintContext, float duration)\n        {\n            Vector2Int coord = WorldToCell(worldPosition);\n\n            if (_logReactionPaint)\n            {\n                string terrainText = TryGetCellData(coord, out ElementFieldCellData data)\n                    ? data.TerrainElement.ToString()\n                    : \"Invalid\";\n\n                Debug.Log(\n                    $\"[ElementFieldGrid] Paint request. World: {worldPosition}, Cell: {coord}, \" +\n                    $\"Terrain: {terrainText}, Element: {paintContext.Element}, \" +\n                    $\"Level: {paintContext.ElementLevel}, Duration: {duration:0.00}\"\n                );\n            }\n\n            PaintCell(coord, paintContext, duration);\n        }\n\n        public void PaintCircle(Vector3 worldPosition, ElementType element, float duration, float radius)\n        {\n            PaintCircle(worldPosition, new ElementPaintContext(element), duration, radius);\n        }\n        public void SetTerrainCell(Vector2Int coord, TerrainElementType terrain)\n        {\n            if (!IsValidCell(coord) || _cellData == null)\n            {\n                return;\n            }\n\n            ElementFieldCellData data = _cellData[coord.x, coord.y];\n            data.TerrainElement = terrain;\n            _cellData[coord.x, coord.y] = data;\n\n            if (_syncDebugCellObjects && _cells.TryGetValue(coord, out ElementFieldCell cell))\n            {\n                cell.SetTerrainElement(terrain);\n            }\n\n            TerrainChanged?.Invoke(coord, data);\n        }\n        public void FillTerrain(TerrainElementType terrain)\n        {\n            if (_cellData == null)\n            {\n                return;\n            }\n\n            for (int x = 0; x < _cellData.GetLength(0); x++)\n            {\n                for (int y = 0; y < _cellData.GetLength(1); y++)\n                {\n                    SetTerrainCell(new Vector2Int(x, y), terrain);\n                }\n            }\n        }\n\n        public void PaintCircle(Vector3 worldPosition, ElementPaintContext paintContext, float duration, float radius)\n        {\n            float cellSize = Mathf.Min(CellWorldSize.x, CellWorldSize.y);\n            int cellRadius = Mathf.CeilToInt(radius / cellSize);\n            Vector2Int center = WorldToCell(worldPosition);\n            int candidateCells = 0;\n            int validCells = 0;\n            int grassCells = 0;\n\n            for (int x = -cellRadius; x <= cellRadius; x++)\n            {\n                for (int y = -cellRadius; y <= cellRadius; y++)\n                {\n                    Vector2Int coord = center + new Vector2Int(x, y);\n                    Vector3 cellPosition = CellToWorld(coord);\n\n                    Vector3 localCellPosition = FieldSpace.InverseTransformPoint(cellPosition);\n                    Vector3 localPaintPosition = FieldSpace.InverseTransformPoint(worldPosition);\n                    Vector2 flatDelta = new Vector2(\n                        localCellPosition.x - localPaintPosition.x,\n                        localCellPosition.z - localPaintPosition.z\n                    );\n\n                    if (flatDelta.sqrMagnitude > radius * radius)\n                    {\n                        continue;\n                    }\n\n                    candidateCells++;\n\n                    if (TryGetCellData(coord, out ElementFieldCellData data))\n                    {\n                        validCells++;\n\n                        if (data.TerrainElement == TerrainElementType.Grass)\n                        {\n                            grassCells++;\n                        }\n                    }\n\n                    PaintCell(coord, paintContext, duration);\n                }\n            }\n\n            if (_logReactionPaint)\n            {\n                Debug.Log(\n                    $\"[ElementFieldGrid] PaintCircle request. World: {worldPosition}, CenterCell: {center}, \" +\n                    $\"Radius: {radius:0.00}, CellRadius: {cellRadius}, CandidateCells: {candidateCells}, \" +\n                    $\"ValidCells: {validCells}, GrassCells: {grassCells}, Element: {paintContext.Element}, \" +\n                    $\"Level: {paintContext.ElementLevel}, Duration: {duration:0.00}\"\n                );\n            }\n        }\n\n        public bool TryGetCellData(Vector2Int coord, out ElementFieldCellData data)\n        {\n            if (!IsValidCell(coord) || _cellData == null)\n            {\n                data = default;\n                return false;\n            }\n\n            data = _cellData[coord.x, coord.y];\n            return true;\n        }\n\n        public bool TryGetCellData(Vector3 worldPosition, out ElementFieldCellData data)\n        {\n            return TryGetCellData(WorldToCell(worldPosition), out data);\n        }\n\n        public bool TryGetCell(Vector3 worldPosition, out ElementFieldCell cell)\n        {\n            Vector2Int coord = WorldToCell(worldPosition);\n            return _cells.TryGetValue(coord, out cell);\n        }\n        public void Clear(Vector3 worldPosition)\n        {\n            ClearCell(WorldToCell(worldPosition));\n        }\n\n        public void ClearCellAt(Vector2Int coord)\n        {\n            ClearCell(coord);\n        }\n\n        public void ClearCircle(Vector3 worldPosition, float radius)\n        {\n            float cellSize = Mathf.Min(CellWorldSize.x, CellWorldSize.y);\n            int cellRadius = Mathf.CeilToInt(radius / cellSize);\n            Vector2Int center = WorldToCell(worldPosition);\n\n            for (int x = -cellRadius; x <= cellRadius; x++)\n            {\n                for (int y = -cellRadius; y <= cellRadius; y++)\n                {\n                    Vector2Int coord = center + new Vector2Int(x, y);\n                    Vector3 cellPosition = CellToWorld(coord);\n\n                    Vector3 localCellPosition = FieldSpace.InverseTransformPoint(cellPosition);\n                    Vector3 localClearPosition = FieldSpace.InverseTransformPoint(worldPosition);\n                    Vector2 flatDelta = new Vector2(\n                        localCellPosition.x - localClearPosition.x,\n                        localCellPosition.z - localClearPosition.z\n                    );\n\n                    if (flatDelta.sqrMagnitude > radius * radius)\n                    {\n                        continue;\n                    }\n\n                    ClearCell(coord);\n                }\n            }\n        }\n\n        public void ClearAll()\n        {\n            if (_cellData == null)\n            {\n                return;\n            }\n\n            _activeCellBuffer.Clear();\n            _activeCellBuffer.AddRange(_activeCells);\n\n            for (int i = 0; i < _activeCellBuffer.Count; i++)\n            {\n                ClearCell(_activeCellBuffer[i]);\n            }\n\n            _activeCells.Clear();\n            _activeCellBuffer.Clear();\n        }\n\n        public bool IsValidCell(Vector2Int coord)\n        {\n            return coord.x >= 0 &&\n                   coord.x < _cellCount.x &&\n                   coord.y >= 0 &&\n                   coord.y < _cellCount.y;\n        }\n\n        public Vector2Int ClampCell(Vector2Int coord)\n        {\n            return new Vector2Int(\n                Mathf.Clamp(coord.x, 0, Mathf.Max(0, _cellCount.x - 1)),\n                Mathf.Clamp(coord.y, 0, Mathf.Max(0, _cellCount.y - 1))\n            );\n        }\n\n        public bool TryCellToWorld(Vector2Int coord, out Vector3 worldPosition)\n        {\n            if (!IsValidCell(coord))\n            {\n                worldPosition = default;\n                return false;\n            }\n\n            worldPosition = CellToWorld(coord);\n            return true;\n        }\n\n        public Vector2Int WorldToCell(Vector3 worldPosition)\n        {\n            Vector3 local = FieldSpace.InverseTransformPoint(worldPosition);\n            Vector2 fieldSize = FieldWorldSize;\n\n            float normalizedX = (local.x / fieldSize.x) + 0.5f;\n            float normalizedY = (local.z / fieldSize.y) + 0.5f;\n\n            int x = Mathf.FloorToInt(normalizedX * _cellCount.x);\n            int y = Mathf.FloorToInt(normalizedY * _cellCount.y);\n\n            return new Vector2Int(x, y);\n        }\n\n        public Vector3 CellToWorld(Vector2Int coord)\n        {\n            Vector2 fieldSize = FieldWorldSize;\n            Vector2 cellSize = CellWorldSize;\n\n            Vector3 localPosition = new Vector3(\n                -fieldSize.x * 0.5f + (coord.x + 0.5f) * cellSize.x,\n                0f,\n                -fieldSize.y * 0.5f + (coord.y + 0.5f) * cellSize.y\n            );\n\n            return FieldSpace.TransformPoint(localPosition);\n        }\n\n        public Vector2 CellToDesignPosition(Vector2Int coord)\n        {\n            return new Vector2(\n                (coord.x + 0.5f) * (_designResolution.x / Mathf.Max(1f, _cellCount.x)),\n                (coord.y + 0.5f) * (_designResolution.y / Mathf.Max(1f, _cellCount.y))\n            );\n        }\n\n        public TerrainElementType ResolveTerrain(Vector2Int coord)\n        {\n            if (_terrainProvider != null && TryCellToWorld(coord, out Vector3 worldPosition))\n            {\n                return _terrainProvider.GetTerrain(worldPosition);\n            }\n\n            if (!_useTerrainRules)\n            {\n                return TerrainElementType.None;\n            }\n\n            Vector2 normalized = new Vector2(\n                (coord.x + 0.5f) / Mathf.Max(1f, _cellCount.x),\n                (coord.y + 0.5f) / Mathf.Max(1f, _cellCount.y)\n            );\n\n            if (IsInsideRect(normalized, _waterRect))\n            {\n                return TerrainElementType.Water;\n            }\n\n            if (IsInsideRect(normalized, _grassRect))\n            {\n                return TerrainElementType.Grass;\n            }\n\n            if (normalized.x < _sandEdgeBand ||\n                normalized.x > 1f - _sandEdgeBand ||\n                normalized.y < _sandEdgeBand ||\n                normalized.y > 1f - _sandEdgeBand)\n            {\n                return TerrainElementType.Sand;\n            }\n\n            return TerrainElementType.None;\n        }\n\n        private static bool IsInsideRect(Vector2 point, Rect rect)\n        {\n            return point.x >= rect.xMin &&\n                   point.x <= rect.xMax &&\n                   point.y >= rect.yMin &&\n                   point.y <= rect.yMax;\n        }\n\n        private void PaintCell(Vector2Int coord, ElementType incomingElement, float duration)\n        {\n            PaintCell(coord, new ElementPaintContext(incomingElement), duration, true);\n        }\n\n        private void PaintCell(Vector2Int coord, ElementPaintContext paintContext, float duration)\n        {\n            PaintCell(coord, paintContext, duration, true);\n        }\n\n        private void PaintCell(Vector2Int coord, ElementPaintContext paintContext, float duration, bool allowSpread)\n        {\n            if (!IsValidCell(coord) || _cellData == null || paintContext.Element == ElementType.None)\n            {\n                return;\n            }\n\n            ElementFieldCellData data = _cellData[coord.x, coord.y];\n            ElementReactionResult reaction = ElementReactionResolver.Resolve(\n                data.TerrainElement,\n                data.CurrentElement,\n                paintContext\n            );\n\n            ElementType resultElement = reaction.HasReaction\n                ? reaction.ResultElement\n                : paintContext.Element;\n\n            if (resultElement == ElementType.None)\n            {\n                ClearCell(coord);\n                return;\n            }\n\n            if (reaction.ReactionType == ElementReactionType.Freeze &&\n                data.TerrainElement == TerrainElementType.Water)\n            {\n                FreezeConnectedWaterTerrain(coord, paintContext, duration, reaction);\n                return;\n            }\n\n            ElementType previousElement = data.CurrentElement;\n            data.CurrentElement = resultElement;\n            data.ElementLevel = previousElement == resultElement\n                ? Mathf.Max(data.ElementLevel, paintContext.ElementLevel)\n                : paintContext.ElementLevel;\n            data.RemainingTime = Mathf.Max(data.RemainingTime, duration * Mathf.Max(0f, reaction.DurationMultiplier));\n            data.LastReactionType = reaction.ReactionType;\n            _cellData[coord.x, coord.y] = data;\n            _activeCells.Add(coord);\n\n            if (_syncDebugCellObjects && _cells.TryGetValue(coord, out ElementFieldCell cell))\n            {\n                cell.ApplyElement(paintContext.Element, duration);\n            }\n\n            CellChanged?.Invoke(coord, data, reaction);\n\n            if (_logReactionPaint && reaction.ReactionType != ElementReactionType.Ignite)\n            {\n                Debug.Log(\n                    $\"[ElementFieldGrid] Paint reaction {reaction.ReactionType} at {coord}. \" +\n                    $\"Terrain: {data.TerrainElement}, Incoming: {paintContext.Element}, \" +\n                    $\"Level: {paintContext.ElementLevel}, Result: {resultElement}, Duration: {data.RemainingTime:0.00}, \" +\n                    $\"SpreadCellRadius: {reaction.SpreadCellRadius}, \" +\n                    $\"SpreadDelay: {reaction.SpreadDelay:0.00}\"\n                );\n            }\n\n            if (allowSpread && reaction.SpreadCellRadius > 0)\n            {\n                ElementType spreadElement = reaction.SpreadElement != ElementType.None\n                    ? reaction.SpreadElement\n                    : resultElement;\n                PaintReactionSpread(coord, paintContext, spreadElement, duration, reaction);\n            }\n        }\n\n        private void RefreshTerrainProviderAreas()\n        {\n            if (_terrainProvider == null)\n            {\n                return;\n            }\n\n            _terrainProvider.RefreshAreas();\n        }\n\n        private void PaintReactionSpread(\n            Vector2Int origin,\n            ElementPaintContext sourceContext,\n            ElementType element,\n            float sourceDuration,\n            ElementReactionResult reaction)\n        {\n            int cellRadius = Mathf.Max(0, reaction.SpreadCellRadius);\n            float spreadDuration = sourceDuration * Mathf.Max(0f, reaction.SpreadDurationMultiplier);\n            int spreadCount = 0;\n            _spreadCellBuffer.Clear();\n\n            for (int x = -cellRadius; x <= cellRadius; x++)\n            {\n                for (int y = -cellRadius; y <= cellRadius; y++)\n                {\n                    Vector2Int coord = origin + new Vector2Int(x, y);\n\n                    if (coord == origin ||\n                        !IsValidCell(coord) ||\n                        !CanSpreadToCell(reaction, coord))\n                    {\n                        continue;\n                    }\n\n                    _spreadCellBuffer.Add(coord);\n                    spreadCount++;\n                }\n            }\n\n            _spreadCellBuffer.Sort((left, right) =>\n            {\n                int leftDistance = Mathf.Abs(left.x - origin.x) + Mathf.Abs(left.y - origin.y);\n                int rightDistance = Mathf.Abs(right.x - origin.x) + Mathf.Abs(right.y - origin.y);\n                return leftDistance.CompareTo(rightDistance);\n            });\n\n            if (_spreadCellBuffer.Count > 0)\n            {\n                StartCoroutine(PaintReactionSpreadRoutine(\n                    _spreadCellBuffer.ToArray(),\n                    new ElementPaintContext(\n                        element,\n                        sourceContext.ElementLevel,\n                        sourceContext.PowerMultiplier,\n                        sourceContext.Source\n                    ),\n                    spreadDuration,\n                    reaction.SpreadDelay,\n                    reaction\n                ));\n            }\n\n            if (_logReactionPaint)\n            {\n                Debug.Log(\n                    $\"[ElementFieldGrid] Spread {reaction.ReactionType} from {origin}. \" +\n                    $\"CellRadius: {cellRadius}, PaintedCells: {spreadCount}\"\n                );\n            }\n        }\n\n        private IEnumerator PaintReactionSpreadRoutine(\n            Vector2Int[] spreadCells,\n            ElementPaintContext paintContext,\n            float spreadDuration,\n            float spreadDelay,\n            ElementReactionResult reaction)\n        {\n            for (int i = 0; i < spreadCells.Length; i++)\n            {\n                if (spreadDelay > 0f)\n                {\n                    yield return new WaitForSeconds(spreadDelay);\n                }\n\n                if (!CanSpreadToCell(reaction, spreadCells[i]))\n                {\n                    continue;\n                }\n\n                PaintCell(spreadCells[i], paintContext, spreadDuration, false);\n            }\n        }\n\n        private bool CanSpreadToCell(ElementReactionResult reaction, Vector2Int coord)\n        {\n            if (!TryGetCellData(coord, out ElementFieldCellData data))\n            {\n                return false;\n            }\n\n            if (reaction.ReactionType == ElementReactionType.SpreadFire)\n            {\n                return data.TerrainElement == TerrainElementType.Grass;\n            }\n\n            if (reaction.ReactionType == ElementReactionType.HotWind)\n            {\n                return data.CurrentElement != ElementType.Wind;\n            }\n\n            return true;\n        }\n\n        private void ClearCell(Vector2Int coord)\n        {\n            if (!IsValidCell(coord) || _cellData == null)\n            {\n                return;\n            }\n\n            ElementFieldCellData data = _cellData[coord.x, coord.y];\n            data.Clear();\n            _cellData[coord.x, coord.y] = data;\n            _activeCells.Remove(coord);\n            _nextHotWindFireRefreshTimeByCell.Remove(coord);\n\n            if (_syncDebugCellObjects && _cells.TryGetValue(coord, out ElementFieldCell cell))\n            {\n                cell.ClearElement();\n            }\n\n            CellCleared?.Invoke(coord, data);\n        }\n\n        private void TickActiveCells(float deltaTime)\n        {\n            if (_activeCells.Count == 0 || _cellData == null)\n            {\n                return;\n            }\n\n            _activeCellBuffer.Clear();\n            _activeCellBuffer.AddRange(_activeCells);\n\n            for (int i = 0; i < _activeCellBuffer.Count; i++)\n            {\n                Vector2Int coord = _activeCellBuffer[i];\n\n                if (!IsValidCell(coord))\n                {\n                    _activeCells.Remove(coord);\n                    continue;\n                }\n\n                ElementFieldCellData data = _cellData[coord.x, coord.y];\n\n                if (!data.IsActive)\n                {\n                    ClearCell(coord);\n                    continue;\n                }\n\n                data.RemainingTime -= deltaTime;\n\n                if (data.RemainingTime <= 0f)\n                {\n                    ClearCell(coord);\n                    continue;\n                }\n\n                _cellData[coord.x, coord.y] = data;\n                TickOngoingHotWindFire(coord, data);\n            }\n        }\n\n        private void TickOngoingHotWindFire(Vector2Int origin, ElementFieldCellData data)\n        {\n            if (!_refreshHotWindFireWhileActive ||\n                data.CurrentElement != ElementType.Wind ||\n                data.LastReactionType != ElementReactionType.HotWind)\n            {\n                return;\n            }\n\n            if (_nextHotWindFireRefreshTimeByCell.TryGetValue(origin, out float nextRefreshTime) &&\n                Time.time < nextRefreshTime)\n            {\n                return;\n            }\n\n            ElementPaintContext windContext = new ElementPaintContext(\n                ElementType.Wind,\n                data.ElementLevel\n            );\n            ElementReactionResult hotWindReaction = ElementReactionResolver.Resolve(\n                data.TerrainElement,\n                data.CurrentElement,\n                windContext\n            );\n\n            if (hotWindReaction.ReactionType != ElementReactionType.HotWind ||\n                hotWindReaction.SpreadCellRadius <= 0)\n            {\n                return;\n            }\n\n            _nextHotWindFireRefreshTimeByCell[origin] = Time.time + _hotWindFireRefreshInterval;\n\n            float fireDuration = _hotWindFireBaseDuration *\n                Mathf.Max(0f, hotWindReaction.SpreadDurationMultiplier);\n            ElementPaintContext fireContext = new ElementPaintContext(\n                ElementType.Fire,\n                data.ElementLevel\n            );\n\n            int cellRadius = Mathf.Max(0, hotWindReaction.SpreadCellRadius);\n            for (int x = -cellRadius; x <= cellRadius; x++)\n            {\n                for (int y = -cellRadius; y <= cellRadius; y++)\n                {\n                    Vector2Int coord = origin + new Vector2Int(x, y);\n\n                    if (coord == origin || !CanSpreadToCell(hotWindReaction, coord))\n                    {\n                        continue;\n                    }\n\n                    PaintCell(coord, fireContext, fireDuration, false);\n                }\n            }\n        }\n\n        private void FreezeConnectedWaterTerrain(\n            Vector2Int origin,\n            ElementPaintContext paintContext,\n            float duration,\n            ElementReactionResult reaction)\n        {\n            _terrainFloodQueue.Clear();\n            _terrainFloodVisited.Clear();\n\n            _terrainFloodQueue.Enqueue(origin);\n            _terrainFloodVisited.Add(origin);\n\n            float freezeDuration = duration * Mathf.Max(0f, reaction.DurationMultiplier);\n\n            while (_terrainFloodQueue.Count > 0)\n            {\n                Vector2Int coord = _terrainFloodQueue.Dequeue();\n\n                if (!TryGetCellData(coord, out ElementFieldCellData data) ||\n                    data.TerrainElement != TerrainElementType.Water)\n                {\n                    continue;\n                }\n\n                ElementType previousElement = data.CurrentElement;\n                data.TerrainElement = TerrainElementType.Ice;\n                data.CurrentElement = ElementType.Ice;\n                data.ElementLevel = previousElement == ElementType.Ice\n                    ? Mathf.Max(data.ElementLevel, paintContext.ElementLevel)\n                    : paintContext.ElementLevel;\n                data.RemainingTime = Mathf.Max(data.RemainingTime, freezeDuration);\n                data.LastReactionType = ElementReactionType.Freeze;\n\n                _cellData[coord.x, coord.y] = data;\n                _activeCells.Add(coord);\n\n                if (_syncDebugCellObjects && _cells.TryGetValue(coord, out ElementFieldCell cell))\n                {\n                    cell.SetTerrainElement(TerrainElementType.Ice);\n                    cell.ApplyElement(ElementType.Ice, freezeDuration);\n                }\n\n                TerrainChanged?.Invoke(coord, data);\n                CellChanged?.Invoke(coord, data, reaction);\n\n                EnqueueWaterNeighbor(coord + Vector2Int.right);\n                EnqueueWaterNeighbor(coord + Vector2Int.left);\n                EnqueueWaterNeighbor(coord + Vector2Int.up);\n                EnqueueWaterNeighbor(coord + Vector2Int.down);\n            }\n        }\n\n        private void EnqueueWaterNeighbor(Vector2Int coord)\n        {\n            if (_terrainFloodVisited.Contains(coord) ||\n                !TryGetCellData(coord, out ElementFieldCellData data) ||\n                data.TerrainElement != TerrainElementType.Water)\n            {\n                return;\n            }\n\n            _terrainFloodVisited.Add(coord);\n            _terrainFloodQueue.Enqueue(coord);\n        }\n\n        private void CreateDebugCellObject(Vector2Int coord)\n        {\n            Vector3 worldPosition = CellToWorld(coord);\n\n            ElementFieldCell cell = Instantiate(\n                _cellPrefab,\n                worldPosition,\n                _fieldSpace.rotation,\n                _cellRoot\n            );\n\n            cell.name = $\"ElementCell_{coord.x}_{coord.y}\";\n            cell.Initialize(coord, ResolveTerrain(coord), CellWorldSize);\n            _cells.Add(coord, cell);\n        }\n\n        [ContextMenu(\"Refresh Terrain Data\")]\n        public void RefreshTerrainData()\n        {\n            if (_terrainProvider != null)\n            {\n                _terrainProvider.RefreshAreas();\n            }\n\n            if (_cellData == null)\n            {\n                return;\n            }\n\n            for (int x = 0; x < _cellData.GetLength(0); x++)\n            {\n                for (int y = 0; y < _cellData.GetLength(1); y++)\n                {\n                    Vector2Int coord = new Vector2Int(x, y);\n                    ElementFieldCellData data = _cellData[x, y];\n\n                    data.TerrainElement = ResolveTerrain(coord);\n                    _cellData[x, y] = data;\n                }\n            }\n        }\n\n        private void OnDrawGizmosSelected()\n        {\n            Transform space = _fieldSpace != null ? _fieldSpace : transform;\n            Vector2 fieldSize = new Vector2(\n                _designResolution.x / Mathf.Max(1f, _pixelsPerWorldUnit),\n                _designResolution.y / Mathf.Max(1f, _pixelsPerWorldUnit)\n            );\n\n            Vector3 bottomLeft = space.TransformPoint(new Vector3(-fieldSize.x * 0.5f, 0f, -fieldSize.y * 0.5f));\n            Vector3 bottomRight = space.TransformPoint(new Vector3(fieldSize.x * 0.5f, 0f, -fieldSize.y * 0.5f));\n            Vector3 topRight = space.TransformPoint(new Vector3(fieldSize.x * 0.5f, 0f, fieldSize.y * 0.5f));\n            Vector3 topLeft = space.TransformPoint(new Vector3(-fieldSize.x * 0.5f, 0f, fieldSize.y * 0.5f));\n\n            Gizmos.color = Color.cyan;\n            Gizmos.DrawLine(bottomLeft, bottomRight);\n            Gizmos.DrawLine(bottomRight, topRight);\n            Gizmos.DrawLine(topRight, topLeft);\n            Gizmos.DrawLine(topLeft, bottomLeft);\n        }\n    }\n}\n", "GameplayCore/Field/ElementFieldVisualController.cs": "using System.Collections.Generic;\nusing UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Field\n{\n    public class ElementFieldVisualController : MonoBehaviour\n    {\n        [Header(\"References\")]\n        [SerializeField] private ElementFieldGrid _fieldGrid;\n        [SerializeField] private Transform _visualRoot;\n\n        [Header(\"Tile\")]\n        [SerializeField] private Material _tileMaterial;\n        [SerializeField, Min(0.001f)] private float _tileHeight = 0.02f;\n        [SerializeField, Range(0.1f, 1f)] private float _tileFillRatio = 0.96f;\n        [SerializeField] private float _yOffset = 0.01f;\n\n        [Header(\"Element Materials\")]\n        [SerializeField] private Material _iceTileMaterial;\n        [SerializeField] private Material _frozenTerrainMaterial;\n\n        [Header(\"Colors\")]\n        [SerializeField] private Color _fireColor = new Color(1f, 0.12f, 0.04f, 0.55f);\n        [SerializeField] private Color _iceColor = new Color(0.2f, 0.8f, 1f, 0.55f);\n        [SerializeField] private Color _poisonColor = new Color(0.3f, 1f, 0.2f, 0.55f);\n        [SerializeField] private Color _lightningColor = new Color(1f, 0.9f, 0.1f, 0.55f);\n        [SerializeField] private Color _windColor = new Color(0.75f, 1f, 0.85f, 0.45f);\n        [SerializeField] private Color _waterColor = new Color(0.1f, 0.35f, 1f, 0.45f);\n\n        private readonly Dictionary<Vector2Int, Renderer> _activeTiles = new();\n        private readonly Stack<Renderer> _tilePool = new();\n        private MaterialPropertyBlock _propertyBlock;\n\n        private static readonly int BaseColorId = Shader.PropertyToID(\"_BaseColor\");\n        private static readonly int ColorId = Shader.PropertyToID(\"_Color\");\n\n        private void Awake()\n        {\n            _propertyBlock = new MaterialPropertyBlock();\n        }\n\n        private void Reset()\n        {\n            _fieldGrid = FindFirstObjectByType<ElementFieldGrid>();\n            _visualRoot = transform;\n        }\n\n        private void OnEnable()\n        {\n            ElementFieldGrid grid = ResolveFieldGrid();\n\n            if (grid == null)\n            {\n                return;\n            }\n\n            grid.CellChanged += HandleCellChanged;\n            grid.CellCleared += HandleCellCleared;\n            grid.TerrainChanged += HandleTerrainChanged;\n        }\n\n        private void OnDisable()\n        {\n            ElementFieldGrid grid = ResolveFieldGrid();\n\n            if (grid == null)\n            {\n                return;\n            }\n\n            grid.CellChanged -= HandleCellChanged;\n            grid.CellCleared -= HandleCellCleared;\n            grid.TerrainChanged -= HandleTerrainChanged;\n        }\n\n        private ElementFieldGrid ResolveFieldGrid()\n        {\n            if (_fieldGrid == null)\n            {\n                _fieldGrid = ElementFieldGrid.Instance != null\n                    ? ElementFieldGrid.Instance\n                    : FindFirstObjectByType<ElementFieldGrid>();\n            }\n\n            return _fieldGrid;\n        }\n\n        private void HandleCellChanged(\n            Vector2Int coord,\n            ElementFieldCellData data,\n            ElementReactionResult reaction)\n        {\n            if (!data.IsActive)\n            {\n                HideTile(coord);\n                return;\n            }\n\n            if (reaction.ReactionType == ElementReactionType.Freeze ||\n                (data.TerrainElement == TerrainElementType.Ice &&\n                 data.LastReactionType == ElementReactionType.Freeze))\n            {\n                HideTile(coord);\n                return;\n            }\n\n            Renderer tile = GetOrCreateTile(coord);\n            ApplyTileTransform(tile.transform, coord);\n            ApplyTileMaterial(tile, data.CurrentElement);\n            ApplyTileColor(tile, data.CurrentElement);\n            tile.gameObject.SetActive(true);\n        }\n\n        private void HandleCellCleared(Vector2Int coord, ElementFieldCellData data)\n        {\n            HideTile(coord);\n        }\n\n        private void HandleTerrainChanged(Vector2Int coord, ElementFieldCellData data)\n        {\n            if (!data.IsActive)\n            {\n                HideTile(coord);\n            }\n        }\n\n        private void ShowTerrainTile(Vector2Int coord, TerrainElementType terrain)\n        {\n            Renderer tile = GetOrCreateTile(coord);\n            ApplyTileTransform(tile.transform, coord);\n            ApplyTerrainTileMaterial(tile, terrain);\n            ApplyTileColor(tile, GetTerrainElementColor(terrain));\n            tile.gameObject.SetActive(true);\n        }\n\n        private Renderer GetOrCreateTile(Vector2Int coord)\n        {\n            if (_activeTiles.TryGetValue(coord, out Renderer existingTile) &&\n                existingTile != null)\n            {\n                return existingTile;\n            }\n\n            Renderer tile = _tilePool.Count > 0\n                ? _tilePool.Pop()\n                : CreateTile();\n\n            tile.gameObject.name = $\"ElementFieldVisual_{coord.x}_{coord.y}\";\n            _activeTiles[coord] = tile;\n            return tile;\n        }\n\n        private Renderer CreateTile()\n        {\n            GameObject tileObject = GameObject.CreatePrimitive(PrimitiveType.Cube);\n            tileObject.transform.SetParent(_visualRoot != null ? _visualRoot : transform, false);\n\n            if (tileObject.TryGetComponent(out Collider tileCollider))\n            {\n                Destroy(tileCollider);\n            }\n\n            Renderer renderer = tileObject.GetComponent<Renderer>();\n\n            if (_tileMaterial != null)\n            {\n                renderer.sharedMaterial = _tileMaterial;\n            }\n            else\n            {\n                renderer.sharedMaterial = CreateFallbackMaterial();\n            }\n\n            tileObject.SetActive(false);\n            return renderer;\n        }\n\n        private Material CreateFallbackMaterial()\n        {\n            Shader shader = Shader.Find(\"Universal Render Pipeline/Lit\");\n\n            if (shader == null)\n            {\n                shader = Shader.Find(\"Standard\");\n            }\n\n            Material material = new Material(shader);\n            material.name = \"Element Field Visual Runtime Material\";\n            return material;\n        }\n\n        private void ApplyTileTransform(Transform tileTransform, Vector2Int coord)\n        {\n            ElementFieldGrid grid = ResolveFieldGrid();\n\n            if (grid == null)\n            {\n                return;\n            }\n\n            Vector2 cellSize = grid.CellWorldSize * _tileFillRatio;\n\n            tileTransform.position =\n                grid.CellToWorld(coord) +\n                grid.FieldSpace.up * (_yOffset + _tileHeight * 0.5f);\n\n            tileTransform.rotation = grid.FieldSpace.rotation;\n            tileTransform.localScale = new Vector3(cellSize.x, _tileHeight, cellSize.y);\n        }\n\n        private void ApplyTileColor(Renderer tile, ElementType element)\n        {\n            if (tile == null)\n            {\n                return;\n            }\n\n            if (_propertyBlock == null)\n            {\n                _propertyBlock = new MaterialPropertyBlock();\n            }\n\n            Color color = GetElementColor(element);\n\n            ApplyTileColor(tile, color);\n        }\n\n        private void ApplyTileMaterial(Renderer tile, ElementType element)\n        {\n            if (tile == null)\n            {\n                return;\n            }\n\n            Material material = element switch\n            {\n                ElementType.Ice => _iceTileMaterial != null ? _iceTileMaterial : _tileMaterial,\n                _ => _tileMaterial\n            };\n\n            if (material != null && tile.sharedMaterial != material)\n            {\n                tile.sharedMaterial = material;\n            }\n        }\n\n        private void ApplyTerrainTileMaterial(Renderer tile, TerrainElementType terrain)\n        {\n            if (tile == null)\n            {\n                return;\n            }\n\n            Material material = terrain switch\n            {\n                TerrainElementType.Ice => _frozenTerrainMaterial != null\n                    ? _frozenTerrainMaterial\n                    : _iceTileMaterial != null\n                        ? _iceTileMaterial\n                        : _tileMaterial,\n                _ => _tileMaterial\n            };\n\n            if (material != null && tile.sharedMaterial != material)\n            {\n                tile.sharedMaterial = material;\n            }\n        }\n\n        private void ApplyTileColor(Renderer tile, Color color)\n        {\n            if (tile == null)\n            {\n                return;\n            }\n\n            if (_propertyBlock == null)\n            {\n                _propertyBlock = new MaterialPropertyBlock();\n            }\n\n            tile.GetPropertyBlock(_propertyBlock);\n            _propertyBlock.SetColor(BaseColorId, color);\n            _propertyBlock.SetColor(ColorId, color);\n            tile.SetPropertyBlock(_propertyBlock);\n        }\n\n        private void HideTile(Vector2Int coord)\n        {\n            if (!_activeTiles.TryGetValue(coord, out Renderer tile) ||\n                tile == null)\n            {\n                return;\n            }\n\n            _activeTiles.Remove(coord);\n            tile.gameObject.SetActive(false);\n            _tilePool.Push(tile);\n        }\n\n        private Color GetElementColor(ElementType element)\n        {\n            return element switch\n            {\n                ElementType.Fire => _fireColor,\n                ElementType.Ice => _iceColor,\n                ElementType.Poison => _poisonColor,\n                ElementType.Lightning => _lightningColor,\n                ElementType.Wind => _windColor,\n                ElementType.Water => _waterColor,\n                _ => Color.clear\n            };\n        }\n\n        private Color GetTerrainElementColor(TerrainElementType terrain)\n        {\n            return terrain switch\n            {\n                TerrainElementType.Ice => _iceColor,\n                TerrainElementType.Water => _waterColor,\n                _ => Color.clear\n            };\n        }\n    }\n}\n", "GameplayCore/Field/ElementReactionResolver.cs": "using UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Field\n{\n    public static class ElementReactionResolver\n    {\n        public static ElementReactionResult Resolve(\n            TerrainElementType terrain,\n            ElementType current,\n            ElementType incoming)\n        {\n            return Resolve(\n                terrain,\n                current,\n                new ElementPaintContext(incoming)\n            );\n        }\n\n        public static ElementReactionResult Resolve(\n            TerrainElementType terrain,\n            ElementType current,\n            ElementPaintContext paintContext)\n        {\n            ElementType incoming = paintContext.Element;\n\n            if (incoming == ElementType.None)\n            {\n                return ElementReactionResult.None;\n            }\n\n            // Grass + Fire: fire spreads wider and lasts longer.\n            if (terrain == TerrainElementType.Grass && incoming == ElementType.Fire)\n            {\n                int level = Mathf.Max(1, paintContext.ElementLevel);\n                int spreadCellRadius = level >= 5\n                    ? 3\n                    : level >= 3\n                        ? 2\n                        : 1;\n\n                float durationMultiplier = (1.2f + level * 0.15f) * paintContext.PowerMultiplier;\n                float spreadDelay = Mathf.Max(0.03f, 0.1f - level * 0.01f);\n                float spreadDurationMultiplier = Mathf.Min(1.2f, 0.65f + level * 0.05f);\n\n                return new ElementReactionResult(\n                    ElementReactionType.SpreadFire,\n                    ElementType.Fire,\n                    durationMultiplier: durationMultiplier,\n                    spreadCellRadius: spreadCellRadius,\n                    spreadDelay: spreadDelay,\n                    spreadDurationMultiplier: spreadDurationMultiplier,\n                    shouldApplyStatus: true\n                );\n            }\n\n            // Sand + Wind: hot wind burns enemies standing in the cell.\n            if (terrain == TerrainElementType.Sand && incoming == ElementType.Wind)\n            {\n                int level = Mathf.Max(1, paintContext.ElementLevel);\n                int spreadCellRadius = level >= 5\n                    ? 3\n                    : level >= 3\n                        ? 2\n                        : 1;\n                float durationMultiplier = (1f + level * 0.15f) * paintContext.PowerMultiplier;\n                float spreadDurationMultiplier = Mathf.Min(1.25f, 0.65f + level * 0.08f);\n\n                return new ElementReactionResult(\n                    ElementReactionType.HotWind,\n                    ElementType.Wind,\n                    durationMultiplier: durationMultiplier,\n                    spreadCellRadius: spreadCellRadius,\n                    spreadElement: ElementType.Fire,\n                    spreadDelay: 0.04f,\n                    spreadDurationMultiplier: spreadDurationMultiplier,\n                    shouldApplyStatus: true\n                );\n            }\n\n            // Water + Ice: freeze the water terrain permanently.\n            if (terrain == TerrainElementType.Water && incoming == ElementType.Ice)\n            {\n                int level = Mathf.Max(1, paintContext.ElementLevel);\n                float durationMultiplier = (1.2f + level * 0.1f) * paintContext.PowerMultiplier;\n\n                return new ElementReactionResult(\n                    ElementReactionType.Freeze,\n                    ElementType.Ice,\n                    durationMultiplier: durationMultiplier,\n                    shouldApplyStatus: true\n                );\n            }\n\n            // Current Ice + Fire: melt ice into water.\n            if (current == ElementType.Ice && incoming == ElementType.Fire)\n            {\n                return new ElementReactionResult(\n                    ElementReactionType.Melt,\n                    ElementType.Water,\n                    durationMultiplier: 0.8f,\n                    spreadRadius: 0f,\n                    shouldApplyStatus: false\n                );\n            }\n\n            // Current Fire + Ice: steam burst.\n            if (current == ElementType.Fire && incoming == ElementType.Ice)\n            {\n                return new ElementReactionResult(\n                    ElementReactionType.Steam,\n                    ElementType.Water,\n                    durationMultiplier: 0.6f,\n                    spreadRadius: 0.5f,\n                    shouldApplyStatus: false\n                );\n            }\n\n            // Poison field + Fire: toxic smoke reaction.\n            if (current == ElementType.Poison && incoming == ElementType.Fire)\n            {\n                return new ElementReactionResult(\n                    ElementReactionType.ToxicSmoke,\n                    ElementType.Poison,\n                    durationMultiplier: 0.8f,\n                    spreadRadius: 1f,\n                    shouldApplyStatus: true\n                );\n            }\n\n            // Default: incoming element overrides or activates the cell.\n            return new ElementReactionResult(\n                ElementReactionType.Ignite,\n                incoming,\n                durationMultiplier: 1f,\n                spreadRadius: 0f,\n                shouldApplyStatus: incoming != ElementType.None\n            );\n        }\n    }\n}\n", "GameplayCore/Weapon/Aim/AimLineRenderer.cs": "using Shield_Shot.GameplayCore.Weapon.Core;\nusing Shield_Shot.GameplayCore.Weapon.Projectile;\nusing UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Weapon.Aim\n{\n    [RequireComponent(typeof(LineRenderer))]\n    public class AimLineRenderer : MonoBehaviour\n    {\n        #region Inspector\n        [Header(\"Distance Settings\")]\n        [Tooltip(\"차징 0% 일 때 조준선 최소 거리\")]\n        [SerializeField] private float minLineDistance = 0.1f;\n\n        [Tooltip(\"차징 100% 일 때 조준선 최대 거리\")]\n        [SerializeField] private float maxLineDistance = 99f;\n\n        [Header(\"Collision Settings\")]\n        [Tooltip(\"기본 벽 반사 횟수 (특성이 없을 때의 기초값)\")]\n        [SerializeField] private int defaultBounceCount = 0;\n\n        [Tooltip(\"벽으로 인식할 레이어 마스크\")]\n        [SerializeField] private LayerMask wallLayerMask;\n\n        [Header(\"Player Status Link\")]\n        [Tooltip(\"플레이어 리스트에서 찾을 반사 특성 SO 에셋\")]\n        [SerializeField] private ProjectileBehaviorSO reflectBehaviorSO;\n\n        [Tooltip(\"반사 특성 1레벨당 추가될 반사 횟수\")]\n        [SerializeField] private int bounceCountPerLevel = 1;\n\n        [Header(\"Line Shape\")]\n        [SerializeField, Min(0)] private int cornerVertices = 6;\n        [SerializeField, Min(0)] private int capVertices = 4;\n        [SerializeField, Min(0f)] private float bounceCornerInset = 0.06f;\n\n        [Header(\"Collision Prediction\")]\n        [SerializeField] private bool useProjectileCollisionRadius = true;\n        [SerializeField, Min(0f)] private float fallbackCastRadius;\n        [SerializeField, Min(0.01f)] private float castRadiusMultiplier = 1f;\n        [SerializeField, Min(0f)] private float maxPredictionCastRadius = 0.18f;\n        #endregion\n\n        #region 내부 참조\n        private LineRenderer lineRenderer;\n        private WeaponBase currentWeapon;\n\n        public float MaxLineDistance => maxLineDistance;\n        public LayerMask WallLayerMask => wallLayerMask;\n        public int DefaultBounceCount => defaultBounceCount;\n        #endregion\n\n        #region Unity 생명주기\n        private void Awake()\n        {\n            lineRenderer = GetComponent<LineRenderer>();\n            lineRenderer.useWorldSpace = true;\n            lineRenderer.enabled = false;\n            EnsureWallLayerMask();\n        }\n        #endregion\n\n        #region 공개 메서드\n\n        // 조준선 활성화\n        public void Show(WeaponBase activeWeapon)\n        {\n            if (activeWeapon == null || lineRenderer == null) return;\n\n            if (currentWeapon == activeWeapon && lineRenderer.enabled) return;\n\n            // 무기가 들고 있는 고유 비주얼 데이터를 통째로 가로채서 라인 렌더러에 주입\n            currentWeapon = activeWeapon;\n            WeaponAimVisualData visual = activeWeapon.AimVisualData;\n\n            lineRenderer.material = visual.LineMaterial;\n            lineRenderer.useWorldSpace = true;\n            lineRenderer.startWidth = visual.StartWidth;\n            lineRenderer.endWidth = visual.EndWidth;\n            lineRenderer.textureMode = visual.TextureMode;\n            lineRenderer.numCornerVertices = cornerVertices;\n            lineRenderer.numCapVertices = capVertices;\n\n            // 유니티 내부 셰이더 프로퍼티 명칭(_MainTex)에 타일링 스케일 적용\n            if (lineRenderer.material != null && lineRenderer.material.HasProperty(\"_MainTex\"))\n            {\n                lineRenderer.material.SetTextureScale(\"_MainTex\", visual.TextureScale);\n            }\n\n            lineRenderer.enabled = true;\n        }\n\n        // 조준선 비활성화\n        public void Hide()\n        {\n            currentWeapon = null;\n            if (lineRenderer != null) lineRenderer.enabled = false;\n        }\n\n        // 조준선 경로를 갱신\n        public void UpdateLine(Vector3 aimDirection, float chargeRatio, Vector3 origin)\n        {\n            // 스크린 XY → 월드 XZ 변환\n            Vector3 worldDir = AimDirectionUtility.ToWorldXZ(aimDirection);\n            if (worldDir == Vector3.zero) return;\n\n            int currentMaxBounce = CalculateDynamicBounceCount();\n            float castRadius = ResolveCastRadius();\n            Vector3 predictionOrigin = ResolvePredictionOrigin(origin, worldDir);\n\n            float totalDistance = Mathf.Lerp(minLineDistance, maxLineDistance, chargeRatio);\n            var points = CalculateBouncePoints(predictionOrigin, worldDir, totalDistance, currentMaxBounce, castRadius);\n\n            lineRenderer.positionCount = points.Length;\n            lineRenderer.SetPositions(points);\n        }\n\n        private Vector3 ResolvePredictionOrigin(Vector3 firePointOrigin, Vector3 worldDirection)\n        {\n            if (currentWeapon != null &&\n                currentWeapon.ProjectileFireHandler is IProjectileAimPredictionProvider predictionProvider)\n            {\n                return predictionProvider.GetPredictedProjectileOrigin(firePointOrigin, worldDirection);\n            }\n\n            return firePointOrigin;\n        }\n        #endregion\n\n        #region 내부 메서드\n        private int CalculateDynamicBounceCount()\n        {\n            // 방어 코드: 기준이 될 SO가 인스펙터에 할당 안 되었거나 싱글톤이 비어있으면 기본값 반환\n            if (!TryGetPlayerStatus(out PlayerStatus playerStatus))\n                return defaultBounceCount;\n\n            // PlayerStatus의 CurrentBehaviors 리스트에서 ID가 일치하는 특성이 있는지 매칭 시도\n            int index = playerStatus.CurrentBehaviors.FindIndex(IsReflectBehavior);\n\n            if (index >= 0)\n            {\n                // 특성을 보유 중이라면: 기본 반사 횟수 + (특성 레벨 * 레벨당 증가량)\n                int reflectLevel = playerStatus.CurrentBehaviors[index].Level;\n                return defaultBounceCount + (reflectLevel * bounceCountPerLevel);\n            }\n\n            // 특성이 리스트에 없다면 0번 혹은 세팅된 기본값 반환\n            return defaultBounceCount;\n        }\n\n        private float ResolveCastRadius()\n        {\n            float radius = fallbackCastRadius;\n\n            if (useProjectileCollisionRadius &&\n                currentWeapon != null &&\n                currentWeapon.ProjectileFireHandler is IProjectileAimPredictionProvider predictionProvider &&\n                predictionProvider.TryGetProjectileCollisionRadius(currentWeapon.Type, out float predictedRadius))\n            {\n                radius = predictedRadius;\n                return ClampPredictionCastRadius(radius * castRadiusMultiplier);\n            }\n\n            if (useProjectileCollisionRadius &&\n                currentWeapon != null &&\n                ProjectileManager.Instance != null &&\n                ProjectileManager.Instance.TryGetProjectileCollisionRadius(currentWeapon.Type, out float projectileRadius))\n            {\n                radius = projectileRadius;\n                return ClampPredictionCastRadius(radius * castRadiusMultiplier);\n            }\n\n            return ClampPredictionCastRadius(radius);\n        }\n\n        private float ClampPredictionCastRadius(float radius)\n        {\n            float safeRadius = Mathf.Max(0f, radius);\n            return maxPredictionCastRadius > 0f\n                ? Mathf.Min(safeRadius, maxPredictionCastRadius)\n                : safeRadius;\n        }\n\n        // 인자값 맨 끝에 bounceCount를 동적으로 받도록 수정\n        private bool TryGetPlayerStatus(out PlayerStatus playerStatus)\n        {\n            playerStatus = null;\n\n            if (currentWeapon != null && currentWeapon.TryGetComponent(out playerStatus))\n            {\n                return true;\n            }\n\n            return LocalPlayerStatusContext.TryGet(out playerStatus);\n        }\n\n        private bool IsReflectBehavior(ActiveBehavior behavior)\n        {\n            ProjectileBehaviorSO behaviorSO = behavior.BehaviorSO;\n            if (behaviorSO == null)\n            {\n                return false;\n            }\n\n            if (reflectBehaviorSO != null &&\n                string.Equals(behaviorSO.BehaviorID, reflectBehaviorSO.BehaviorID, System.StringComparison.OrdinalIgnoreCase))\n            {\n                return true;\n            }\n\n            string id = string.IsNullOrWhiteSpace(behaviorSO.BehaviorID)\n                ? string.Empty\n                : behaviorSO.BehaviorID.Trim();\n            string typeName = behaviorSO.GetType().Name;\n\n            return id == \"1\" ||\n                   string.Equals(id, \"StandardReflect\", System.StringComparison.OrdinalIgnoreCase) ||\n                   string.Equals(id, \"RandomReflect\", System.StringComparison.OrdinalIgnoreCase) ||\n                   typeName.IndexOf(\"StandardReflect\", System.StringComparison.OrdinalIgnoreCase) >= 0 ||\n                   typeName.IndexOf(\"RandomReflect\", System.StringComparison.OrdinalIgnoreCase) >= 0;\n        }\n\n        private Vector3[] CalculateBouncePoints(\n            Vector3 origin,\n            Vector3 direction,\n            float remainingDistance,\n            int bounceCount,\n            float castRadius)\n        {\n            var points = new System.Collections.Generic.List<Vector3> { origin };\n            var curOrigin = origin;\n            var curDir = direction;\n            int remainingBounceCount = Mathf.Max(0, bounceCount);\n            bool stoppedByWall = false;\n\n            // 고정된 maxBounceCount 대신 매개변수로 들어온 동적 bounceCount를 루프 한계로 설정함\n            while (remainingDistance > 0f)\n            {\n                if (TryCastPrediction(curOrigin, curDir, remainingDistance, castRadius, out RaycastHit hit))\n                {\n                    Vector3 incomingDir = curDir;\n                    remainingDistance -= Mathf.Max(hit.distance, 0.001f);\n                    Vector3 bouncePoint = GetBouncePoint(hit, castRadius);\n\n                    if (remainingBounceCount <= 0)\n                    {\n                        points.Add(bouncePoint);\n                        stoppedByWall = true;\n                        break;\n                    }\n\n                    remainingBounceCount--;\n                    curDir = Vector3.Reflect(incomingDir, hit.normal);\n\n                    curDir.y = 0f;\n                    curDir = curDir.normalized;\n                    AddBounceCornerPoints(points, bouncePoint, incomingDir, curDir);\n                    curOrigin = bouncePoint + curDir * 0.01f;\n                }\n                else\n                {\n                    // 레이캐스트가 벽에 닿지 않고 공간이 남았을 때 직선 처리 후 탈출\n                    points.Add(curOrigin + curDir * remainingDistance);\n                    return points.ToArray();\n                }\n            }\n\n            // 만약 반사 횟수를 다 채웠는데도 남은 거리가 있다면 마지막 튕긴 지점에서 남은 거리만큼 최종 연장선 추가\n            if (!stoppedByWall && remainingDistance > 0f && points.Count > 0)\n            {\n                points.Add(curOrigin + curDir * remainingDistance);\n            }\n\n            return points.ToArray();\n        }\n\n        private bool TryCastPrediction(\n            Vector3 origin,\n            Vector3 direction,\n            float distance,\n            float castRadius,\n            out RaycastHit hit)\n        {\n            if (castRadius > 0f)\n            {\n                return Physics.SphereCast(origin, castRadius, direction, out hit, distance, wallLayerMask);\n            }\n\n            return Physics.Raycast(origin, direction, out hit, distance, wallLayerMask);\n        }\n\n        private static Vector3 GetBouncePoint(RaycastHit hit, float castRadius)\n        {\n            if (castRadius <= 0f || hit.normal.sqrMagnitude <= 0.0001f)\n            {\n                return hit.point;\n            }\n\n            return hit.point + hit.normal.normalized * castRadius;\n        }\n\n        private void EnsureWallLayerMask()\n        {\n            IncludeWallLayer(\"Wall\");\n            IncludeWallLayer(\"PvpWall\");\n        }\n\n        private void IncludeWallLayer(string layerName)\n        {\n            int layer = LayerMask.NameToLayer(layerName);\n            if (layer < 0)\n            {\n                return;\n            }\n\n            wallLayerMask |= 1 << layer;\n        }\n\n        private void AddBounceCornerPoints(System.Collections.Generic.List<Vector3> points, Vector3 hitPoint, Vector3 incomingDir, Vector3 reflectedDir)\n        {\n            float inset = Mathf.Max(0f, bounceCornerInset);\n\n            if (inset <= 0f)\n            {\n                points.Add(hitPoint);\n                return;\n            }\n\n            Vector3 beforeCorner = hitPoint - incomingDir.normalized * inset;\n            Vector3 afterCorner = hitPoint + reflectedDir.normalized * inset;\n\n            if (points.Count > 0 && Vector3.Distance(points[^1], beforeCorner) > 0.001f)\n            {\n                points.Add(beforeCorner);\n            }\n\n            points.Add(hitPoint);\n\n            if (Vector3.Distance(hitPoint, afterCorner) > 0.001f)\n            {\n                points.Add(afterCorner);\n            }\n        }\n\n        #endregion\n    }\n}\n", "GameplayCore/Weapon/Core/WeaponBase.cs": "using Shield_Shot.Audio;\nusing Shield_Shot.DataManagement.InventorySystem;\nusing Shield_Shot.GameplayCore.Render;\nusing Shield_Shot.GameplayCore.Weapon.Aim;\nusing Shield_Shot.GameplayCore.Weapon.Charge;\nusing Shield_Shot.GameplayCore.Weapon.Projectile;\nusing Shield_Shot.InputSystem.Data;\nusing UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Weapon.Core\n{\n    [RequireComponent(typeof(WeaponAimController))]\n    [RequireComponent(typeof(WeaponRotationController))]\n    [RequireComponent(typeof(WeaponChargeController))]\n    public abstract class WeaponBase : MonoBehaviour, IWeaponStrategy\n    {\n        #region Inspector\n        [Header(\"References\")]\n        [SerializeField] protected Transform firePoint;\n\n        [Header(\"[Base] Attack Cooldown Settings\")]\n        [Tooltip(\"무기 발사 후 재입력/장전이 불가능한 기본 쿨타임 (초)\")]\n        [SerializeField] protected float attackCooldownDuration = 0.5f;\n\n        [Header(\"[Base] Critical Settings\")]\n        [Tooltip(\"크리티컬 발생 시 데미지 배율\")]\n        [SerializeField] protected float criticalDamageMultiplier = 2.0f;\n\n        [Header(\"[Base] Charge VFX Settings\")]\n        [Tooltip(\"차징 진행 중 일정 주기마다 재생할 VFX 타입\")]\n        [SerializeField] protected VFXType chargingVfxType = VFXType.Charging;\n        [Tooltip(\"차징 이펙트 생성 주기 (초 단위)\")]\n        [SerializeField] protected float vfxSpawnInterval = 0.15f;\n        [Tooltip(\"차징 VFX 자동 반환 시간 (초)\")]\n        [SerializeField] protected float chargingVfxDuration = 1f;\n        [Tooltip(\"풀차징 달성 순간 딱 1번 재생할 VFX 타입\")]\n        [SerializeField] protected VFXType fullChargeVfxType = VFXType.FullCharging;\n        [Tooltip(\"풀차징 VFX 자동 반환 시간 (초)\")]\n        [SerializeField] protected float fullChargeVfxDuration = 2f;\n\n        [Header(\"[Base] Weapon Aim Visual Settings\")]\n        [SerializeField] private WeaponAimVisualData _aimVisualData;\n\n        [Header(\"[Base] Projectile Fire\")]\n        [SerializeField] private MonoBehaviour _projectileFireHandlerOverride;\n\n        [Header(\"[Base] Rotation\")]\n        [SerializeField] private bool _applyRotationLocally = true;\n\n        [Header(\"[Base] Sound\")]\n        [Tooltip(\"이 무기로 교체/장착됐을 때 재생할 사운드 (활, 라이플 등 무기마다 다르게 설정)\")]\n        [SerializeField] protected AudioClip equipSfx;\n        [SerializeField] private float _equipVolume = 1f;\n\n        [Header(\"[Base] Active Skill\")]\n        [Tooltip(\"기본/테스트용 스킬 (WeaponItem 데이터가 없는 테스트 프리팹에서 쓰인다). \" +\n                 \"실제 게임에서는 WeaponManager가 뽑기 결과(WeaponItem.SkillType)를 \" +\n                 \"WeaponSkillDatabaseSO에서 찾아 SetSkill()로 덮어쓴다.\")]\n        [SerializeField] private ActiveWeaponSkillSO weaponSkill;\n        #endregion\n\n        private float _vfxTimer;\n        private bool _isFullChargeVFXPlayed;\n        private float _attackCooldownTimer = 0f;\n        protected abstract Transform EffectSpawnPoint { get; }\n\n        protected WeaponAimController aimController;\n        protected WeaponRotationController rotationController;\n        protected WeaponChargeController chargeController;\n        protected AimLineRenderer aimLineRenderer;\n        protected ProjectileShooter projectileLauncher;\n        protected IProjectileFireHandler projectileFireHandler;\n\n        #region 공개 프로퍼티\n        public abstract WeaponType Type { get; }\n        public WeaponAimVisualData AimVisualData => _aimVisualData;\n        public float ChargeRatio => chargeController != null ? chargeController.ChargeRatio : 0f;\n        public Vector3 AimDirection => aimController != null ? aimController.AimDirection : Vector3.right;\n        public Transform FirePoint => firePoint;\n        public bool IsCooldownActive => _attackCooldownTimer > 0f;\n        public float CriticalDamageMultiplier => criticalDamageMultiplier;\n        public IProjectileFireHandler ProjectileFireHandler => projectileFireHandler;\n\n        /// <summary>이 무기 프리팹에 지정된 능동 스킬. 없으면 null.</summary>\n        public ActiveWeaponSkillSO Skill => weaponSkill;\n        #endregion\n\n        public void SetSkill(ActiveWeaponSkillSO skill)\n        {\n            weaponSkill = skill;\n        }\n\n        public void PlayEquipSound()\n        {\n            if (equipSfx == null) return;\n\n            if (SoundManager.Instance != null)\n                SoundManager.Instance.PlaySFX(equipSfx, _equipVolume);\n        }\n\n        public void SetLocalRotationEnabled(bool isEnabled) => _applyRotationLocally = isEnabled;\n\n        public void SetProjectileFireHandler(IProjectileFireHandler fireHandler)\n        {\n            projectileFireHandler = fireHandler;\n            _projectileFireHandlerOverride = fireHandler as MonoBehaviour;\n        }\n\n        protected virtual void Awake()\n        {\n            aimController = GetComponent<WeaponAimController>();\n            rotationController = GetComponent<WeaponRotationController>();\n            chargeController = GetComponent<WeaponChargeController>();\n            aimLineRenderer = GetComponent<AimLineRenderer>();\n            projectileLauncher = GetComponent<ProjectileShooter>();\n            projectileFireHandler = ResolveProjectileFireHandler();\n        }\n\n        protected virtual void Update()\n        {\n            if (_attackCooldownTimer > 0f)\n                _attackCooldownTimer -= Time.deltaTime;\n        }\n\n        public virtual void Initialize()\n        {\n            aimController = GetComponent<WeaponAimController>();\n            rotationController = GetComponent<WeaponRotationController>();\n            chargeController = GetComponent<WeaponChargeController>();\n            aimLineRenderer = GetComponent<AimLineRenderer>();\n            projectileLauncher = GetComponent<ProjectileShooter>();\n            projectileFireHandler = ResolveProjectileFireHandler();\n\n            chargeController?.Initialize();\n            aimLineRenderer?.Hide();\n            _attackCooldownTimer = 0f;\n\n            Debug.Log($\"[{gameObject.name}] 무기 컴포넌트 재바인딩 및 초기화 완료! Skill={(weaponSkill != null ? weaponSkill.BehaviorName : \"없음\")}\");\n        }\n\n        public virtual void ApplyWeaponData(WeaponItem data)\n        {\n            if (data == null) return;\n\n            attackCooldownDuration = data.FinalFireRate;\n            criticalDamageMultiplier = data.FinalCriticalDamageMultiplier;\n\n            Debug.Log($\"[{gameObject.name}] WeaponData 적용 완료. \" +\n                      $\"CoolDown={attackCooldownDuration}s, \" +\n                      $\"CritMultiplier={criticalDamageMultiplier}\");\n        }\n\n        protected void HandleChargeVFX(float currentChargeRatio)\n        {\n            if (EffectSpawnPoint == null) return;\n\n            if (currentChargeRatio >= 0.99f)\n            {\n                if (!_isFullChargeVFXPlayed)\n                {\n                    SpawnVFX(fullChargeVfxType, fullChargeVfxDuration);\n                    _isFullChargeVFXPlayed = true;\n                    OnFullChargeAchieved();\n                }\n            }\n            else\n            {\n                _vfxTimer += Time.deltaTime;\n                if (_vfxTimer >= vfxSpawnInterval)\n                {\n                    if (currentChargeRatio > 0.05f)\n                        SpawnVFX(chargingVfxType, chargingVfxDuration);\n                    _vfxTimer = 0f;\n                }\n                _isFullChargeVFXPlayed = false;\n            }\n        }\n\n        private void SpawnVFX(VFXType vfxType, float duration)\n        {\n            if (vfxType == VFXType.None || EffectSpawnPoint == null) return;\n\n            VFXPoolManager vfxPoolManager = VFXPoolManager.EnsureInstance();\n            if (vfxPoolManager == null)\n            {\n                Debug.LogWarning($\"[WeaponBase] VFXPoolManager 없음. {vfxType} VFX 스킵.\");\n                return;\n            }\n\n            vfxPoolManager.SpawnVFX(vfxType, EffectSpawnPoint.position, EffectSpawnPoint.rotation, duration);\n        }\n\n        protected void StartAttackCooldown() => _attackCooldownTimer = CalculateFinalCooldown(attackCooldownDuration);\n        protected void StartAttackCooldown(float customDuration) => _attackCooldownTimer = CalculateFinalCooldown(customDuration);\n\n        private float CalculateFinalCooldown(float baseCooldown)\n        {\n            float result = baseCooldown;\n\n            if (LocalPlayerStatusContext.TryGet(out PlayerStatus playerStatus))\n            {\n                for (int i = 0; i < playerStatus.CurrentBehaviors.Count; i++)\n                {\n                    ActiveBehavior active = playerStatus.CurrentBehaviors[i];\n                    if (active.BehaviorSO is AttackSpeedModifierSO attackSpeedSO)\n                    {\n                        result = attackSpeedSO.ApplyCooldown(result, active.Level);\n                    }\n                }\n            }\n\n            return Mathf.Max(0.01f, result);\n        }\n\n        protected void ResetChargeVFXStates()\n        {\n            _vfxTimer = 0f;\n            _isFullChargeVFXPlayed = false;\n        }\n\n        protected virtual void OnFullChargeAchieved() { }\n\n        #region IWeaponStrategy 구현\n        public virtual void HandleInputStay(InputContext ctx)\n        {\n            if (IsCooldownActive)\n            {\n                chargeController?.Reset();\n                aimLineRenderer?.Hide();\n                return;\n            }\n\n            aimController?.UpdateAimDirection(ctx.dragVector);\n            ApplyLocalRotation();\n\n            if (ctx.state == GestureState.Charging || ctx.state == GestureState.ChargedComplete)\n                chargeController?.Tick(Time.deltaTime);\n            else\n                chargeController?.Reset();\n\n            if (firePoint != null)\n            {\n                aimLineRenderer?.Show(this);\n                aimLineRenderer?.UpdateLine(AimDirection, ChargeRatio, firePoint.position);\n            }\n        }\n\n        public abstract void HandleInputUp(InputContext ctx);\n\n        public virtual void Deactivate()\n        {\n            chargeController?.Reset();\n            aimLineRenderer?.Hide();\n        }\n\n        protected void ApplyLocalRotation()\n        {\n            if (!_applyRotationLocally) return;\n            rotationController?.SyncRotation(AimDirection);\n        }\n\n        private IProjectileFireHandler ResolveProjectileFireHandler()\n        {\n            if (_projectileFireHandlerOverride is IProjectileFireHandler overrideHandler)\n            {\n                Debug.Log($\"[{gameObject.name}] Projectile fire handler resolved by override: {_projectileFireHandlerOverride.GetType().Name}\");\n                return overrideHandler;\n            }\n\n            if (_projectileFireHandlerOverride != null)\n                Debug.LogWarning($\"[{gameObject.name}] Projectile fire handler override must implement IProjectileFireHandler.\");\n\n            MonoBehaviour[] behaviours = GetComponents<MonoBehaviour>();\n            IProjectileFireHandler fallbackHandler = null;\n\n            for (int i = 0; i < behaviours.Length; i++)\n            {\n                if (behaviours[i] is not IProjectileFireHandler handler) continue;\n\n                if (handler is not ProjectileShooter)\n                {\n                    Debug.Log($\"[{gameObject.name}] Projectile fire handler resolved by component: {behaviours[i].GetType().Name}\");\n                    return handler;\n                }\n\n                fallbackHandler ??= handler;\n            }\n\n            if (fallbackHandler != null)\n                Debug.Log($\"[{gameObject.name}] Projectile fire handler resolved by fallback: {fallbackHandler.GetType().Name}\");\n            else\n                Debug.LogWarning($\"[{gameObject.name}] Projectile fire handler is missing.\");\n\n            return fallbackHandler;\n        }\n        #endregion\n    }\n}", "GameplayCore/Weapon/Projectile/IProjectileFireHandler.cs": "using Shield_Shot.InputSystem.Data;\nusing UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Weapon.Projectile\n{\n    public interface IProjectileFireHandler\n    {\n        void Fire(Transform firePoint, Vector3 aimDirection, float chargeRatio, bool isCritical);\n    }\n\n    public interface IProjectileAimPredictionProvider\n    {\n        Vector3 GetPredictedProjectileOrigin(Vector3 firePointPosition, Vector3 worldDirection);\n        bool TryGetProjectileCollisionRadius(WeaponType weaponType, out float radius);\n    }\n}\n", "GameplayCore/Weapon/Projectile/ProjectileBase.cs": "using System;\nusing System.Collections.Generic;\nusing Shield_Shot.GameplayCore.Weapon.Projectile;\nusing UnityEngine;\nusing Shield_Shot.GameplayCore.Network.Pvp;\nusing Shield_Shot.InputSystem.Data;\n\nnamespace Shield_Shot.GameplayCore.Weapon.Projectile\n{\n    public class ProjectileBase : MonoBehaviour\n    {\n        [Header(\"Collision Detection\")]\n        [SerializeField] private LayerMask _environmentLayer; // 벽이나 장애물 레이어\n        [SerializeField] private LayerMask _targetLayer;      // 적 캐릭터 레이어\n        [SerializeField] private float _projectileRadius = 0.18f; // 투사체 두께 (구체 레이캐스트용)\n\n        [Header(\"Movement Settings\")]\n        public float BaseSpeed = 10f;\n        [SerializeField] private bool _simulateInUpdate = true;\n        private Vector3 _velocity;\n\n        public Vector3 Direction\n        {\n            get\n            {\n                return _velocity.sqrMagnitude > 0.0001f\n                    ? _velocity.normalized\n                    : transform.forward;\n            }\n        }\n\n        public float ProjectileRadius => _projectileRadius;\n        public int CollisionBehaviorCount => _collisionBehaviors.Count;\n        public bool IsCritical { get; set; }\n\n        public ProjectileShooter Launcher { get; set; }\n        public WeaponType SourceWeaponType { get; set; }\n        public float ChargeRatio { get; set; }\n        public float ProjectileDamage { get; set; }\n        public event Action<ProjectileBase> ReleaseRequested;\n        public event Action<ProjectileBase, RaycastHit> CollisionExecuted;\n        public event Action<ProjectileBase, Collider> HitExecuted;\n        public event Func<ProjectileBase, RaycastHit, bool> SplitRequested;\n\n        private bool _useExternalRelease;\n        private bool _isReleased;\n        private bool _loggedNoCastHit;\n        private readonly HashSet<int> _hitTargetIds = new HashSet<int>();\n        private readonly Dictionary<Renderer, Material[]> _originalMaterialsByRenderer = new Dictionary<Renderer, Material[]>();\n        private Renderer[] _cachedRenderers;\n        private Material _currentOverrideMaterial;\n        private bool _currentOverrideReplacesAllMaterialSlots;\n        private bool _hasMaterialOverride;\n\n        public Vector3 Velocity\n        {\n            get => _velocity;\n            set => _velocity = value;\n        }\n\n        public void SetUpdateSimulationEnabled(bool isEnabled)\n        {\n            _simulateInUpdate = isEnabled;\n        }\n\n        public void SetExternalReleaseEnabled(bool isEnabled)\n        {\n            _useExternalRelease = isEnabled;\n        }\n\n        public bool TryRequestExternalSplit(RaycastHit hitInfo)\n        {\n            if (SplitRequested == null)\n            {\n                return false;\n            }\n\n            return SplitRequested.Invoke(this, hitInfo);\n        }\n\n        // 내부적으로 행동 인스턴스와 우선순위(Priority)를 함께 묶어서 관리하기 위한 구조체\n        private struct BehaviorEntry<T>\n        {\n            public T Behavior;\n            public int Priority;\n\n            public BehaviorEntry(T behavior, int priority)\n            {\n                Behavior = behavior;\n                Priority = priority;\n            }\n        }\n\n        // 우선순위 정렬이 적용될 내부 리스트\n        private readonly List<BehaviorEntry<IMovementBehavior>> _movementBehaviors = new List<BehaviorEntry<IMovementBehavior>>();\n        private readonly List<BehaviorEntry<ICollisionBehavior>> _collisionBehaviors = new List<BehaviorEntry<ICollisionBehavior>>();\n        private readonly List<BehaviorEntry<IHitBehavior>> _hitBehaviors = new List<BehaviorEntry<IHitBehavior>>();\n\n        // 런타임에 리스트 요소가 조작되어도 에러가 나지 않도록 방어하는 실행용 버퍼 캐시\n        private readonly List<ICollisionBehavior> _collisionBuffer = new List<ICollisionBehavior>();\n        private readonly List<IHitBehavior> _hitBuffer = new List<IHitBehavior>();\n\n        private void Start()\n        {\n            if (_velocity == Vector3.zero)\n            {\n                _velocity = transform.forward * BaseSpeed;\n            }\n        }\n\n        private void Update()\n        {\n            if (!_simulateInUpdate)\n            {\n                return;\n            }\n\n            Simulate(Time.deltaTime);\n        }\n\n        public void Simulate(float deltaTime)\n        {\n            if (_isReleased)\n            {\n                return;\n            }\n\n            Vector3 currentVelocity = Velocity;\n\n            // 1. 주입된 이동 특성들을 우선순위대로 순차 중첩 계산\n            for (int i = 0; i < _movementBehaviors.Count; i++)\n            {\n                _movementBehaviors[i].Behavior.UpdateMovement(transform, ref currentVelocity, deltaTime);\n            }\n            Velocity = currentVelocity;\n\n            // 2. 물리 충돌 및 피격 예측 감지 (Raycast)\n            Vector3 moveDelta = Velocity * deltaTime;\n            float moveDistance = moveDelta.magnitude;\n            Vector3 moveDirection = moveDelta.normalized;\n\n            if (moveDistance > 0f)\n            {\n                // [수정 핵심]: 환경과 적 레이어를 통합하여 한 번에 스캔한다.\n                LayerMask combinedMask = _environmentLayer | _targetLayer;\n                RaycastHit[] hits = Physics.SphereCastAll(\n                    transform.position,\n                    _projectileRadius,\n                    moveDirection,\n                    moveDistance,\n                    combinedMask,\n                    QueryTriggerInteraction.Collide);\n\n                if (hits.Length == 0 && !_loggedNoCastHit)\n                {\n                    _loggedNoCastHit = true;\n                    Debug.Log(\n                        $\"[ProjectileBase] No sphere cast hit. Projectile: {name}, Origin: {transform.position}, Direction: {moveDirection}, Distance: {moveDistance}, Radius: {_projectileRadius}, EnvMask: {_environmentLayer.value}, TargetMask: {_targetLayer.value}, CombinedMask: {combinedMask.value}\");\n                }\n\n                // 스캔된 모든 오브젝트를 '거리가 가까운 순서(distance)'대로 오름차순 정렬한다.\n                System.Array.Sort(hits, (a, b) => a.distance.CompareTo(b.distance));\n\n                for (int i = 0; i < hits.Length; i++)\n                {\n                    RaycastHit currentHit = hits[i];\n                    int hitLayer = currentHit.collider.gameObject.layer;\n                    int hitLayerMask = 1 << hitLayer;\n\n                    // 1) 맞은 것이 벽(Environment)인 경우\n                    if ((_environmentLayer.value & hitLayerMask) != 0)\n                    {\n                        Debug.Log(\n                            $\"[ProjectileBase] Sphere cast environment hit. Projectile: {name}, Hit: {currentHit.collider.name}, Layer: {LayerMask.LayerToName(hitLayer)}({hitLayer}), Distance: {currentHit.distance}, Point: {currentHit.point}\");\n                        ExecuteCollision(currentHit);\n                        return; // 벽에 막혔으므로 이후 궤적 무시 및 이동 즉시 중단\n                    }\n                    // 2) 맞은 것이 적(Target)인 경우\n                    else if ((_targetLayer.value & hitLayerMask) != 0)\n                    {\n                        // 피격 판정 실행. ExecuteHit가 true를 반환하면 투사체가 소멸/정지해야 함을 의미.\n                        // (만약 관통 특성이 있어서 false를 반환하면 return하지 않고 다음 충돌체를 마저 탐색한다)\n                        Debug.Log(\n                            $\"[ProjectileBase] Sphere cast target hit candidate. Projectile: {name}, Hit: {currentHit.collider.name}, Layer: {LayerMask.LayerToName(hitLayer)}({hitLayer}), Distance: {currentHit.distance}, Point: {currentHit.point}\");\n                        if (ExecuteHit(currentHit.collider))\n                        {\n                            return;\n                        }\n                    }\n                }\n            }\n\n            // 3. 충돌이 없었다면 최종 연산된 물리량만큼 위치 이동 및 회전 정렬\n            transform.position += moveDelta;\n            if (Velocity != Vector3.zero)\n            {\n                transform.rotation = Quaternion.LookRotation(Velocity);\n            }\n        }\n\n        #region 동적 주입 및 자동 정렬 시스템\n\n        public void AddMovementBehavior(IMovementBehavior behavior, int priority)\n        {\n            if (behavior == null) return;\n            _movementBehaviors.Add(new BehaviorEntry<IMovementBehavior>(behavior, priority));\n            _movementBehaviors.Sort((x, y) => x.Priority.CompareTo(y.Priority)); // 오름차순 정렬\n        }\n\n        public void AddCollisionBehavior(ICollisionBehavior behavior, int priority)\n        {\n            if (behavior == null) return;\n            _collisionBehaviors.Add(new BehaviorEntry<ICollisionBehavior>(behavior, priority));\n            _collisionBehaviors.Sort((x, y) => x.Priority.CompareTo(y.Priority));\n            Debug.Log($\"[ProjectileBase] Added collision behavior: {behavior.GetType().Name}, Priority: {priority}, Count: {_collisionBehaviors.Count}\");\n        }\n\n        public void AddHitBehavior(IHitBehavior behavior, int priority)\n        {\n            if (behavior == null) return;\n            _hitBehaviors.Add(new BehaviorEntry<IHitBehavior>(behavior, priority));\n            _hitBehaviors.Sort((x, y) => x.Priority.CompareTo(y.Priority));\n        }\n\n        public T FindHitBehavior<T>() where T : class, IHitBehavior\n        {\n            for (int i = 0; i < _hitBehaviors.Count; i++)\n            {\n                if (_hitBehaviors[i].Behavior is T match)\n                    return match;\n            }\n            return null;\n        }\n        #endregion\n\n        #region 안전한 이벤트 실행 구조 (Buffer 순회)\n\n        public void ExecuteCollision(RaycastHit hitInfo)\n        {\n            bool hasCollisionBehavior = _collisionBehaviors.Count > 0;\n            Debug.Log($\"[ProjectileBase] ExecuteCollision. Hit: {hitInfo.collider.name}, CollisionBehaviors: {_collisionBehaviors.Count}, Velocity: {Velocity}\");\n\n            _collisionBuffer.Clear();\n            for (int i = 0; i < _collisionBehaviors.Count; i++)\n            {\n                _collisionBuffer.Add(_collisionBehaviors[i].Behavior);\n            }\n\n            // 버퍼 복사본을 돌기 때문에 이 도중에 부모가 파괴되거나 자식이 생성되어도 안전함\n            for (int i = 0; i < _collisionBuffer.Count; i++)\n            {\n                _collisionBuffer[i].OnCollide(this, hitInfo);\n\n                if (_isReleased)\n                {\n                    break;\n                }\n            }\n\n            CollisionExecuted?.Invoke(this, hitInfo);\n\n            if (!hasCollisionBehavior && !_isReleased)\n            {\n                ReleaseOrDestroy();\n            }\n        }\n\n        public bool ExecuteHit(Collider targetInfo)\n        {\n            if (targetInfo != null)\n            {\n                PvpWeaponHitTarget hitTarget = targetInfo.GetComponentInParent<PvpWeaponHitTarget>();\n                NetworkProjectileIdentity projectileIdentity = GetComponent<NetworkProjectileIdentity>();\n                Debug.Log(\n                    $\"[ProjectileBase] ExecuteHit candidate. Projectile: {name}, TargetCollider: {targetInfo.name}, Layer: {LayerMask.LayerToName(targetInfo.gameObject.layer)}({targetInfo.gameObject.layer}), HasPvpHitTarget: {hitTarget != null}, ProjectileOwner: {projectileIdentity?.Owner}, ProjectileSide: {projectileIdentity?.OwnerSide}\");\n\n                if (hitTarget != null && !hitTarget.CanBeHitBy(projectileIdentity))\n                {\n                    Debug.Log(\n                        $\"[ProjectileBase] ExecuteHit rejected by PvpWeaponHitTarget.CanBeHitBy. Projectile: {name}, TargetCollider: {targetInfo.name}\");\n                    return false;\n                }\n\n                int targetId = targetInfo.GetInstanceID();\n                if (!_hitTargetIds.Add(targetId))\n                {\n                    Debug.Log(\n                        $\"[ProjectileBase] ExecuteHit ignored duplicate target collider. Projectile: {name}, TargetCollider: {targetInfo.name}\");\n                    return false;\n                }\n\n                if (hitTarget != null)\n                {\n                    hitTarget.NotifyHit(projectileIdentity, this, targetInfo);\n                }\n            }\n\n            bool canSurviveHit = HasHitSurvivalBehavior();\n            _hitBuffer.Clear();\n            for (int i = 0; i < _hitBehaviors.Count; i++)\n            {\n                _hitBuffer.Add(_hitBehaviors[i].Behavior);\n            }\n\n            for (int i = 0; i < _hitBuffer.Count; i++)\n            {\n                _hitBuffer[i].OnHit(this, targetInfo);\n            }\n\n            HitExecuted?.Invoke(this, targetInfo);\n\n            if (!canSurviveHit && !_isReleased)\n            {\n                ReleaseOrDestroy();\n            }\n\n            return true;\n        }\n\n        private bool HasHitSurvivalBehavior()\n        {\n            for (int i = 0; i < _hitBehaviors.Count; i++)\n            {\n                if (_hitBehaviors[i].Behavior is IProjectileHitSurvivalBehavior)\n                {\n                    return true;\n                }\n            }\n\n            return false;\n        }\n\n        #endregion\n\n        #region 특성 복사 및 상속 헬퍼\n        // 자신이 가진 모든 특성과 우선순위 데이터를 새로운 자식 투사체에게 그대로 이식한다.\n        public void CopyBehaviorsTo(ProjectileBase targetProjectile, params System.Type[] excludedCollisionBehaviorTypes)\n        {\n            if (targetProjectile == null) return;\n\n            for (int i = 0; i < _movementBehaviors.Count; i++)\n                targetProjectile.AddMovementBehavior(_movementBehaviors[i].Behavior, _movementBehaviors[i].Priority);\n\n            for (int i = 0; i < _collisionBehaviors.Count; i++)\n            {\n                ICollisionBehavior behavior = _collisionBehaviors[i].Behavior;\n                if (ShouldExcludeCollisionBehavior(behavior, excludedCollisionBehaviorTypes))\n                {\n                    continue;\n                }\n\n                if (behavior is ICopyableCollisionBehavior copyableBehavior)\n                {\n                    behavior = copyableBehavior.CreateCopy();\n                }\n\n                targetProjectile.AddCollisionBehavior(behavior, _collisionBehaviors[i].Priority);\n            }\n\n            for (int i = 0; i < _hitBehaviors.Count; i++)\n            {\n                IHitBehavior behavior = _hitBehaviors[i].Behavior;\n                if (behavior is ICopyableHitBehavior copyableBehavior)\n                {\n                    behavior = copyableBehavior.CreateCopy();\n                }\n\n                targetProjectile.AddHitBehavior(behavior, _hitBehaviors[i].Priority);\n            }\n\n            if (_currentOverrideMaterial != null)\n            {\n                targetProjectile.ApplyMaterialOverride(\n                    _currentOverrideMaterial,\n                    _currentOverrideReplacesAllMaterialSlots\n                );\n            }\n        }\n\n        private static bool ShouldExcludeCollisionBehavior(ICollisionBehavior behavior, System.Type[] excludedTypes)\n        {\n            if (behavior == null || excludedTypes == null)\n            {\n                return false;\n            }\n\n            System.Type behaviorType = behavior.GetType();\n            for (int i = 0; i < excludedTypes.Length; i++)\n            {\n                System.Type excludedType = excludedTypes[i];\n                if (excludedType != null && excludedType.IsAssignableFrom(behaviorType))\n                {\n                    return true;\n                }\n            }\n\n            return false;\n        }\n\n        #endregion\n\n        #region Object Pool Integration\n\n        private Shield_Shot.GameplayCore.Weapon.Projectile.ProjectileObjectPool _associatedPool;\n\n        // 생성 시 오브젝트 풀러가 이 투사체의 고향 풀을 등록해 준다.\n        public void SetPool(Shield_Shot.GameplayCore.Weapon.Projectile.ProjectileObjectPool pool)\n        {\n            _associatedPool = pool;\n        }\n\n        // 재사용(Get)될 때 호출되어 이전 발사 때 쌓였던 모든 주입 특성과 내부 상태를 초기화한다.\n        public void ResetProjectileState()\n        {\n            RestoreMaterialOverride();\n\n            // 1. 주입된 모든 행동 컴포넌트 리스트 청소\n            _movementBehaviors.Clear();\n            _collisionBehaviors.Clear();\n            _hitBehaviors.Clear();\n\n            _collisionBuffer.Clear();\n            _hitBuffer.Clear();\n\n            // 2. 물리 및 생명주기 데이터 초기화\n            _hitTargetIds.Clear();\n            _isReleased = false;\n            _loggedNoCastHit = false;\n            Velocity = Vector3.zero;\n\n            // 3. 다음 발사를 위한 실시간 데이터 초기화\n            Launcher = null;\n            ChargeRatio = 0f;\n            transform.localScale = Vector3.one;\n        }\n\n        // 이제 시스템 내부에서 Destroy(gameObject)를 하던 모든 부분을 이 메서드로 대체한다.\n        public void ApplyMaterialOverride(Material material, bool replaceAllMaterialSlots = true)\n        {\n            RestoreMaterialOverride();\n\n            if (material == null)\n            {\n                return;\n            }\n\n            Renderer[] renderers = GetProjectileRenderers();\n            for (int i = 0; i < renderers.Length; i++)\n            {\n                Renderer targetRenderer = renderers[i];\n                if (targetRenderer == null)\n                {\n                    continue;\n                }\n\n                Material[] originalMaterials = targetRenderer.sharedMaterials;\n                if (originalMaterials == null || originalMaterials.Length == 0)\n                {\n                    continue;\n                }\n\n                _originalMaterialsByRenderer[targetRenderer] = originalMaterials;\n\n                Material[] overrideMaterials = new Material[originalMaterials.Length];\n                for (int materialIndex = 0; materialIndex < overrideMaterials.Length; materialIndex++)\n                {\n                    overrideMaterials[materialIndex] = replaceAllMaterialSlots\n                        ? material\n                        : originalMaterials[materialIndex];\n                }\n\n                if (!replaceAllMaterialSlots)\n                {\n                    overrideMaterials[0] = material;\n                }\n\n                targetRenderer.sharedMaterials = overrideMaterials;\n            }\n\n            _hasMaterialOverride = _originalMaterialsByRenderer.Count > 0;\n            _currentOverrideMaterial = _hasMaterialOverride ? material : null;\n            _currentOverrideReplacesAllMaterialSlots = replaceAllMaterialSlots;\n        }\n\n        public void RestoreMaterialOverride()\n        {\n            if (!_hasMaterialOverride)\n            {\n                return;\n            }\n\n            foreach (var pair in _originalMaterialsByRenderer)\n            {\n                Renderer targetRenderer = pair.Key;\n                if (targetRenderer != null)\n                {\n                    targetRenderer.sharedMaterials = pair.Value;\n                }\n            }\n\n            _originalMaterialsByRenderer.Clear();\n            _currentOverrideMaterial = null;\n            _hasMaterialOverride = false;\n        }\n\n        private Renderer[] GetProjectileRenderers()\n        {\n            if (_cachedRenderers == null || _cachedRenderers.Length == 0)\n            {\n                _cachedRenderers = GetComponentsInChildren<Renderer>(true);\n            }\n\n            return _cachedRenderers;\n        }\n\n        public void ReleaseOrDestroy()\n        {\n            if (_isReleased)\n            {\n                return;\n            }\n\n            _isReleased = true;\n            RestoreMaterialOverride();\n\n            if (_useExternalRelease)\n            {\n                ReleaseRequested?.Invoke(this);\n                return;\n            }\n\n            if (_associatedPool != null)\n            {\n                _associatedPool.Return(this); // 풀이 있으면 풀로 안전하게 반납\n            }\n            else\n            {\n                Destroy(gameObject); // 풀 없이 단독 생성된 경우 물리적 파괴\n            }\n        }\n\n        #endregion\n    }\n}\n", "GameplayCore/Weapon/Projectile/ProjectileBehaviorSO.cs": "using UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Weapon.Projectile\n{\n    public abstract class ProjectileBehaviorSO : ScriptableObject\n    {\n        [Header(\"Behavior Base Info\")]\n        public string BehaviorID;\n        public string BehaviorName;\n        public Sprite Icon;\n\n        [Header(\"Network\")]\n        [SerializeField] private int networkCode;\n\n        public int NetworkCode => networkCode;\n\n        [TextArea(2, 5)]\n        public string Description;\n\n        [SerializeField, Min(1)] private int maxLevel = 1;\n\n        [Tooltip(\"Lower values run earlier. Example: Split=10, Reflect=50\")]\n        public int Priority = 100;\n\n        public int MaxLevel => Mathf.Max(1, maxLevel);\n\n\n        public virtual bool CanInject(ProjectileBase projectile)\n        {\n            return projectile != null;\n        }\n\n        public abstract void InjectBehavior(ProjectileBase projectile, int currentLevel);\n\n        public virtual string GetDynamicDescription(int currentLevel)\n        {\n            int nextLevel = Mathf.Clamp(currentLevel + 1, 1, MaxLevel);\n\n            if (string.IsNullOrWhiteSpace(Description))\n            {\n                return $\"Lv. {nextLevel}/{MaxLevel}\";\n            }\n\n            try\n            {\n                return string.Format(Description, currentLevel, nextLevel, MaxLevel);\n            }\n            catch (System.FormatException)\n            {\n                return Description;\n            }\n        }\n    }\n}\n", "GameplayCore/Weapon/Projectile/ProjectileShooter.cs": "using Shield_Shot.GameplayCore.Render;\nusing Shield_Shot.GameplayCore.Weapon.Aim;\nusing UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Weapon.Projectile\n{\n    public class ProjectileShooter : MonoBehaviour, IProjectileFireHandler, IProjectileAimPredictionProvider\n    {\n        [Header(\"References\")]\n        [SerializeField] private Transform _firePoint;\n        [SerializeField] private InputSystem.Data.WeaponType _defaultWeaponType;\n        [SerializeField] private bool _allowLocalFire = true;\n\n        [Header(\"Full Charge Bonus\")]\n        [Tooltip(\"풀차징(차징 99% 이상) 발사 시 추가 관통 횟수 (0이면 비활성)\")]\n        [SerializeField] private int _fullChargePierceBonus = 1;\n\n        [Tooltip(\"풀차징 판정 기준 (0~1)\")]\n        [SerializeField, Range(0.9f, 1f)] private float _fullChargeThreshold = 0.99f;\n\n        [Header(\"Sniper Settings\")]\n        [Tooltip(\"스나이퍼가 기본으로 보유하는 관통 횟수 (항상 적용, 차징 조건 없음)\")]\n        [SerializeField, Min(0)] private int _sniperBasePierceCount = 1;\n\n        private PlayerStatus _playerStatus;\n        private StatCalculator _statCalculator;\n\n        public StatCalculator StatCalculator => _statCalculator;\n\n        public void Fire(Transform firePoint, Vector3 aimDirection, float chargeRatio, bool isCritical)\n        {\n            Fire(firePoint, aimDirection, chargeRatio, isCritical, _defaultWeaponType);\n        }\n\n        public void Fire(Transform firePoint, Vector3 aimDirection, float chargeRatio, bool isCritical, InputSystem.Data.WeaponType weaponType)\n        {\n            if (!_allowLocalFire)\n            {\n                Debug.Log(\"[ProjectileShooter] Local fire is disabled.\");\n                return;\n            }\n\n            Transform origin = firePoint != null ? firePoint : _firePoint;\n\n            if (_playerStatus == null)\n            {\n                if (!LocalPlayerStatusContext.TryGet(out _playerStatus))\n                    _playerStatus = GetComponentInParent<PlayerStatus>();\n            }\n\n            if (_statCalculator == null) _statCalculator = GetComponent<StatCalculator>();\n\n            if (origin == null || _playerStatus == null || _statCalculator == null)\n            {\n                Debug.LogWarning($\"[ProjectileShooter] 필수 참조가 누락됨. Origin: {origin != null}, Status: {_playerStatus != null}, Calc: {_statCalculator != null}\");\n                return;\n            }\n\n            Vector3 worldDirection = AimDirectionUtility.ToWorldXZ(aimDirection);\n            if (worldDirection == Vector3.zero)\n            {\n                worldDirection = origin.forward;\n                worldDirection.y = 0f;\n                worldDirection = worldDirection.sqrMagnitude > 0.0001f ? worldDirection.normalized : Vector3.forward;\n            }\n\n            Quaternion launchRotation = Quaternion.LookRotation(worldDirection, Vector3.up);\n\n            ProjectileBase projectile = SpawnProjectile(weaponType, origin.position, launchRotation);\n            if (projectile == null)\n            {\n                Debug.LogWarning(\"[ProjectileShooter] Spawned object does not have a Projectile component.\");\n                return;\n            }\n\n            projectile.IsCritical = isCritical;\n            projectile.Launcher = this;\n            projectile.SourceWeaponType = weaponType;\n            projectile.ChargeRatio = chargeRatio;\n            projectile.SetUpdateSimulationEnabled(true);\n\n            ProjectileStats finalStats = _statCalculator.Calculate(chargeRatio, isCritical);\n            projectile.ProjectileDamage = finalStats.Damage;\n            projectile.BaseSpeed = finalStats.Speed;\n            projectile.Velocity = worldDirection * finalStats.Speed;\n\n            for (int i = 0; i < _playerStatus.CurrentBehaviors.Count; i++)\n            {\n                ActiveBehavior activeBehavior = _playerStatus.CurrentBehaviors[i];\n                if (activeBehavior.BehaviorSO == null) continue;\n                activeBehavior.BehaviorSO.InjectBehavior(projectile, activeBehavior.Level);\n            }\n\n            _playerStatus.TryInjectAndConsumeNextShotBehavior(projectile);\n\n            // 풀차징 보너스: 활(Bow) 전용 - 관통 횟수 추가\n            if (weaponType == InputSystem.Data.WeaponType.Bow &&\n    _fullChargePierceBonus > 0 &&\n    chargeRatio >= _fullChargeThreshold)\n            {\n                PierceHitBehavior existingPierce = projectile.FindHitBehavior<PierceHitBehavior>();\n\n                if (existingPierce != null)\n                {\n                    existingPierce.PierceCount += _fullChargePierceBonus;\n                    Debug.Log($\"[ProjectileShooter] 활 풀차징! 기존 관통에 +{_fullChargePierceBonus} 합산. 최종 관통: {existingPierce.PierceCount}\");\n                }\n                else\n                {\n                    projectile.AddHitBehavior(new PierceHitBehavior(_fullChargePierceBonus), 90);   // ← -1 제거됨\n                    Debug.Log($\"[ProjectileShooter] 활 풀차징! 관통 보너스 +{_fullChargePierceBonus} 신규 적용.\");\n                }\n            }\n\n            // 스나이퍼 기본 관통 - 차징/조건 없이 항상 적용\n            if (weaponType == InputSystem.Data.WeaponType.Sniper && _sniperBasePierceCount > 0)\n            {\n                PierceHitBehavior existingPierce = projectile.FindHitBehavior<PierceHitBehavior>();\n\n                if (existingPierce != null)\n                {\n                    existingPierce.PierceCount += _sniperBasePierceCount;\n                    Debug.Log($\"[ProjectileShooter] 스나이퍼 기존 관통에 +{_sniperBasePierceCount} 합산. 최종 관통: {existingPierce.PierceCount}\");\n                }\n                else\n                {\n                    projectile.AddHitBehavior(new PierceHitBehavior(_sniperBasePierceCount), 90);\n                    Debug.Log($\"[ProjectileShooter] 스나이퍼 기본 관통 +{_sniperBasePierceCount} 적용.\");\n                }\n            }\n\n            Debug.Log($\"[ProjectileShooter] Fired projectile. Speed: {finalStats.Speed}, Damage: {finalStats.Damage}\");\n        }\n\n        private ProjectileBase SpawnProjectile(InputSystem.Data.WeaponType weaponType, Vector3 position, Quaternion rotation)\n        {\n            if (ProjectileManager.Instance != null)\n                return ProjectileManager.Instance.GetProjectile(weaponType, position, rotation);\n\n            Debug.LogError(\"[ProjectileShooter] ProjectileManager Instance가 씬에 존재하지 않는다!\");\n            return null;\n        }\n\n        public Vector3 GetPredictedProjectileOrigin(Vector3 firePointPosition, Vector3 worldDirection)\n        {\n            return firePointPosition;\n        }\n\n        public bool TryGetProjectileCollisionRadius(InputSystem.Data.WeaponType weaponType, out float radius)\n        {\n            radius = 0f;\n\n            return ProjectileManager.Instance != null &&\n                   ProjectileManager.Instance.TryGetProjectileCollisionRadius(weaponType, out radius) &&\n                   radius > 0f;\n        }\n    }\n}\n", "Network/PvP/NetworkProjectileActor.cs": "using Fusion;\nusing Shield_Shot.GameplayCore.Field;\nusing Shield_Shot.GameplayCore.Render;\nusing Shield_Shot.GameplayCore.Weapon.Projectile;\nusing UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Network.Pvp\n{\n    [RequireComponent(typeof(NetworkObject))]\n    [RequireComponent(typeof(ProjectileBase))]\n    public sealed class NetworkProjectileActor : NetworkBehaviour\n    {\n        [Header(\"Split\")]\n        [SerializeField] private NetworkObject _projectilePrefab;\n\n        [Header(\"Projectile Visual\")]\n        [SerializeField] private Material _iceProjectileMaterial;\n        [SerializeField] private bool _replaceAllProjectileMaterialSlots = true;\n\n        [Networked] private int NetworkedVisualElement { get; set; }\n\n        private const VFXType CollisionVfxType = VFXType.Reflect;\n        private const float CollisionVfxDuration = 0.5f;\n        private const VFXType HitVfxType = VFXType.Hit;\n        private const float HitVfxDuration = 1.5f;\n\n        private ProjectileBase _projectile;\n        private bool _despawnRequested;\n        private bool _isBound;\n        private int _appliedVisualElement = -1;\n\n        private void Awake()\n        {\n            _projectile = GetComponent<ProjectileBase>();\n        }\n\n        public override void Spawned()\n        {\n            if (_projectile == null)\n            {\n                _projectile = GetComponent<ProjectileBase>();\n            }\n\n            BindProjectileLifecycle();\n            ApplyNetworkedVisualElement();\n        }\n\n        public override void Render()\n        {\n            ApplyNetworkedVisualElement();\n        }\n\n        public override void FixedUpdateNetwork()\n        {\n            if (!Object.HasStateAuthority || _projectile == null || _despawnRequested)\n            {\n                return;\n            }\n\n            _projectile.Simulate(Runner.DeltaTime);\n        }\n\n        public override void Despawned(NetworkRunner runner, bool hasState)\n        {\n            if (_projectile == null)\n            {\n                return;\n            }\n\n            _projectile.ReleaseRequested -= OnProjectileReleaseRequested;\n            _projectile.CollisionExecuted -= OnProjectileCollisionExecuted;\n            _projectile.HitExecuted -= OnProjectileHitExecuted;\n            _projectile.SplitRequested -= OnProjectileSplitRequested;\n            _isBound = false;\n            _projectile.SetExternalReleaseEnabled(false);\n            _projectile.SetUpdateSimulationEnabled(true);\n            _projectile.RestoreMaterialOverride();\n            _appliedVisualElement = -1;\n        }\n\n        public void SetElementVisual(ElementType element)\n        {\n            int elementValue = (int)element;\n\n            if (Object != null && Object.HasStateAuthority)\n            {\n                NetworkedVisualElement = elementValue;\n            }\n\n            ApplyVisualElement(elementValue);\n        }\n\n        public void BindProjectileLifecycle()\n        {\n            if (_isBound)\n            {\n                return;\n            }\n\n            if (_projectile == null)\n            {\n                _projectile = GetComponent<ProjectileBase>();\n            }\n\n            if (_projectile == null)\n            {\n                return;\n            }\n\n            _projectile.SetUpdateSimulationEnabled(false);\n            _projectile.SetExternalReleaseEnabled(true);\n            _projectile.ReleaseRequested += OnProjectileReleaseRequested;\n            _projectile.CollisionExecuted += OnProjectileCollisionExecuted;\n            _projectile.HitExecuted += OnProjectileHitExecuted;\n            _projectile.SplitRequested += OnProjectileSplitRequested;\n            _isBound = true;\n        }\n\n        private void OnProjectileCollisionExecuted(ProjectileBase projectile, RaycastHit hitInfo)\n        {\n            if (!Object.HasStateAuthority)\n            {\n                return;\n            }\n\n            RPC_PlayCollisionVfx(hitInfo.point, hitInfo.normal);\n        }\n\n        private void OnProjectileHitExecuted(ProjectileBase projectile, Collider targetInfo)\n        {\n            if (!Object.HasStateAuthority || projectile == null)\n            {\n                return;\n            }\n\n            Vector3 position = projectile.transform.position;\n            if (targetInfo != null)\n            {\n                position = targetInfo.ClosestPoint(projectile.transform.position);\n            }\n\n            RPC_PlayHitVfx(position, projectile.transform.rotation);\n        }\n\n        [Rpc(RpcSources.StateAuthority, RpcTargets.All)]\n        private void RPC_PlayCollisionVfx(Vector3 position, Vector3 normal)\n        {\n            VFXPoolManager vfxPoolManager = VFXPoolManager.EnsureInstance();\n            if (CollisionVfxType == VFXType.None || vfxPoolManager == null)\n            {\n                return;\n            }\n\n            Quaternion rotation = normal.sqrMagnitude > 0.0001f\n                ? Quaternion.LookRotation(normal)\n                : Quaternion.identity;\n\n            vfxPoolManager.SpawnVFX(CollisionVfxType, position, rotation, CollisionVfxDuration);\n        }\n\n        [Rpc(RpcSources.StateAuthority, RpcTargets.All)]\n        private void RPC_PlayHitVfx(Vector3 position, Quaternion rotation)\n        {\n            VFXPoolManager vfxPoolManager = VFXPoolManager.EnsureInstance();\n            if (HitVfxType == VFXType.None || vfxPoolManager == null)\n            {\n                return;\n            }\n\n            vfxPoolManager.SpawnVFX(HitVfxType, position, rotation, HitVfxDuration);\n        }\n\n        private void OnProjectileReleaseRequested(ProjectileBase projectile)\n        {\n            if (!Object.HasStateAuthority || _despawnRequested)\n            {\n                return;\n            }\n\n            _despawnRequested = true;\n            Runner.Despawn(Object);\n        }\n\n        private bool OnProjectileSplitRequested(ProjectileBase projectile, RaycastHit hitInfo)\n        {\n            if (!Object.HasStateAuthority || _despawnRequested || projectile == null)\n            {\n                return false;\n            }\n\n            NetworkObject prefab = _projectilePrefab != null ? _projectilePrefab : Object;\n            Vector3 baseDirection = projectile.Velocity.sqrMagnitude > 0.0001f\n                ? projectile.Velocity.normalized\n                : projectile.transform.forward;\n            float speed = projectile.Velocity.magnitude > 0.0001f\n                ? projectile.Velocity.magnitude\n                : projectile.BaseSpeed;\n            Vector3 spawnPosition = SplitCollisionBehavior.GetChildSpawnPosition(hitInfo, projectile.ProjectileRadius);\n\n            for (int i = 0; i < SplitCollisionBehavior.ChildCount; i++)\n            {\n                Vector3 childIncomingDirection = SplitCollisionBehavior.GetChildIncomingDirection(baseDirection, i);\n                Quaternion rotation = Quaternion.LookRotation(childIncomingDirection, Vector3.up);\n\n                Runner.Spawn(\n                    prefab,\n                    spawnPosition,\n                    rotation,\n                    Object.InputAuthority,\n                    (_, spawnedObject) =>\n                    {\n                        if (!spawnedObject.TryGetComponent(out ProjectileBase childProjectile))\n                        {\n                            return;\n                        }\n\n                        childProjectile.ResetProjectileState();\n                        childProjectile.SetUpdateSimulationEnabled(false);\n                        childProjectile.SetExternalReleaseEnabled(true);\n                        childProjectile.BaseSpeed = projectile.BaseSpeed;\n                        childProjectile.ChargeRatio = projectile.ChargeRatio;\n                        childProjectile.Velocity = childIncomingDirection * speed;\n                        projectile.CopyBehaviorsTo(childProjectile, typeof(SplitCollisionBehavior));\n\n                        if (spawnedObject.TryGetComponent(out NetworkProjectileActor childActor))\n                        {\n                            childActor.SetElementVisual((ElementType)NetworkedVisualElement);\n                            childActor.BindProjectileLifecycle();\n                        }\n\n                        if (spawnedObject.TryGetComponent(out NetworkProjectileIdentity childIdentity) &&\n                            Object.TryGetComponent(out NetworkProjectileIdentity parentIdentity))\n                        {\n                            childIdentity.Initialize(parentIdentity.Owner, parentIdentity.OwnerSide);\n                        }\n\n                        childProjectile.ExecuteCollision(hitInfo);\n                    });\n            }\n\n            return true;\n        }\n\n        private void ApplyNetworkedVisualElement()\n        {\n            ApplyVisualElement(NetworkedVisualElement);\n        }\n\n        private void ApplyVisualElement(int elementValue)\n        {\n            if (_projectile == null)\n            {\n                _projectile = GetComponent<ProjectileBase>();\n            }\n\n            if (_projectile == null || _appliedVisualElement == elementValue)\n            {\n                return;\n            }\n\n            _appliedVisualElement = elementValue;\n\n            if ((ElementType)elementValue == ElementType.Ice && _iceProjectileMaterial != null)\n            {\n                _projectile.ApplyMaterialOverride(_iceProjectileMaterial, _replaceAllProjectileMaterialSlots);\n                return;\n            }\n\n            _projectile.RestoreMaterialOverride();\n        }\n    }\n}\n", "Network/PvP/NetworkProjectileFireHandler.cs": "using Fusion;\nusing Shield_Shot.GameplayCore.Field;\nusing Shield_Shot.GameplayCore.Network.Match;\nusing Shield_Shot.GameplayCore.Render;\nusing Shield_Shot.GameplayCore.Weapon.Projectile;\nusing Shield_Shot.InputSystem.Data;\nusing UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Network.Pvp\n{\n    [RequireComponent(typeof(NetworkObject))]\n    [RequireComponent(typeof(PlayerStatus))]\n    [RequireComponent(typeof(StatCalculator))]\n    public sealed class NetworkProjectileFireHandler : NetworkBehaviour, IProjectileFireHandler, IProjectileAimPredictionProvider\n    {\n        [Header(\"Projectile\")]\n        [SerializeField] private NetworkObject _projectilePrefab;\n        [SerializeField] private float _spawnForwardOffset = 0.35f;\n\n        private PlayerStatus _playerStatus;\n        private StatCalculator _statCalculator;\n        private PvpWeaponActorIdentity _weaponIdentity;\n        private PvpProjectileAugmentSnapshotProvider _augmentSnapshotProvider;\n        private ProjectileBehaviorRegistry _behaviorRegistry;\n        private PvpMatchStateController _matchStateController;\n\n        private void Awake()\n        {\n            _playerStatus = GetComponent<PlayerStatus>();\n            _statCalculator = GetComponent<StatCalculator>();\n            _weaponIdentity = GetComponent<PvpWeaponActorIdentity>();\n            _augmentSnapshotProvider = GetComponent<PvpProjectileAugmentSnapshotProvider>();\n        }\n\n        public void Fire(Transform firePoint, Vector3 aimDirection, float chargeRatio, bool isCritical)\n        {\n            if (Object == null || !Object.HasInputAuthority)\n            {\n                return;\n            }\n\n            if (!CanFireInCurrentMatchState())\n            {\n                Debug.Log(\"[NetworkProjectileFireHandler] Fire blocked by match state.\");\n                return;\n            }\n\n            if (firePoint == null)\n            {\n                Debug.LogWarning(\"[NetworkProjectileFireHandler] FirePoint is missing.\");\n                return;\n            }\n\n            Vector3 worldDirection = ToWorldXZ(aimDirection);\n            if (worldDirection.sqrMagnitude <= 0.0001f)\n            {\n                worldDirection = firePoint.forward;\n                worldDirection.y = 0f;\n                worldDirection = worldDirection.sqrMagnitude > 0.0001f\n                    ? worldDirection.normalized\n                    : Vector3.forward;\n            }\n\n            PvpProjectileAugmentPayload payload = CreateAugmentPayload();\n\n            Debug.Log(payload.HasAnyAugment\n                ? \"[NetworkProjectileFireHandler] Fire with augment payload.\"\n                : \"[NetworkProjectileFireHandler] Fire with empty augment payload.\");\n\n            isCritical = (chargeRatio >= 0.99f);\n\n            if (Object.HasStateAuthority)\n            {\n                SpawnProjectile(GetSpawnPosition(firePoint.position, worldDirection), worldDirection, chargeRatio, isCritical, payload);\n                return;\n            }\n\n\n            RPC_RequestFire(GetSpawnPosition(firePoint.position, worldDirection), worldDirection, chargeRatio, isCritical, payload);\n        }\n\n        [Rpc(RpcSources.InputAuthority, RpcTargets.StateAuthority)]\n        private void RPC_RequestFire(\n    Vector3 position,\n    Vector3 worldDirection,\n    float chargeRatio,\n    bool isCritical,\n    PvpProjectileAugmentPayload payload)\n        {\n            if (!CanFireInCurrentMatchState())\n            {\n                Debug.Log(\"[NetworkProjectileFireHandler] RPC fire blocked by match state.\");\n                return;\n            }\n\n            SpawnProjectile(position, worldDirection, chargeRatio, isCritical, payload);\n        }\n\n        private void SpawnProjectile(\n    Vector3 position,\n    Vector3 worldDirection,\n    float chargeRatio,\n    bool isCritical,\n    PvpProjectileAugmentPayload payload)\n        {\n            if (_projectilePrefab == null)\n            {\n                Debug.LogWarning(\"[NetworkProjectileFireHandler] Projectile prefab is missing.\");\n                return;\n            }\n\n            if (_playerStatus == null || _statCalculator == null)\n            {\n                Debug.LogWarning(\"[NetworkProjectileFireHandler] Required references are missing.\");\n                return;\n            }\n\n            Quaternion rotation = Quaternion.LookRotation(worldDirection, Vector3.up);\n            ProjectileStats finalStats = _statCalculator.Calculate(chargeRatio, isCritical);\n            Debug.Log($\"[NetworkProjectileFireHandler] Spawn network projectile. Authority: {Object.InputAuthority}, Position: {position}, Direction: {worldDirection}, Speed: {finalStats.Speed}, Critical: {isCritical}\");\n            LogFireAlignmentDiagnostics(position, worldDirection);\n\n            Runner.Spawn(\n                _projectilePrefab,\n                position,\n                rotation,\n                Object.InputAuthority,\n                (_, spawnedObject) =>\n                {\n                    if (!spawnedObject.TryGetComponent(out ProjectileBase projectile))\n                    {\n                        Debug.LogWarning(\"[NetworkProjectileFireHandler] Spawned object does not have ProjectileBase.\");\n                        return;\n                    }\n                    if (spawnedObject.TryGetComponent(out NetworkProjectileIdentity projectileIdentity))\n                    {\n                        PlayerRef owner = _weaponIdentity != null ? _weaponIdentity.Owner : Object.InputAuthority;\n                        PlayerSide ownerSide = _weaponIdentity != null ? _weaponIdentity.Side : PlayerSide.Bottom;\n\n                        projectileIdentity.Initialize(owner, ownerSide);\n                    }\n                    else\n                    {\n                        Debug.LogWarning(\"[NetworkProjectileFireHandler] Spawned object does not have NetworkProjectileIdentity.\");\n                    }\n\n                    projectile.IsCritical = isCritical;\n                    projectile.ChargeRatio = chargeRatio;\n                    projectile.ProjectileDamage = finalStats.Damage;\n                    projectile.BaseSpeed = finalStats.Speed;\n                    projectile.Velocity = worldDirection * finalStats.Speed;\n\n                    ApplyProjectileBehaviors(projectile, payload);\n\n                    if (spawnedObject.TryGetComponent(out NetworkProjectileActor projectileActor))\n                    {\n                        projectileActor.SetElementVisual(ResolveProjectileVisualElement(payload));\n                    }\n                });\n        }\n\n        private Vector3 GetSpawnPosition(Vector3 firePointPosition, Vector3 worldDirection)\n        {\n            if (worldDirection.sqrMagnitude <= 0.0001f || _spawnForwardOffset <= 0f)\n            {\n                return firePointPosition;\n            }\n\n            return firePointPosition + worldDirection.normalized * _spawnForwardOffset;\n        }\n\n        private void LogFireAlignmentDiagnostics(Vector3 position, Vector3 worldDirection)\n        {\n            if (worldDirection.sqrMagnitude <= 0.0001f)\n            {\n                Debug.LogWarning(\"[NetworkProjectileFireHandler] Fire alignment skipped. World direction is zero.\");\n                return;\n            }\n\n            Vector3 normalizedDirection = worldDirection.normalized;\n            PvpWeaponActorIdentity[] actors = FindObjectsByType<PvpWeaponActorIdentity>(\n                FindObjectsInactive.Exclude,\n                FindObjectsSortMode.None);\n\n            for (int i = 0; i < actors.Length; i++)\n            {\n                PvpWeaponActorIdentity actor = actors[i];\n                if (actor == null || actor == _weaponIdentity)\n                {\n                    continue;\n                }\n\n                Vector3 toActor = actor.transform.position - position;\n                toActor.y = 0f;\n                float forwardDistance = Vector3.Dot(toActor, normalizedDirection);\n                Vector3 closestPoint = position + normalizedDirection * forwardDistance;\n                closestPoint.y = actor.transform.position.y;\n                float lateralDistance = Vector3.Distance(\n                    new Vector3(actor.transform.position.x, 0f, actor.transform.position.z),\n                    new Vector3(closestPoint.x, 0f, closestPoint.z));\n\n                Debug.Log(\n                    $\"[NetworkProjectileFireHandler] Fire alignment. Shooter: {_weaponIdentity?.Owner}/{_weaponIdentity?.Side}, Target: {actor.Owner}/{actor.Side}, FirePosition: {position}, FireDirection: {normalizedDirection}, TargetPosition: {actor.transform.position}, ForwardDistance: {forwardDistance}, LateralDistance: {lateralDistance}\");\n            }\n        }\n\n        public Vector3 GetPredictedProjectileOrigin(Vector3 firePointPosition, Vector3 worldDirection)\n        {\n            return GetSpawnPosition(firePointPosition, worldDirection);\n        }\n\n        public bool TryGetProjectileCollisionRadius(WeaponType weaponType, out float radius)\n        {\n            radius = 0f;\n            if (_projectilePrefab == null)\n            {\n                return false;\n            }\n\n            ProjectileBase projectile = _projectilePrefab.GetComponent<ProjectileBase>();\n            if (projectile == null)\n            {\n                return false;\n            }\n\n            radius = projectile.ProjectileRadius;\n            return radius > 0f;\n        }\n\n        private void ApplyProjectileBehaviors(ProjectileBase projectile, PvpProjectileAugmentPayload payload)\n        {\n            if (projectile == null || !payload.HasAnyAugment)\n            {\n                return;\n            }\n\n            int appliedCount = 0;\n            if (_behaviorRegistry == null)\n            {\n                _behaviorRegistry = FindFirstObjectByType<ProjectileBehaviorRegistry>();\n            }\n\n            payload.ForEach(entry =>\n            {\n                if (_behaviorRegistry != null &&\n                    _behaviorRegistry.TryGet(entry.BehaviorCode, out ProjectileBehaviorSO behaviorSO))\n                {\n                    behaviorSO.InjectBehavior(projectile, entry.Level);\n                    appliedCount++;\n                    Debug.Log($\"[NetworkProjectileFireHandler] Applied behavior from registry: {behaviorSO.BehaviorName}({entry.BehaviorCode}) Lv.{entry.Level}\");\n                    return;\n                }\n\n                if (ApplyEntryDirectly(projectile, entry))\n                {\n                    appliedCount++;\n                }\n            });\n\n            Debug.Log($\"[NetworkProjectileFireHandler] Applied projectile payload. Count: {appliedCount}\");\n        }\n\n        private static int ApplyPayloadDirectly(ProjectileBase projectile, PvpProjectileAugmentPayload payload)\n        {\n            int appliedCount = 0;\n\n            payload.ForEach(entry =>\n            {\n                if (ApplyEntryDirectly(projectile, entry))\n                {\n                    appliedCount++;\n                }\n            });\n\n            return appliedCount;\n        }\n\n        private static bool ApplyEntryDirectly(ProjectileBase projectile, PvpProjectileAugmentEntry entry)\n        {\n            switch (entry.BehaviorCode)\n            {\n                case PvpProjectileBehaviorCode.StandardReflect:\n                    projectile.AddCollisionBehavior(new StandardReflectCollisionBehavior(entry.Level), 40);\n                    Debug.Log($\"[NetworkProjectileFireHandler] Fallback applied StandardReflect Lv.{entry.Level}\");\n                    return true;\n\n                case PvpProjectileBehaviorCode.RandomReflect:\n                    projectile.AddCollisionBehavior(new RandomReflectCollisionBehavior(entry.Level), 50);\n                    Debug.Log($\"[NetworkProjectileFireHandler] Fallback applied RandomReflect Lv.{entry.Level}\");\n                    return true;\n\n                case PvpProjectileBehaviorCode.Split:\n                    projectile.AddCollisionBehavior(new SplitCollisionBehavior(entry.Level), 10);\n                    Debug.Log($\"[NetworkProjectileFireHandler] Fallback applied Split Lv.{entry.Level}\");\n                    return true;\n\n                case PvpProjectileBehaviorCode.Pierce:\n                    projectile.AddHitBehavior(new PierceHitBehavior(entry.Level), 90);\n                    Debug.Log($\"[NetworkProjectileFireHandler] Fallback applied Pierce Lv.{entry.Level}\");\n                    return true;\n\n                case PvpProjectileBehaviorCode.Poison:\n                    projectile.AddHitBehavior(\n                        new PoisonHitBehavior(\n                            duration: 4f,\n                            tickInterval: 0.5f,\n                            damagePerTick: projectile.ProjectileDamage * (0.8f + 0.2f * Mathf.Max(0, entry.Level - 1)) / 8f,\n                            showDamagePopup: true,\n                            tickVfxType: VFXType.Hit,\n                            vfxAutoReleaseTime: 1.5f\n                        ),\n                        100\n                    );\n                    Debug.Log($\"[NetworkProjectileFireHandler] Fallback applied Poison Lv.{entry.Level}\");\n                    return true;\n\n                case PvpProjectileBehaviorCode.ElementTrailFire:\n                    projectile.AddMovementBehavior(\n                        new FieldPaintMovementBehavior(\n                            ElementType.Fire,\n                            entry.Level,\n                            2f,\n                            0.6f + 0.1f * Mathf.Max(0, entry.Level - 1)\n                        ),\n                        100\n                    );\n                    Debug.Log($\"[NetworkProjectileFireHandler] Fallback applied ElementTrailFire Lv.{entry.Level}\");\n                    return true;\n\n                case PvpProjectileBehaviorCode.ElementTrailWind:\n                    projectile.AddMovementBehavior(\n                        new FieldPaintMovementBehavior(\n                            ElementType.Wind,\n                            entry.Level,\n                            2f + 0.2f * Mathf.Max(0, entry.Level - 1),\n                            0.6f + 0.1f * Mathf.Max(0, entry.Level - 1)\n                        ),\n                        100\n                    );\n                    WindFieldProjectileBoostBehavior windTrailBoostBehavior = new WindFieldProjectileBoostBehavior(\n                        entry.Level,\n                        baseBoostDuration: 0.6f,\n                        durationPerLevel: 0.12f,\n                        baseSpeedMultiplier: 1.25f,\n                        speedMultiplierPerLevel: 0.05f\n                    );\n                    projectile.AddMovementBehavior(windTrailBoostBehavior, 100);\n                    projectile.AddHitBehavior(\n                        new WindBoostKnockbackHitBehavior(\n                            windTrailBoostBehavior,\n                            entry.Level,\n                            baseKnockbackSpeed: 8f,\n                            knockbackSpeedPerLevel: 1.5f,\n                            knockbackDuration: 0.15f\n                        ),\n                        100\n                    );\n                    Debug.Log($\"[NetworkProjectileFireHandler] Fallback applied ElementTrailWind Lv.{entry.Level}\");\n                    return true;\n\n                case PvpProjectileBehaviorCode.ElementTrailIce:\n                    projectile.AddMovementBehavior(\n                        new FieldPaintMovementBehavior(\n                            ElementType.Ice,\n                            entry.Level,\n                            2f + 0.2f * Mathf.Max(0, entry.Level - 1),\n                            0.6f + 0.1f * Mathf.Max(0, entry.Level - 1)\n                        ),\n                        100\n                    );\n                    projectile.AddHitBehavior(\n                        new FreezeHitBehavior(1.5f + 0.2f * Mathf.Max(0, entry.Level - 1)),\n                        100\n                    );\n                    Debug.Log($\"[NetworkProjectileFireHandler] Fallback applied ElementTrailIce Lv.{entry.Level}\");\n                    return true;\n\n                case PvpProjectileBehaviorCode.FreezeHit:\n                    projectile.AddHitBehavior(\n                        new FreezeHitBehavior(1.5f + 0.2f * Mathf.Max(0, entry.Level - 1)),\n                        100\n                    );\n                    Debug.Log($\"[NetworkProjectileFireHandler] Fallback applied FreezeHit Lv.{entry.Level}\");\n                    return true;\n\n                case PvpProjectileBehaviorCode.WindFieldBoost:\n                    WindFieldProjectileBoostBehavior boostBehavior = new WindFieldProjectileBoostBehavior(\n                        entry.Level,\n                        baseBoostDuration: 0.6f,\n                        durationPerLevel: 0.12f,\n                        baseSpeedMultiplier: 1.25f,\n                        speedMultiplierPerLevel: 0.05f\n                    );\n                    projectile.AddMovementBehavior(boostBehavior, 100);\n                    projectile.AddHitBehavior(\n                        new WindBoostKnockbackHitBehavior(\n                            boostBehavior,\n                            entry.Level,\n                            baseKnockbackSpeed: 8f,\n                            knockbackSpeedPerLevel: 1.5f,\n                            knockbackDuration: 0.15f\n                        ),\n                        100\n                    );\n                    Debug.Log($\"[NetworkProjectileFireHandler] Fallback applied WindFieldBoost Lv.{entry.Level}\");\n                    return true;\n\n                default:\n                    Debug.LogWarning($\"[NetworkProjectileFireHandler] No direct fallback for behavior code: {entry.BehaviorCode}\");\n                    return false;\n            }\n        }\n\n        private static ElementType ResolveProjectileVisualElement(PvpProjectileAugmentPayload payload)\n        {\n            ElementType visualElement = ElementType.None;\n\n            payload.ForEach(entry =>\n            {\n                if (entry.BehaviorCode == PvpProjectileBehaviorCode.ElementTrailIce ||\n                    entry.BehaviorCode == PvpProjectileBehaviorCode.FreezeHit)\n                {\n                    visualElement = ElementType.Ice;\n                }\n            });\n\n            return visualElement;\n        }\n\n        private PvpProjectileAugmentPayload CreateAugmentPayload()\n        {\n            if (_augmentSnapshotProvider == null)\n            {\n                _augmentSnapshotProvider = GetComponent<PvpProjectileAugmentSnapshotProvider>();\n            }\n\n            if (_augmentSnapshotProvider != null)\n            {\n                PvpProjectileAugmentPayload payload = _augmentSnapshotProvider.CreatePayload();\n                if (payload.HasAnyAugment)\n                {\n                    return payload;\n                }\n            }\n\n            if (LocalPlayerStatusContext.TryGet(out PlayerStatus localPlayerStatus))\n            {\n                PvpProjectileAugmentPayload payload = PvpProjectileAugmentSnapshotProvider.CreatePayloadFrom(localPlayerStatus);\n                if (payload.HasAnyAugment)\n                {\n                    Debug.Log(\"[NetworkProjectileFireHandler] Created augment payload from LocalPlayerStatusContext.\");\n                    return payload;\n                }\n            }\n\n            if (_playerStatus != null)\n            {\n                PvpProjectileAugmentPayload payload = PvpProjectileAugmentSnapshotProvider.CreatePayloadFrom(_playerStatus);\n                if (payload.HasAnyAugment)\n                {\n                    Debug.Log(\"[NetworkProjectileFireHandler] Created augment payload from local PlayerStatus component.\");\n                    return payload;\n                }\n            }\n\n            Debug.LogWarning(\"[NetworkProjectileFireHandler] Could not create augment payload. No active projectile behaviors found.\");\n            return PvpProjectileAugmentPayload.Empty;\n        }\n\n        private bool CanFireInCurrentMatchState()\n        {\n            if (_matchStateController == null)\n            {\n                _matchStateController = FindFirstObjectByType<PvpMatchStateController>();\n            }\n\n            return _matchStateController == null ||\n                   _matchStateController.CurrentState == PvpMatchState.Fighting;\n        }\n\n        private static Vector3 ToWorldXZ(Vector3 direction)\n        {\n            Vector3 worldDirection = Mathf.Approximately(direction.z, 0f)\n                ? new Vector3(direction.x, 0f, direction.y)\n                : new Vector3(direction.x, 0f, direction.z);\n\n            return worldDirection.sqrMagnitude > 0.0001f\n                ? worldDirection.normalized\n                : Vector3.zero;\n        }\n        public override void Spawned()\n        {\n            _behaviorRegistry = FindFirstObjectByType<ProjectileBehaviorRegistry>();\n            _matchStateController = FindFirstObjectByType<PvpMatchStateController>();\n        }\n    }\n}\n", "Network/PvP/NetworkShieldActor.cs": "using Fusion;\nusing Shield_Shot.GameplayCore.Render;\nusing Shield_Shot.GameplayCore.Weapon.Projectile;\nusing Shield_Shot.GameplayCore.Weapon.Shield;\nusing System.Collections.Generic;\nusing UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Network.Pvp\n{\n    [RequireComponent(typeof(NetworkObject))]\n    [RequireComponent(typeof(PvpWeaponActorIdentity))]\n    public sealed class NetworkShieldActor : NetworkBehaviour\n    {\n        [Header(\"Smoothing\")]\n        [SerializeField] private float _remoteLerpSpeed = 15f;\n\n        [Header(\"Reflect Rules\")]\n        [Tooltip(\"true = 자기/상대 투사체 모두 반사 / false = 상대 투사체만 반사\")]\n        [SerializeField] private bool _reflectOwnProjectile = true;\n\n        [Header(\"Reflect Cooldown\")]\n        [SerializeField] private float _reflectCooldown = 0.5f;\n\n        [Header(\"Reflect VFX\")]\n        [SerializeField] private VFXType _reflectVfxType = VFXType.Reflect;\n        [SerializeField] private float _reflectVfxDuration = 0.5f;\n\n        [Networked] private float NetworkedOrbitAngle { get; set; }\n\n        private ShieldBase _localShieldBase;\n        private ShieldOrbitController _localOrbitCtrl;\n        private ShieldOrbitController _remoteOrbitCtrl;\n        private PvpWeaponActorIdentity _identity;\n\n        private float _smoothedRemoteAngle;\n        private float _lastSentAngle;\n        private const float AngleSyncThreshold = 0.5f;\n\n        private bool _localInjected;\n        private bool _forceSend;\n\n        // StateAuthority에서 중복 반사 방지\n        private readonly Dictionary<NetworkId, float> _recentlyReflected = new();\n\n        private void Awake()\n        {\n            _identity = GetComponent<PvpWeaponActorIdentity>();\n        }\n\n        public override void Spawned()\n        {\n            _smoothedRemoteAngle = NetworkedOrbitAngle;\n            _lastSentAngle = NetworkedOrbitAngle;\n            _forceSend = true;\n\n            Debug.Log($\"[NetworkShieldActor] Spawned. \" +\n                      $\"InputAuth={Object.HasInputAuthority}, StateAuth={Object.HasStateAuthority}\");\n        }\n\n        public void InjectShieldReferences(ShieldBase shieldBase, ShieldOrbitController orbitCtrl)\n        {\n            _localShieldBase = shieldBase;\n            _localOrbitCtrl = orbitCtrl;\n            _localInjected = true;\n            _forceSend = true;\n            Debug.Log($\"[NetworkShieldActor] 내 방패 참조 주입 완료. InitialAngle={orbitCtrl?.CurrentAngle}\");\n        }\n\n        public void InjectRemoteShieldReferences(ShieldOrbitController orbitCtrl)\n        {\n            _remoteOrbitCtrl = orbitCtrl;\n            Debug.Log(\"[NetworkShieldActor] 상대 방패 참조 주입 완료.\");\n        }\n\n        public override void FixedUpdateNetwork()\n        {\n            if (!Object.HasInputAuthority) return;\n            if (Runner.IsResimulation) return;\n            if (!_localInjected || _localOrbitCtrl == null) return;\n\n            float current = _localOrbitCtrl.CurrentAngle;\n            float delta = Mathf.Abs(Mathf.DeltaAngle(current, _lastSentAngle));\n\n            bool shouldSend = _forceSend || delta >= AngleSyncThreshold;\n            if (!shouldSend) return;\n\n            _forceSend = false;\n            _lastSentAngle = current;\n\n            if (Object.HasStateAuthority)\n                NetworkedOrbitAngle = current;\n            else\n                RPC_SetOrbitAngle(current);\n        }\n\n        private void LateUpdate()\n        {\n            if (Object == null) return;\n            if (Object.HasInputAuthority) return;\n            if (_remoteOrbitCtrl == null) return;\n\n            _smoothedRemoteAngle = Mathf.MoveTowardsAngle(\n                _smoothedRemoteAngle,\n                NetworkedOrbitAngle,\n                _remoteLerpSpeed * 360f * Time.deltaTime);\n\n            _remoteOrbitCtrl.SetOrbitAngleDirectly(_smoothedRemoteAngle);\n        }\n\n        public void NotifyShieldHit(ProjectileBase projectile, Vector3 hitNormal,\n                                    NetworkProjectileIdentity projectileIdentity)\n        {\n            if (projectile == null) return;\n            if (!CanReflect(projectileIdentity)) return;\n\n            if (Object.HasStateAuthority)\n            {\n                // StateAuthority에서 중복 반사 방지\n                if (projectile.TryGetComponent(out NetworkObject netObj))\n                {\n                    if (IsReflectOnCooldown(netObj.Id)) return;\n                    RegisterReflectCooldown(netObj.Id);\n                }\n                ProcessReflect(projectile, hitNormal);\n            }\n            else if (projectile.TryGetComponent(out NetworkObject netObj))\n            {\n                RPC_RequestReflect(netObj.Id, hitNormal);\n            }\n        }\n\n        private void Update()\n        {\n            // 만료된 반사 쿨다운 정리\n            var toRemove = new List<NetworkId>();\n            foreach (var kvp in _recentlyReflected)\n                if (Time.time - kvp.Value > _reflectCooldown)\n                    toRemove.Add(kvp.Key);\n            foreach (var key in toRemove)\n                _recentlyReflected.Remove(key);\n        }\n\n        private bool IsReflectOnCooldown(NetworkId id)\n        {\n            if (!_recentlyReflected.TryGetValue(id, out float t)) return false;\n            return Time.time - t < _reflectCooldown;\n        }\n\n        private void RegisterReflectCooldown(NetworkId id)\n        {\n            _recentlyReflected[id] = Time.time;\n        }\n\n        [Rpc(RpcSources.InputAuthority, RpcTargets.StateAuthority)]\n        private void RPC_SetOrbitAngle(float angle)\n        {\n            NetworkedOrbitAngle = angle;\n        }\n\n        [Rpc(RpcSources.All, RpcTargets.StateAuthority)]\n        private void RPC_RequestReflect(NetworkId projectileId, Vector3 hitNormal)\n        {\n            if (!Runner.TryFindObject(projectileId, out NetworkObject netObj)) return;\n            if (!netObj.TryGetComponent(out ProjectileBase projectile)) return;\n\n            // StateAuthority에서도 중복 방지\n            if (IsReflectOnCooldown(projectileId)) return;\n            RegisterReflectCooldown(projectileId);\n\n            ProcessReflect(projectile, hitNormal);\n        }\n\n        [Rpc(RpcSources.StateAuthority, RpcTargets.All)]\n        private void RPC_BroadcastReflectVFX(Vector3 pos, Vector3 normal)\n        {\n            Debug.Log($\"[NetworkShieldActor] 반사 VFX at {pos}\");\n            VFXPoolManager vfxPoolManager = VFXPoolManager.EnsureInstance();\n            if (_reflectVfxType == VFXType.None || vfxPoolManager == null)\n            {\n                return;\n            }\n\n            Quaternion rotation = normal.sqrMagnitude > 0.0001f\n                ? Quaternion.LookRotation(normal)\n                : Quaternion.identity;\n\n            vfxPoolManager.SpawnVFX(_reflectVfxType, pos, rotation, _reflectVfxDuration);\n        }\n\n        private void ProcessReflect(ProjectileBase projectile, Vector3 hitNormal)\n        {\n            if (_localShieldBase != null)\n                _localShieldBase.HandleNetworkProjectileHit(projectile, hitNormal);\n            else\n            {\n                projectile.Velocity = Vector3.Reflect(projectile.Velocity, hitNormal);\n                Debug.Log($\"[NetworkShieldActor] 원격 방패 반사. 방향={projectile.Velocity}\");\n            }\n            RPC_BroadcastReflectVFX(projectile.transform.position, hitNormal);\n        }\n\n        private bool CanReflect(NetworkProjectileIdentity identity)\n        {\n            if (_reflectOwnProjectile) return true;\n            if (identity == null || _identity == null) return true;\n            return identity.Owner != _identity.Owner;\n        }\n    }\n}\n", "Network/PvP/NetworkShieldColliderDetector.cs": "using Fusion;\nusing Shield_Shot.GameplayCore.Weapon.Projectile;\nusing Shield_Shot.GameplayCore.Weapon.Shield;\nusing System.Collections.Generic;\nusing UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Network.Pvp\n{\n    [RequireComponent(typeof(Collider))]\n    public sealed class NetworkShieldColliderDetector : MonoBehaviour, IShieldColliderDetector\n    {\n        [Header(\"Layer Settings\")]\n        [SerializeField] private LayerMask projectileLayerMask;\n\n        [Header(\"Defense Angle Settings\")]\n        [SerializeField, Range(10f, 180f)] private float defenseAngle = 120f;\n\n        [Header(\"Reflect Rules\")]\n        [Tooltip(\"true = 자기/상대 투사체 모두 반사 / false = 상대 투사체만 반사\")]\n        [SerializeField] private bool _reflectOwnProjectile = true;\n\n        [Header(\"Reflect Cooldown\")]\n        [Tooltip(\"반사 후 같은 투사체를 무시할 시간 (초)\")]\n        [SerializeField] private float reflectCooldown = 0.5f;\n\n        public event System.Action<ProjectileBase, Vector3> OnProjectileDetected;\n\n        private NetworkShieldActor _networkShieldActor;\n        private PvpWeaponActorIdentity _weaponActorIdentity;\n\n        // 최근 반사한 투사체와 시간 기록\n        private readonly Dictionary<ProjectileBase, float> _recentlyReflected = new();\n\n        private void Awake()\n        {\n            IncludeProjectileLayer(\"Projectile\");\n            IncludeProjectileLayer(\"PvpProjectile\");\n            IncludeProjectileLayer(\"MonsterProjectile\");\n        }\n\n        public void InjectNetworkShieldActor(NetworkShieldActor actor)\n        {\n            _networkShieldActor = actor;\n            _weaponActorIdentity = actor != null ? actor.GetComponent<PvpWeaponActorIdentity>() : null;\n        }\n\n        private void OnTriggerEnter(Collider other)\n        {\n            ProjectileBase projectile = other.GetComponent<ProjectileBase>()\n                ?? other.GetComponentInParent<ProjectileBase>()\n                ?? other.GetComponentInChildren<ProjectileBase>();\n            if (projectile == null) return;\n\n            int mask = 1 << other.gameObject.layer;\n            bool layerAllowed = (projectileLayerMask.value & mask) != 0;\n            NetworkProjectileIdentity networkProjectile = other.GetComponent<NetworkProjectileIdentity>()\n                ?? other.GetComponentInParent<NetworkProjectileIdentity>();\n            if (!layerAllowed && networkProjectile == null) return;\n\n            // 반사 직후 재충돌 방지\n            if (IsOnCooldown(projectile)) return;\n\n            if (!IsHitFromFront(projectile)) return;\n\n            NetworkProjectileIdentity identity =\n                other.GetComponent<NetworkProjectileIdentity>()\n                ?? other.GetComponentInParent<NetworkProjectileIdentity>();\n\n            if (!CanReflect(identity)) return;\n\n            Vector3 hitNormal = GetHitNormal(other, projectile);\n\n            // 쿨다운 등록\n            _recentlyReflected[projectile] = Time.time;\n\n            if (_networkShieldActor != null)\n                _networkShieldActor.NotifyShieldHit(projectile, hitNormal, identity);\n            else\n                OnProjectileDetected?.Invoke(projectile, hitNormal);\n        }\n\n        private void Update()\n        {\n            // 만료된 쿨다운 정리\n            var toRemove = new List<ProjectileBase>();\n            foreach (var kvp in _recentlyReflected)\n            {\n                if (kvp.Key == null || Time.time - kvp.Value > reflectCooldown)\n                    toRemove.Add(kvp.Key);\n            }\n            foreach (var key in toRemove)\n                _recentlyReflected.Remove(key);\n        }\n\n        private bool IsOnCooldown(ProjectileBase projectile)\n        {\n            if (!_recentlyReflected.TryGetValue(projectile, out float lastTime)) return false;\n            return Time.time - lastTime < reflectCooldown;\n        }\n\n        private bool CanReflect(NetworkProjectileIdentity identity)\n        {\n            if (_reflectOwnProjectile) return true;\n            if (identity == null || _weaponActorIdentity == null) return true;\n            return identity.Owner != _weaponActorIdentity.Owner;\n        }\n\n        private bool IsHitFromFront(ProjectileBase projectile)\n        {\n            Vector3 incoming = projectile.Velocity.sqrMagnitude > 0.001f\n                ? projectile.Velocity.normalized\n                : projectile.transform.forward;\n            Vector3 shieldFwd = -transform.forward;\n\n            if (Vector3.Dot(incoming, shieldFwd) >= 0f) return false;\n\n            Vector3 toProj = (projectile.transform.position - transform.position).normalized;\n            toProj.y = 0f;\n            shieldFwd.y = 0f;\n            return Vector3.Angle(shieldFwd.normalized, toProj.normalized) <= defenseAngle * 0.5f;\n        }\n\n        private Vector3 GetHitNormal(Collider other, ProjectileBase projectile)\n        {\n            Vector3 dir = projectile.Velocity.sqrMagnitude > 0.001f\n                ? projectile.Velocity.normalized\n                : projectile.transform.forward;\n            Vector3 origin = projectile.transform.position - dir * 0.2f;\n\n            if (Physics.SphereCast(origin, 0.1f, dir, out RaycastHit hit, 2f, 1 << gameObject.layer))\n            {\n                Vector3 n = hit.normal;\n                return Vector3.Dot(n, -transform.forward) < 0f ? -n : n;\n            }\n            return -transform.forward;\n        }\n\n        private void IncludeProjectileLayer(string layerName)\n        {\n            int layer = LayerMask.NameToLayer(layerName);\n            if (layer < 0)\n            {\n                return;\n            }\n\n            projectileLayerMask |= 1 << layer;\n        }\n    }\n}\n", "Network/PvP/NetworkShieldSpawnSetup.cs": "using Fusion;\nusing Shield_Shot.DataManagement;\nusing Shield_Shot.DataManagement.DataParsing;\nusing Shield_Shot.DataManagement.InventorySystem;\nusing Shield_Shot.GameplayCore.Weapon.Shield;\nusing Shield_Shot.InputSystem;\nusing UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Network.Pvp\n{\n    [RequireComponent(typeof(NetworkObject))]\n    [RequireComponent(typeof(NetworkShieldActor))]\n    public sealed class NetworkShieldSpawnSetup : NetworkBehaviour\n    {\n        [Header(\"Shield Resources\")]\n        [SerializeField] private string _networkShieldResourcesFolder = \"Prefabs/Network\";\n        [SerializeField] private string _networkShieldNameSuffix = \"\";\n        [SerializeField] private bool _allowLocalPrefabFallback;\n\n        private const string DefaultNetworkShieldPrefabName = \"Shield1\";\n\n        [Header(\"Mount Points\")]\n        [Tooltip(\"Initial shield spawn point, for example ShieldPoint.\")]\n        [SerializeField] private Transform _shieldMountPoint;\n\n        [Tooltip(\"Shield orbit center. Usually the WeaponCore_Network root.\")]\n        [SerializeField] private Transform _playerOrbitCenter;\n\n        [Header(\"Spawn Visual Scale\")]\n        [SerializeField, Min(0.01f)] private float _spawnedShieldScale = 0.75f;\n\n        [Networked] private NetworkString<_32> ShieldId { get; set; }\n        [Networked] private NetworkBool ShieldLoadoutInitialized { get; set; }\n\n        private NetworkShieldActor _networkShieldActor;\n        private ShieldItem _localShieldData;\n        private GameObject _spawnedShield;\n        private string _builtShieldId = string.Empty;\n\n        private void Awake()\n        {\n            _networkShieldActor = GetComponent<NetworkShieldActor>();\n        }\n\n        public override void Spawned()\n        {\n            Debug.Log($\"[ShieldSpawnSetup] Spawned\\n\" +\n                      $\"  HasInputAuthority  = {Object.HasInputAuthority}\\n\" +\n                      $\"  HasStateAuthority  = {Object.HasStateAuthority}\\n\" +\n                      $\"  LocalPlayer        = {Runner.LocalPlayer}\\n\" +\n                      $\"  MountPoint         = {(_shieldMountPoint != null ? _shieldMountPoint.name : \"NULL!\")}\");\n\n            if (_shieldMountPoint == null)\n            {\n                Debug.LogError(\"[ShieldSpawnSetup] Shield Mount Point is missing.\");\n                return;\n            }\n\n            if (_playerOrbitCenter == null)\n            {\n                Debug.LogWarning(\"[ShieldSpawnSetup] Player Orbit Center is missing. Using root transform.\");\n                _playerOrbitCenter = transform;\n            }\n\n            if (Object.HasInputAuthority)\n            {\n                LoadLocalShieldData();\n                SendShieldLoadoutToStateAuthority();\n            }\n\n            RebuildShieldIfNeeded();\n        }\n\n        private void Update()\n        {\n            RebuildShieldIfNeeded();\n        }\n\n        private void LoadLocalShieldData()\n        {\n            _localShieldData = PlayerIngameLoadData.ShieldItem as ShieldItem;\n            if (_localShieldData != null)\n            {\n                return;\n            }\n\n            if (PlayerDataManager.Instance == null)\n            {\n                Debug.LogWarning(\"[ShieldSpawnSetup] PlayerDataManager is missing.\");\n                return;\n            }\n\n            _localShieldData = PlayerDataManager.Instance.GetShield() as ShieldItem;\n        }\n\n        private void SendShieldLoadoutToStateAuthority()\n        {\n            string shieldId = GetShieldId(_localShieldData);\n\n            if (Object.HasStateAuthority)\n            {\n                ApplyShieldLoadout(shieldId);\n                return;\n            }\n\n            RPC_SetShieldLoadout(shieldId);\n        }\n\n        [Rpc(RpcSources.InputAuthority, RpcTargets.StateAuthority)]\n        private void RPC_SetShieldLoadout(string shieldId)\n        {\n            ApplyShieldLoadout(shieldId);\n        }\n\n        private void ApplyShieldLoadout(string shieldId)\n        {\n            ShieldId = shieldId ?? string.Empty;\n            ShieldLoadoutInitialized = true;\n        }\n\n        private void RebuildShieldIfNeeded()\n        {\n            if (!ShieldLoadoutInitialized)\n            {\n                return;\n            }\n\n            string shieldId = NormalizeShieldId(ShieldId.ToString());\n            if (_spawnedShield != null && _builtShieldId == shieldId)\n            {\n                return;\n            }\n\n            ClearShield();\n            if (SpawnShield(shieldId))\n            {\n                _builtShieldId = shieldId;\n            }\n        }\n\n        private bool SpawnShield(string shieldId)\n        {\n            shieldId = NormalizeShieldId(shieldId);\n            ShieldItem shieldItem = _localShieldData ?? CreateShieldItemFromId(shieldId);\n            ShieldItemData shieldData = shieldItem?.ShieldData;\n            GameObject prefab = ResolveNetworkShieldPrefab(shieldId, shieldData);\n            if (prefab == null && _allowLocalPrefabFallback && shieldData != null)\n            {\n                prefab = shieldData.ShieldPrefab;\n            }\n\n            if (prefab == null)\n            {\n                Debug.LogError($\"[ShieldSpawnSetup] Shield prefab missing. ShieldId: {shieldId}\");\n                return false;\n            }\n\n            // Keep the shield at scene root; ShieldOrbitController updates world position from orbit center.\n            GameObject shieldObj = Instantiate(\n                prefab,\n                _shieldMountPoint.position,\n                Quaternion.identity,\n                null);\n            shieldObj.transform.localScale = Vector3.one * _spawnedShieldScale;\n            shieldObj.SetActive(true);\n            ApplyLayerRecursively(shieldObj.transform, ResolvePvpShieldLayer());\n            _spawnedShield = shieldObj;\n\n            var skillShield = shieldObj.GetComponentInChildren<SkillShield>(true);\n            var orbitCtrl = shieldObj.GetComponentInChildren<ShieldOrbitController>(true);\n            var netDetector = shieldObj.GetComponentInChildren<NetworkShieldColliderDetector>(true);\n            var binder = shieldObj.GetComponentInChildren<ShieldSystemBinder>(true);\n\n            if (skillShield == null)\n            {\n                Debug.LogError(\"[ShieldSpawnSetup] SkillShield is missing.\");\n                ClearShield();\n                return false;\n            }\n\n            if (netDetector != null)\n            {\n                netDetector.InjectNetworkShieldActor(_networkShieldActor);\n            }\n\n            bool enableCollider = Object.HasStateAuthority || Object.HasInputAuthority;\n            foreach (var col in shieldObj.GetComponentsInChildren<Collider>(true))\n            {\n                col.enabled = enableCollider;\n            }\n\n            if (orbitCtrl != null)\n            {\n                orbitCtrl.SetupOrbitCenter(_playerOrbitCenter);\n            }\n\n            if (binder != null)\n            {\n                binder.InitializeBinding(null, orbitCtrl);\n            }\n\n            skillShield.ApplyShieldData(shieldData, _playerOrbitCenter, null);\n            skillShield.Initialize();\n\n            if (Object.HasInputAuthority)\n            {\n                var inputReceiver = FindFirstObjectByType<PlayerInputReceiver>();\n                if (inputReceiver != null)\n                {\n                    inputReceiver.SetCurrentShield(skillShield);\n                }\n                else\n                {\n                    Debug.LogWarning(\"[ShieldSpawnSetup] PlayerInputReceiver is missing.\");\n                }\n\n                _networkShieldActor?.InjectShieldReferences(skillShield, orbitCtrl);\n                Debug.Log(\"[ShieldSpawnSetup] Local shield initialized.\");\n            }\n            else\n            {\n                _networkShieldActor?.InjectRemoteShieldReferences(orbitCtrl);\n                Debug.Log(\"[ShieldSpawnSetup] Remote shield visual initialized.\");\n            }\n\n            return true;\n        }\n\n        private GameObject ResolveNetworkShieldPrefab(string shieldId, ShieldItemData shieldData)\n        {\n            if (string.IsNullOrWhiteSpace(_networkShieldResourcesFolder))\n            {\n                return null;\n            }\n\n            string localPrefabName = shieldData != null && shieldData.ShieldPrefab != null\n                ? shieldData.ShieldPrefab.name\n                : shieldId;\n\n            if (string.IsNullOrWhiteSpace(localPrefabName))\n            {\n                localPrefabName = DefaultNetworkShieldPrefabName;\n            }\n\n            string networkPrefabName = $\"{localPrefabName}{_networkShieldNameSuffix}\";\n            string resourcePath = $\"{_networkShieldResourcesFolder.TrimEnd('/')}/{networkPrefabName}\";\n            GameObject prefab = Resources.Load<GameObject>(resourcePath);\n            if (prefab != null)\n            {\n                return prefab;\n            }\n\n            if (!string.Equals(networkPrefabName, DefaultNetworkShieldPrefabName, System.StringComparison.Ordinal))\n            {\n                string fallbackPath = $\"{_networkShieldResourcesFolder.TrimEnd('/')}/{DefaultNetworkShieldPrefabName}\";\n                return Resources.Load<GameObject>(fallbackPath);\n            }\n\n            return null;\n        }\n\n        private void ClearShield()\n        {\n            if (_spawnedShield == null)\n            {\n                return;\n            }\n\n            Destroy(_spawnedShield);\n            _spawnedShield = null;\n        }\n\n        private static string GetShieldId(ShieldItem item)\n        {\n            return item != null && item.ShieldData != null\n                ? item.ShieldData.ItemID\n                : string.Empty;\n        }\n\n        private string NormalizeShieldId(string shieldId)\n        {\n            return !string.IsNullOrWhiteSpace(shieldId)\n                ? shieldId\n                : DefaultNetworkShieldPrefabName;\n        }\n\n        private static ShieldItem CreateShieldItemFromId(string shieldId)\n        {\n            if (string.IsNullOrWhiteSpace(shieldId))\n            {\n                return null;\n            }\n\n            if (ItemDataParsingManager.Instance == null)\n            {\n                Debug.LogWarning($\"[ShieldSpawnSetup] ItemDataParsingManager is missing. ShieldId: {shieldId}\");\n                return null;\n            }\n\n            ShieldItemData shieldData = ItemDataParsingManager.Instance.GetShieldData(shieldId);\n            return shieldData != null ? new ShieldItem(shieldData) : null;\n        }\n\n        private static int ResolvePvpShieldLayer()\n        {\n            int layer = LayerMask.NameToLayer(\"PvpShield\");\n            if (layer >= 0)\n            {\n                return layer;\n            }\n\n            layer = LayerMask.NameToLayer(\"pvpshield\");\n            if (layer >= 0)\n            {\n                return layer;\n            }\n\n            Debug.LogWarning(\"[ShieldSpawnSetup] PvpShield layer is missing.\");\n            return -1;\n        }\n\n        private static void ApplyLayerRecursively(Transform target, int layer)\n        {\n            if (target == null || layer < 0)\n            {\n                return;\n            }\n\n            target.gameObject.layer = layer;\n            for (int i = 0; i < target.childCount; i++)\n            {\n                ApplyLayerRecursively(target.GetChild(i), layer);\n            }\n        }\n    }\n}\n", "Network/PvP/NetworkWeaponManager.cs": "using Fusion;\nusing Shield_Shot.DataManagement;\nusing Shield_Shot.DataManagement.DataParsing;\nusing Shield_Shot.DataManagement.InventorySystem;\nusing Shield_Shot.GameplayCore.Weapon.Aim;\nusing Shield_Shot.GameplayCore.Weapon.Core;\nusing Shield_Shot.GameplayCore.Weapon.Projectile;\nusing Shield_Shot.InputSystem;\nusing Shield_Shot.InputSystem.Data;\nusing UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Network.Pvp\n{\n    [RequireComponent(typeof(NetworkObject))]\n    [RequireComponent(typeof(NetworkProjectileFireHandler))]\n    [RequireComponent(typeof(StatCalculator))]\n    public sealed class NetworkWeaponManager : NetworkBehaviour\n    {\n        [System.Serializable]\n#pragma warning disable 0649\n        private struct NetworkWeaponPrefabEntry\n        {\n            public WeaponType Type;\n            public GameObject Prefab;\n        }\n#pragma warning restore 0649\n\n        [Header(\"Weapon Slots\")]\n        [SerializeField] private Transform _weaponMountPoint;\n        [SerializeField] private NetworkWeaponPrefabEntry[] _weaponPrefabs;\n        [SerializeField] private string _networkWeaponResourcesFolder = \"Prefabs/Network\";\n        [SerializeField] private string _networkWeaponNameSuffix = \"\";\n        [SerializeField] private bool _allowLocalPrefabFallback;\n\n        [Header(\"Spawn Visual Scale\")]\n        [SerializeField, Min(0.01f)] private float _spawnedWeaponScale = 1f;\n\n        [Header(\"Input\")]\n        [SerializeField] private PlayerInputReceiver _inputReceiver;\n\n        [Networked] private int CurrentWeaponIndex { get; set; }\n        [Networked] private int MainWeaponTypeValue { get; set; }\n        [Networked] private int SubWeaponTypeValue { get; set; }\n        [Networked] private NetworkString<_32> MainWeaponId { get; set; }\n        [Networked] private NetworkString<_32> SubWeaponId { get; set; }\n        [Networked] private float MainDamage { get; set; }\n        [Networked] private float MainSpeed { get; set; }\n        [Networked] private float MainCriticalMultiplier { get; set; }\n        [Networked] private float MainFireRate { get; set; }\n        [Networked] private float SubDamage { get; set; }\n        [Networked] private float SubSpeed { get; set; }\n        [Networked] private float SubCriticalMultiplier { get; set; }\n        [Networked] private float SubFireRate { get; set; }\n        [Networked] private NetworkBool LoadoutInitialized { get; set; }\n        [Networked] private Vector3 NetworkAimDirection { get; set; }\n\n        private const string DefaultNetworkMainWeaponPrefabName = \"Bow1_1_1\";\n        private const WeaponType DefaultMainWeaponType = WeaponType.Bow;\n\n        private readonly WeaponBase[] _equippedWeapons = new WeaponBase[2];\n        private readonly WeaponItem[] _localWeaponData = new WeaponItem[2];\n        private StatCalculator _statCalculator;\n        private NetworkProjectileFireHandler _fireHandler;\n        private int _appliedWeaponIndex = -1;\n        private int _builtMainTypeValue = int.MinValue;\n        private int _builtSubTypeValue = int.MinValue;\n        private string _builtMainWeaponId = string.Empty;\n        private string _builtSubWeaponId = string.Empty;\n        private Vector3 _smoothedRemoteAimDirection = Vector3.right;\n\n        public WeaponBase CurrentWeapon => _equippedWeapons[Mathf.Clamp(CurrentWeaponIndex, 0, 1)];\n\n        private void Awake()\n        {\n            _statCalculator = GetComponent<StatCalculator>();\n            _fireHandler = GetComponent<NetworkProjectileFireHandler>();\n\n            if (_weaponMountPoint == null)\n            {\n                _weaponMountPoint = transform;\n            }\n        }\n\n        public override void Spawned()\n        {\n            if (Object.HasInputAuthority)\n            {\n                LoadLocalWeaponData();\n                SendLoadoutToStateAuthority();\n            }\n\n            RebuildWeaponsIfNeeded();\n            ApplyCurrentWeapon();\n        }\n\n        private void Update()\n        {\n            RebuildWeaponsIfNeeded();\n            ApplyCurrentWeapon();\n        }\n\n        public override void FixedUpdateNetwork()\n        {\n            if (!Object.HasInputAuthority)\n            {\n                return;\n            }\n\n            Vector3 aimDirection = NormalizeAimDirection(CurrentWeapon != null ? CurrentWeapon.AimDirection : Vector3.right);\n            if (aimDirection.sqrMagnitude <= 0.0001f)\n            {\n                return;\n            }\n\n            if (Object.HasStateAuthority)\n            {\n                NetworkAimDirection = aimDirection;\n                return;\n            }\n\n            RPC_SetAimDirection(aimDirection);\n        }\n\n        private void LateUpdate()\n        {\n            ApplyRemoteWeaponRotation();\n        }\n\n        public void SwapWeapon()\n        {\n            if (!Object.HasInputAuthority)\n            {\n                return;\n            }\n\n            int nextIndex = CurrentWeaponIndex == 0 ? 1 : 0;\n\n            if (_equippedWeapons[nextIndex] == null)\n            {\n                Debug.LogWarning(\"[NetworkWeaponManager] Swap target weapon is missing.\");\n                return;\n            }\n\n            if (Object.HasStateAuthority)\n            {\n                CurrentWeaponIndex = nextIndex;\n                ApplyCurrentWeapon();\n                return;\n            }\n\n            RPC_RequestSwapWeapon(nextIndex);\n        }\n\n        [Rpc(RpcSources.InputAuthority, RpcTargets.StateAuthority)]\n        private void RPC_RequestSwapWeapon(int nextIndex)\n        {\n            CurrentWeaponIndex = Mathf.Clamp(nextIndex, 0, 1);\n            ApplyCurrentWeapon();\n        }\n\n        [Rpc(RpcSources.InputAuthority, RpcTargets.StateAuthority)]\n        private void RPC_SetAimDirection(Vector3 aimDirection)\n        {\n            NetworkAimDirection = NormalizeAimDirection(aimDirection);\n        }\n\n        [Rpc(RpcSources.InputAuthority, RpcTargets.StateAuthority)]\n        private void RPC_SetLoadout(\n            int mainType,\n            string mainWeaponId,\n            float mainDamage,\n            float mainSpeed,\n            float mainCriticalMultiplier,\n            float mainFireRate,\n            int subType,\n            string subWeaponId,\n            float subDamage,\n            float subSpeed,\n            float subCriticalMultiplier,\n            float subFireRate)\n        {\n            ApplyLoadout(\n                mainType,\n                mainWeaponId,\n                mainDamage,\n                mainSpeed,\n                mainCriticalMultiplier,\n                mainFireRate,\n                subType,\n                subWeaponId,\n                subDamage,\n                subSpeed,\n                subCriticalMultiplier,\n                subFireRate);\n        }\n\n        private void LoadLocalWeaponData()\n        {\n            _localWeaponData[0] = PlayerIngameLoadData.MainWeaponItem as WeaponItem;\n            _localWeaponData[1] = PlayerIngameLoadData.SubWeaponItem as WeaponItem;\n\n            if (_localWeaponData[0] != null || _localWeaponData[1] != null)\n            {\n                return;\n            }\n\n            if (PlayerDataManager.Instance == null)\n            {\n                Debug.LogWarning(\"[NetworkWeaponManager] PlayerDataManager is missing.\");\n                return;\n            }\n\n            _localWeaponData[0] = PlayerDataManager.Instance.GetMainWeapon() as WeaponItem;\n            _localWeaponData[1] = PlayerDataManager.Instance.GetSubWeapon() as WeaponItem;\n        }\n\n        private void SendLoadoutToStateAuthority()\n        {\n            WeaponItem main = _localWeaponData[0];\n            WeaponItem sub = _localWeaponData[1];\n\n            int mainType = ToWeaponTypeValue(main);\n            int subType = ToWeaponTypeValue(sub);\n            string mainWeaponId = NormalizeMainWeaponId(GetWeaponId(main));\n            string subWeaponId = GetWeaponId(sub);\n\n            if (mainType == (int)WeaponType.None)\n            {\n                mainType = (int)DefaultMainWeaponType;\n            }\n\n            if (Object.HasStateAuthority)\n            {\n                ApplyLoadout(\n                    mainType,\n                    mainWeaponId,\n                    GetDamage(main),\n                    GetSpeed(main),\n                    GetCriticalMultiplier(main),\n                    GetFireRate(main),\n                    subType,\n                    subWeaponId,\n                    GetDamage(sub),\n                    GetSpeed(sub),\n                    GetCriticalMultiplier(sub),\n                    GetFireRate(sub));\n                return;\n            }\n\n            RPC_SetLoadout(\n                mainType,\n                mainWeaponId,\n                GetDamage(main),\n                GetSpeed(main),\n                GetCriticalMultiplier(main),\n                GetFireRate(main),\n                subType,\n                subWeaponId,\n                GetDamage(sub),\n                GetSpeed(sub),\n                GetCriticalMultiplier(sub),\n                GetFireRate(sub));\n        }\n\n        private void ApplyLoadout(\n            int mainType,\n            string mainWeaponId,\n            float mainDamage,\n            float mainSpeed,\n            float mainCriticalMultiplier,\n            float mainFireRate,\n            int subType,\n            string subWeaponId,\n            float subDamage,\n            float subSpeed,\n            float subCriticalMultiplier,\n            float subFireRate)\n        {\n            MainWeaponTypeValue = mainType;\n            MainWeaponId = mainWeaponId ?? string.Empty;\n            MainDamage = mainDamage;\n            MainSpeed = mainSpeed;\n            MainCriticalMultiplier = mainCriticalMultiplier;\n            MainFireRate = mainFireRate;\n            SubWeaponTypeValue = subType;\n            SubWeaponId = subWeaponId ?? string.Empty;\n            SubDamage = subDamage;\n            SubSpeed = subSpeed;\n            SubCriticalMultiplier = subCriticalMultiplier;\n            SubFireRate = subFireRate;\n            CurrentWeaponIndex = 0;\n            LoadoutInitialized = true;\n        }\n\n        private void RebuildWeaponsIfNeeded()\n        {\n            if (!LoadoutInitialized)\n            {\n                return;\n            }\n\n            string mainWeaponId = MainWeaponId.ToString();\n            string subWeaponId = SubWeaponId.ToString();\n\n            if (_builtMainTypeValue == MainWeaponTypeValue &&\n                _builtSubTypeValue == SubWeaponTypeValue &&\n                _builtMainWeaponId == mainWeaponId &&\n                _builtSubWeaponId == subWeaponId)\n            {\n                return;\n            }\n\n            ClearWeapon(0);\n            ClearWeapon(1);\n\n            _equippedWeapons[0] = CreateWeapon((WeaponType)MainWeaponTypeValue, mainWeaponId, _localWeaponData[0]);\n            _equippedWeapons[1] = CreateWeapon((WeaponType)SubWeaponTypeValue, subWeaponId, _localWeaponData[1]);\n\n            _builtMainTypeValue = MainWeaponTypeValue;\n            _builtSubTypeValue = SubWeaponTypeValue;\n            _builtMainWeaponId = mainWeaponId;\n            _builtSubWeaponId = subWeaponId;\n            _appliedWeaponIndex = -1;\n        }\n\n        private WeaponBase CreateWeapon(WeaponType type, string weaponId, WeaponItem localData)\n        {\n            if (type == WeaponType.None)\n            {\n                return null;\n            }\n\n            WeaponItem weaponData = localData ?? CreateWeaponItemFromId(weaponId);\n            GameObject prefab = ResolveNetworkWeaponPrefab(type, weaponId, weaponData);\n            if (prefab == null && _allowLocalPrefabFallback && localData != null && localData.WeaponData != null)\n            {\n                prefab = localData.WeaponData.WeaponPrefab;\n            }\n\n            if (prefab == null)\n            {\n                Debug.LogWarning($\"[NetworkWeaponManager] Network weapon prefab is missing for type: {type}, id: {weaponId}\");\n                return null;\n            }\n\n            GameObject instance = Instantiate(prefab, _weaponMountPoint);\n            instance.transform.localPosition = Vector3.zero;\n            instance.transform.localRotation = Quaternion.identity;\n            instance.transform.localScale = Vector3.one * _spawnedWeaponScale;\n\n            PvpWeaponActorIdentity identity = GetComponent<PvpWeaponActorIdentity>();\n            string ownerText = identity != null ? $\"{identity.Owner}/{identity.Side}\" : \"Unknown\";\n            Debug.Log(\n                $\"[NetworkWeaponManager] Created weapon prefab. \" +\n                $\"Actor: {gameObject.name}, Owner/Side: {ownerText}, Type: {type}, Id: {weaponId}, \" +\n                $\"Prefab: {prefab.name}, Instance: {instance.name}, \" +\n                $\"LocalPosition: {instance.transform.localPosition}, LocalScale: {instance.transform.localScale}, \" +\n                $\"WorldPosition: {instance.transform.position}\");\n\n            WeaponBase weapon = instance.GetComponentInChildren<WeaponBase>();\n            if (weapon == null)\n            {\n                Debug.LogWarning($\"[NetworkWeaponManager] WeaponBase is missing on prefab: {prefab.name}\");\n                return null;\n            }\n\n            weapon.SetProjectileFireHandler(_fireHandler);\n            ApplyWeaponDataIfAvailable(instance, weapon, weaponData);\n            weapon.Initialize();\n            instance.SetActive(false);\n            return weapon;\n        }\n\n        private void ApplyWeaponDataIfAvailable(GameObject instance, WeaponBase weapon, WeaponItem weaponData)\n        {\n            if (weaponData == null)\n            {\n                return;\n            }\n\n            StatCalculator weaponStatCalculator = instance.GetComponentInChildren<StatCalculator>();\n            if (weaponStatCalculator != null)\n            {\n                weaponStatCalculator.ApplyWeaponData(weaponData);\n            }\n\n            weapon.ApplyWeaponData(weaponData);\n        }\n\n        private void ApplyCurrentWeapon()\n        {\n            int weaponIndex = Mathf.Clamp(CurrentWeaponIndex, 0, 1);\n            if (_appliedWeaponIndex == weaponIndex)\n            {\n                return;\n            }\n\n            for (int i = 0; i < _equippedWeapons.Length; i++)\n            {\n                if (_equippedWeapons[i] == null)\n                {\n                    continue;\n                }\n\n                _equippedWeapons[i].Deactivate();\n                _equippedWeapons[i].gameObject.SetActive(i == weaponIndex);\n            }\n\n            ApplyNetworkStats(weaponIndex);\n            BindLocalInput(weaponIndex);\n            _appliedWeaponIndex = weaponIndex;\n\n            PvpWeaponActorIdentity identity = GetComponent<PvpWeaponActorIdentity>();\n            string ownerText = identity != null ? $\"{identity.Owner}/{identity.Side}\" : \"Unknown\";\n            WeaponBase currentWeapon = _equippedWeapons[weaponIndex];\n            Debug.Log(\n                $\"[NetworkWeaponManager] Applied current weapon. \" +\n                $\"Actor: {gameObject.name}, Owner/Side: {ownerText}, Index: {weaponIndex}, \" +\n                $\"Weapon: {(currentWeapon != null ? currentWeapon.gameObject.name : \"None\")}, \" +\n                $\"Active: {(currentWeapon != null && currentWeapon.gameObject.activeSelf)}\");\n        }\n\n        private void ApplyNetworkStats(int weaponIndex)\n        {\n            float damage = weaponIndex == 0 ? MainDamage : SubDamage;\n            float speed = weaponIndex == 0 ? MainSpeed : SubSpeed;\n            float criticalMultiplier = weaponIndex == 0 ? MainCriticalMultiplier : SubCriticalMultiplier;\n\n            if (_statCalculator != null)\n            {\n                _statCalculator.ApplyRawStats(damage, speed, 1f, 1f, criticalMultiplier);\n            }\n        }\n\n        private void BindLocalInput(int weaponIndex)\n        {\n            if (!Object.HasInputAuthority)\n            {\n                return;\n            }\n\n            WeaponBase weapon = _equippedWeapons[weaponIndex];\n            if (weapon == null)\n            {\n                return;\n            }\n\n            if (_inputReceiver == null)\n            {\n                _inputReceiver = FindFirstObjectByType<PlayerInputReceiver>();\n            }\n\n            if (_inputReceiver != null)\n            {\n                _inputReceiver.SetCurrentWeapon(weapon);\n            }\n        }\n\n        private void ApplyRemoteWeaponRotation()\n        {\n            if (Object == null || Object.HasInputAuthority)\n            {\n                return;\n            }\n\n            WeaponBase weapon = CurrentWeapon;\n            if (weapon == null)\n            {\n                return;\n            }\n\n            Vector3 targetDirection = NormalizeAimDirection(NetworkAimDirection);\n            if (targetDirection.sqrMagnitude <= 0.0001f)\n            {\n                return;\n            }\n\n            WeaponRotationController rotationController = weapon.GetComponent<WeaponRotationController>();\n            if (rotationController == null)\n            {\n                return;\n            }\n\n            _smoothedRemoteAimDirection = Vector3.Slerp(\n                NormalizeAimDirection(_smoothedRemoteAimDirection),\n                targetDirection,\n                Time.deltaTime * 20f);\n\n            rotationController.SyncRotation(_smoothedRemoteAimDirection);\n        }\n\n        private GameObject ResolveNetworkWeaponPrefab(WeaponType type, string weaponId, WeaponItem weaponData)\n        {\n            GameObject prefab = ResolveNetworkWeaponPrefabFromResources(type, weaponId, weaponData);\n            if (prefab != null)\n            {\n                return prefab;\n            }\n\n            if (type == WeaponType.None || _weaponPrefabs == null)\n            {\n                return null;\n            }\n\n            for (int i = 0; i < _weaponPrefabs.Length; i++)\n            {\n                if (_weaponPrefabs[i].Type == type)\n                {\n                    return _weaponPrefabs[i].Prefab;\n                }\n            }\n\n            return null;\n        }\n\n        private GameObject ResolveNetworkWeaponPrefabFromResources(WeaponType type, string weaponId, WeaponItem weaponData)\n        {\n            if (string.IsNullOrWhiteSpace(_networkWeaponResourcesFolder))\n            {\n                return null;\n            }\n\n            string localPrefabName = weaponData != null &&\n                weaponData.WeaponData != null &&\n                weaponData.WeaponData.WeaponPrefab != null\n                    ? weaponData.WeaponData.WeaponPrefab.name\n                    : weaponId;\n\n            if (string.IsNullOrWhiteSpace(localPrefabName))\n            {\n                return null;\n            }\n\n            string networkPrefabName = $\"{localPrefabName}{_networkWeaponNameSuffix}\";\n            string resourcePath = $\"{_networkWeaponResourcesFolder.TrimEnd('/')}/{networkPrefabName}\";\n            GameObject prefab = Resources.Load<GameObject>(resourcePath);\n            if (prefab != null)\n            {\n                return prefab;\n            }\n\n            if (type == DefaultMainWeaponType &&\n                !string.Equals(networkPrefabName, DefaultNetworkMainWeaponPrefabName, System.StringComparison.Ordinal))\n            {\n                string fallbackPath = $\"{_networkWeaponResourcesFolder.TrimEnd('/')}/{DefaultNetworkMainWeaponPrefabName}\";\n                return Resources.Load<GameObject>(fallbackPath);\n            }\n\n            return null;\n        }\n\n        private void ClearWeapon(int index)\n        {\n            if (_equippedWeapons[index] == null)\n            {\n                return;\n            }\n\n            Destroy(_equippedWeapons[index].gameObject);\n            _equippedWeapons[index] = null;\n        }\n\n        private static int ToWeaponTypeValue(WeaponItem item)\n        {\n            if (item == null || item.WeaponData == null)\n            {\n                return (int)WeaponType.None;\n            }\n\n            WeaponType type = item.WeaponData.weaponType;\n            if (type == WeaponType.None)\n            {\n                type = item.WeaponData.Type;\n            }\n\n            return (int)type;\n        }\n\n        private static string GetWeaponId(WeaponItem item)\n        {\n            return item != null && item.WeaponData != null\n                ? item.WeaponData.ItemID\n                : string.Empty;\n        }\n\n        private static string NormalizeMainWeaponId(string weaponId)\n        {\n            return !string.IsNullOrWhiteSpace(weaponId)\n                ? weaponId\n                : DefaultNetworkMainWeaponPrefabName;\n        }\n\n        private static WeaponItem CreateWeaponItemFromId(string weaponId)\n        {\n            if (string.IsNullOrWhiteSpace(weaponId))\n            {\n                return null;\n            }\n\n            if (ItemDataParsingManager.Instance == null)\n            {\n                Debug.LogWarning($\"[NetworkWeaponManager] ItemDataParsingManager is missing. WeaponId: {weaponId}\");\n                return null;\n            }\n\n            WeaponItemData weaponData = ItemDataParsingManager.Instance.GetWeaponData(weaponId);\n            return weaponData != null ? new WeaponItem(weaponData) : null;\n        }\n\n        private static float GetDamage(WeaponItem item) => item != null ? item.FinalDamage : 10f;\n        private static float GetSpeed(WeaponItem item) => item != null ? item.FinalSpeed : 15f;\n        private static float GetCriticalMultiplier(WeaponItem item) => item != null ? item.FinalCriticalDamageMultiplier : 2f;\n        private static float GetFireRate(WeaponItem item) => item != null ? item.FinalFireRate : 0.5f;\n\n        private static Vector3 NormalizeAimDirection(Vector3 direction)\n        {\n            direction.z = 0f;\n\n            if (direction.sqrMagnitude <= 0.0001f)\n            {\n                return Vector3.right;\n            }\n\n            return direction.normalized;\n        }\n    }\n}\n", "Network/PvP/ProjectileBehaviorRegistry.cs": "using System.Collections.Generic;\nusing Shield_Shot.GameplayCore.Weapon.Projectile;\nusing UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Network.Pvp\n{\n    public sealed class ProjectileBehaviorRegistry : MonoBehaviour\n    {\n        [Header(\"Projectile Behaviors\")]\n        [SerializeField] private List<ProjectileBehaviorSO> _behaviors = new();\n\n        private readonly Dictionary<int, ProjectileBehaviorSO> _behaviorByCode = new();\n\n        private void Awake()\n        {\n            BuildRegistry();\n        }\n\n        public bool TryGet(int behaviorCode, out ProjectileBehaviorSO behaviorSO)\n        {\n            return _behaviorByCode.TryGetValue(behaviorCode, out behaviorSO);\n        }\n\n        public int ApplyPayload(ProjectileBase projectile, PvpProjectileAugmentPayload payload)\n        {\n            if (projectile == null)\n            {\n                return 0;\n            }\n\n            if (!payload.HasAnyAugment)\n            {\n                Debug.Log(\"[ProjectileBehaviorRegistry] Payload is empty.\");\n                return 0;\n            }\n\n            int appliedCount = 0;\n            payload.ForEach(entry =>\n            {\n                if (!TryGet(entry.BehaviorCode, out ProjectileBehaviorSO behaviorSO))\n                {\n                    Debug.LogWarning($\"[ProjectileBehaviorRegistry] Unknown behavior code: {entry.BehaviorCode}\");\n                    return;\n                }\n\n                behaviorSO.InjectBehavior(projectile, entry.Level);\n                appliedCount++;\n                Debug.Log($\"[ProjectileBehaviorRegistry] Applied behavior: {behaviorSO.BehaviorName}({entry.BehaviorCode}) Lv.{entry.Level}\");\n            });\n\n            return appliedCount;\n        }\n\n        private void BuildRegistry()\n        {\n            _behaviorByCode.Clear();\n\n            for (int i = 0; i < _behaviors.Count; i++)\n            {\n                ProjectileBehaviorSO behaviorSO = _behaviors[i];\n                if (behaviorSO == null)\n                {\n                    continue;\n                }\n\n                int code = PvpProjectileBehaviorCode.Resolve(behaviorSO);\n                if (code == 0)\n                {\n                    Debug.LogWarning($\"[ProjectileBehaviorRegistry] Behavior has invalid network code 0: {behaviorSO.name}\");\n                    continue;\n                }\n\n                if (_behaviorByCode.ContainsKey(code))\n                {\n                    Debug.LogError($\"[ProjectileBehaviorRegistry] Duplicate behavior code {code}: {behaviorSO.name}\");\n                    continue;\n                }\n\n                _behaviorByCode.Add(code, behaviorSO);\n            }\n\n            Debug.Log($\"[ProjectileBehaviorRegistry] Registered {_behaviorByCode.Count} projectile behaviors.\");\n        }\n    }\n}\n", "Network/PvP/PvpMatchStateController.cs": "using Fusion;\nusing Shield_Shot.GameplayCore.Network.Match;\nusing UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Network.Pvp\n{\n    [RequireComponent(typeof(NetworkObject))]\n    public sealed class PvpMatchStateController : NetworkBehaviour\n    {\n        [Header(\"Match Rule\")]\n        [SerializeField] private int _targetScore = 2;\n\n        [Header(\"Countdown\")]\n        [SerializeField] private float _countdownSeconds = 3f;\n\n        [Header(\"Round Flow\")]\n        [SerializeField] private float _roundEndDelaySeconds = 1.5f;\n\n        [Header(\"Arena Seed\")]\n        [SerializeField] private int _defaultArenaSeed = 12345;\n\n        [Networked]\n        public PvpMatchState CurrentState { get; private set; }\n\n        [Networked]\n        public int BottomScore { get; private set; }\n\n        [Networked]\n        public int TopScore { get; private set; }\n\n        [Networked]\n        private TickTimer CountdownTimer { get; set; }\n\n        [Networked]\n        private TickTimer RoundEndTimer { get; set; }\n\n        [Networked]\n        public NetworkBool BottomAugmentReady { get; private set; }\n\n        [Networked]\n        public NetworkBool TopAugmentReady { get; private set; }\n\n        [Networked]\n        public int ArenaSeed { get; private set; }\n\n        [Networked]\n        public NetworkBool ArenaSeedInitialized { get; private set; }\n\n        public int TargetScore => _targetScore;\n\n        public bool IsFighting => CurrentState == PvpMatchState.Fighting;\n        public bool IsCountdown => CurrentState == PvpMatchState.Countdown;\n        public bool IsMatchEnded => CurrentState == PvpMatchState.MatchEnded;\n\n        public float CountdownRemaining\n        {\n            get\n            {\n                if (Runner == null || !CountdownTimer.IsRunning)\n                {\n                    return 0f;\n                }\n\n                return Mathf.Max(0f, CountdownTimer.RemainingTime(Runner) ?? 0f);\n            }\n        }\n\n        public override void Spawned()\n        {\n            if (Object.HasStateAuthority)\n            {\n                BottomScore = 0;\n                TopScore = 0;\n                EnsureArenaSeedInitialized();\n                SetState(PvpMatchState.WaitingForPlayers);\n            }\n            BottomAugmentReady = false;\n            TopAugmentReady = false;\n            Debug.Log($\"[PvpMatchStateController] Spawned. StateAuthority: {Object.HasStateAuthority}\");\n        }\n\n        public void EnsureArenaSeedInitialized()\n        {\n            if (!Object.HasStateAuthority || ArenaSeedInitialized)\n            {\n                return;\n            }\n\n            int tickSeed = Runner != null ? Runner.Tick.Raw : 0;\n            ArenaSeed = _defaultArenaSeed ^ tickSeed ^ System.Environment.TickCount;\n            ArenaSeedInitialized = true;\n\n            Debug.Log($\"[PvpMatchStateController] Arena seed initialized: {ArenaSeed}\");\n        }\n\n        public override void FixedUpdateNetwork()\n        {\n            if (!Object.HasStateAuthority)\n            {\n                return;\n            }\n\n            if (CurrentState == PvpMatchState.Countdown &&\n                CountdownTimer.Expired(Runner))\n            {\n                StartFight();\n                return;\n            }\n\n            if (CurrentState == PvpMatchState.RoundEnded &&\n                RoundEndTimer.Expired(Runner))\n            {\n                StartAugmentSelection();\n            }\n        }\n\n        public void StartCountdown()\n        {\n            if (!Object.HasStateAuthority)\n            {\n                return;\n            }\n\n            if (CurrentState == PvpMatchState.MatchEnded ||\n                CurrentState == PvpMatchState.ReturningToLobby)\n            {\n                return;\n            }\n\n            CountdownTimer = TickTimer.CreateFromSeconds(Runner, _countdownSeconds);\n            SetState(PvpMatchState.Countdown);\n\n            Debug.Log($\"[PvpMatchStateController] Countdown started: {_countdownSeconds}s\");\n        }\n\n        public void StartFight()\n        {\n            if (!Object.HasStateAuthority)\n            {\n                return;\n            }\n\n            CountdownTimer = TickTimer.None;\n            SetState(PvpMatchState.Fighting);\n\n            Debug.Log(\"[PvpMatchStateController] Fight started.\");\n        }\n\n        private void StartRoundEndDelay()\n        {\n            if (!Object.HasStateAuthority)\n            {\n                return;\n            }\n\n            RoundEndTimer = TickTimer.CreateFromSeconds(Runner, _roundEndDelaySeconds);\n            SetState(PvpMatchState.RoundEnded);\n\n            Debug.Log($\"[PvpMatchStateController] Round end delay started: {_roundEndDelaySeconds}s\");\n        }\n\n        private void StartAugmentSelection()\n        {\n            if (!Object.HasStateAuthority)\n            {\n                return;\n            }\n            BottomAugmentReady = false;\n            TopAugmentReady = false;\n            RoundEndTimer = TickTimer.None;\n            SetState(PvpMatchState.AugmentSelection);\n\n            Debug.Log(\"[PvpMatchStateController] Augment selection started.\");\n        }\n\n        public void SetState(PvpMatchState nextState)\n        {\n            if (!Object.HasStateAuthority)\n            {\n                return;\n            }\n\n            if (CurrentState == nextState)\n            {\n                return;\n            }\n\n            PvpMatchState previousState = CurrentState;\n            CurrentState = nextState;\n\n            Debug.Log($\"[PvpMatchStateController] State changed: {previousState} -> {CurrentState}\");\n        }\n\n        public void AddScore(PlayerSide scoringSide)\n        {\n            if (!Object.HasStateAuthority)\n            {\n                return;\n            }\n\n            if (CurrentState == PvpMatchState.MatchEnded ||\n                CurrentState == PvpMatchState.ReturningToLobby)\n            {\n                return;\n            }\n\n            if (scoringSide == PlayerSide.Bottom)\n            {\n                BottomScore++;\n                Debug.Log($\"[PvpMatchStateController] Bottom scored. Score: {BottomScore}/{_targetScore}\");\n            }\n            else\n            {\n                TopScore++;\n                Debug.Log($\"[PvpMatchStateController] Top scored. Score: {TopScore}/{_targetScore}\");\n            }\n\n            if (BottomScore >= _targetScore || TopScore >= _targetScore)\n            {\n                SetState(PvpMatchState.MatchEnded);\n                return;\n            }\n\n            StartRoundEndDelay();\n        }\n\n        public void ResetScores()\n        {\n            if (!Object.HasStateAuthority)\n            {\n                return;\n            }\n\n            BottomScore = 0;\n            TopScore = 0;\n            Debug.Log(\"[PvpMatchStateController] Scores reset.\");\n        }\n\n        public void NotifyLocalAugmentSelectionCompleted(PlayerSide playerSide)\n        {\n            if (CurrentState != PvpMatchState.AugmentSelection)\n            {\n                Debug.LogWarning($\"[PvpMatchStateController] Ignore augment ready. CurrentState: {CurrentState}\");\n                return;\n            }\n\n            if (Object.HasStateAuthority)\n            {\n                SetAugmentReady(playerSide);\n                return;\n            }\n\n            RPC_SetAugmentReady(playerSide);\n        }\n\n        [Rpc(RpcSources.All, RpcTargets.StateAuthority)]\n        private void RPC_SetAugmentReady(PlayerSide playerSide)\n        {\n            SetAugmentReady(playerSide);\n        }\n\n        private void SetAugmentReady(PlayerSide playerSide)\n        {\n            if (!Object.HasStateAuthority)\n            {\n                return;\n            }\n\n            if (CurrentState != PvpMatchState.AugmentSelection)\n            {\n                return;\n            }\n\n            if (playerSide == PlayerSide.Bottom)\n            {\n                BottomAugmentReady = true;\n                Debug.Log(\"[PvpMatchStateController] Bottom augment ready.\");\n            }\n            else\n            {\n                TopAugmentReady = true;\n                Debug.Log(\"[PvpMatchStateController] Top augment ready.\");\n            }\n\n            if (BottomAugmentReady && TopAugmentReady)\n            {\n                PrepareNextRound();\n            }\n        }\n\n        private void PrepareNextRound()\n        {\n            if (!Object.HasStateAuthority)\n            {\n                return;\n            }\n\n            ResetAllWeaponHealth();\n\n            BottomAugmentReady = false;\n            TopAugmentReady = false;\n\n            StartCountdown();\n\n            Debug.Log(\"[PvpMatchStateController] Next round prepared.\");\n        }\n\n        private void ResetAllWeaponHealth()\n        {\n            PvpWeaponHealth[] healths = FindObjectsByType<PvpWeaponHealth>(\n                FindObjectsInactive.Exclude,\n                FindObjectsSortMode.None\n            );\n\n            for (int i = 0; i < healths.Length; i++)\n            {\n                if (healths[i] == null)\n                {\n                    continue;\n                }\n\n                healths[i].ResetHealth();\n            }\n        }\n    }\n}\n", "Network/PvP/PvpProjectileAugmentEntry.cs": "using System;\nusing Fusion;\nusing Shield_Shot.GameplayCore.Weapon.Projectile;\n\nnamespace Shield_Shot.GameplayCore.Network.Pvp\n{\n    [Serializable]\n    public struct PvpProjectileAugmentEntry : INetworkStruct\n    {\n        public int BehaviorCode;\n        public int Level;\n\n        public bool IsValid => BehaviorCode != 0 && Level > 0;\n\n        public PvpProjectileAugmentEntry(int behaviorCode, int level)\n        {\n            BehaviorCode = behaviorCode;\n            Level = level;\n        }\n    }\n\n    public static class PvpProjectileBehaviorCode\n    {\n        // Code format: thousands digit = major category, hundreds digit = subcategory, last two digits = effect index.\n        // 1000 Reflect, 2000 Pierce, 3000 Split/Clone, 4000 Targeting/Chain, 5000 Damage, 6000 Status, 9000 Visual/System.\n        public const int StandardReflect = 1101;\n        public const int RandomReflect = 1201;\n        public const int Pierce = 2101;\n        public const int Split = 3101;\n        public const int ChainLightning = 4101;\n        public const int DefaultDamage = 5101;\n        public const int Poison = 6101;\n        public const int ElementTrailFire = 6201;\n        public const int ElementTrailWind = 6202;\n        public const int WindFieldBoost = 6203;\n        public const int ElementTrailIce = 6204;\n        public const int FreezeHit = 6205;\n        public const int HitImpactFX = 9101;\n        public const int WallCollisionFX = 9201;\n\n        public static int Resolve(ProjectileBehaviorSO behaviorSO)\n        {\n            if (behaviorSO == null)\n            {\n                return 0;\n            }\n\n            if (behaviorSO.NetworkCode != 0)\n            {\n                return behaviorSO.NetworkCode;\n            }\n\n            string id = string.IsNullOrWhiteSpace(behaviorSO.BehaviorID)\n                ? string.Empty\n                : behaviorSO.BehaviorID.Trim();\n            string typeName = behaviorSO.GetType().Name;\n\n            if (id == \"1\" ||\n                string.Equals(id, \"StandardReflect\", StringComparison.OrdinalIgnoreCase) ||\n                typeName.IndexOf(\"StandardReflect\", StringComparison.OrdinalIgnoreCase) >= 0)\n            {\n                return StandardReflect;\n            }\n\n            if (string.Equals(id, \"RandomReflect\", StringComparison.OrdinalIgnoreCase) ||\n                typeName.IndexOf(\"RandomReflect\", StringComparison.OrdinalIgnoreCase) >= 0)\n            {\n                return RandomReflect;\n            }\n\n            if (string.Equals(id, \"Pierce\", StringComparison.OrdinalIgnoreCase) ||\n                typeName.IndexOf(\"Pierce\", StringComparison.OrdinalIgnoreCase) >= 0)\n            {\n                return Pierce;\n            }\n\n            if (string.Equals(id, \"Split\", StringComparison.OrdinalIgnoreCase) ||\n                typeName.IndexOf(\"Split\", StringComparison.OrdinalIgnoreCase) >= 0)\n            {\n                return Split;\n            }\n\n            if (string.Equals(id, \"DefaultDamage\", StringComparison.OrdinalIgnoreCase) ||\n                typeName.IndexOf(\"DefaultDamage\", StringComparison.OrdinalIgnoreCase) >= 0)\n            {\n                return DefaultDamage;\n            }\n\n            if (string.Equals(id, \"ChainLightning\", StringComparison.OrdinalIgnoreCase) ||\n                typeName.IndexOf(\"ChainLightning\", StringComparison.OrdinalIgnoreCase) >= 0)\n            {\n                return ChainLightning;\n            }\n\n            if (string.Equals(id, \"Poison\", StringComparison.OrdinalIgnoreCase) ||\n                typeName.IndexOf(\"Poison\", StringComparison.OrdinalIgnoreCase) >= 0)\n            {\n                return Poison;\n            }\n\n            if (string.Equals(id, \"ElementTrail_Wind\", StringComparison.OrdinalIgnoreCase) ||\n                string.Equals(id, \"ElementTrailWind\", StringComparison.OrdinalIgnoreCase))\n            {\n                return ElementTrailWind;\n            }\n\n            if (string.Equals(id, \"ElementTrail_Ice\", StringComparison.OrdinalIgnoreCase) ||\n                string.Equals(id, \"ElementTrailIce\", StringComparison.OrdinalIgnoreCase))\n            {\n                return ElementTrailIce;\n            }\n\n            if (string.Equals(id, \"FreezeHit\", StringComparison.OrdinalIgnoreCase) ||\n                typeName.IndexOf(\"Freeze\", StringComparison.OrdinalIgnoreCase) >= 0)\n            {\n                return FreezeHit;\n            }\n\n            if (string.Equals(id, \"WindFieldBoost\", StringComparison.OrdinalIgnoreCase) ||\n                typeName.IndexOf(\"WindFieldBoost\", StringComparison.OrdinalIgnoreCase) >= 0)\n            {\n                return WindFieldBoost;\n            }\n\n            if (string.Equals(id, \"ElementTrail_Fire\", StringComparison.OrdinalIgnoreCase) ||\n                string.Equals(id, \"ElementTrailFire\", StringComparison.OrdinalIgnoreCase) ||\n                typeName.IndexOf(\"ElementTrail\", StringComparison.OrdinalIgnoreCase) >= 0)\n            {\n                return ElementTrailFire;\n            }\n\n            if (string.Equals(id, \"HitImpactFX\", StringComparison.OrdinalIgnoreCase) ||\n                typeName.IndexOf(\"HitFX\", StringComparison.OrdinalIgnoreCase) >= 0)\n            {\n                return HitImpactFX;\n            }\n\n            if (string.Equals(id, \"WallCollisionFX\", StringComparison.OrdinalIgnoreCase) ||\n                typeName.IndexOf(\"CollisionFX\", StringComparison.OrdinalIgnoreCase) >= 0)\n            {\n                return WallCollisionFX;\n            }\n\n            return 0;\n        }\n    }\n}\n", "Network/PvP/PvpProjectileAugmentPayload.cs": "using System;\nusing Fusion;\n\nnamespace Shield_Shot.GameplayCore.Network.Pvp\n{\n    [Serializable]\n    public struct PvpProjectileAugmentPayload : INetworkStruct\n    {\n        public const int MaxEntries = 8;\n\n        public PvpProjectileAugmentEntry Entry0;\n        public PvpProjectileAugmentEntry Entry1;\n        public PvpProjectileAugmentEntry Entry2;\n        public PvpProjectileAugmentEntry Entry3;\n        public PvpProjectileAugmentEntry Entry4;\n        public PvpProjectileAugmentEntry Entry5;\n        public PvpProjectileAugmentEntry Entry6;\n        public PvpProjectileAugmentEntry Entry7;\n\n        public bool HasAnyAugment =>\n            Entry0.IsValid ||\n            Entry1.IsValid ||\n            Entry2.IsValid ||\n            Entry3.IsValid ||\n            Entry4.IsValid ||\n            Entry5.IsValid ||\n            Entry6.IsValid ||\n            Entry7.IsValid;\n\n        public bool TryAdd(PvpProjectileAugmentEntry entry)\n        {\n            if (!entry.IsValid)\n            {\n                return false;\n            }\n\n            if (!Entry0.IsValid) { Entry0 = entry; return true; }\n            if (!Entry1.IsValid) { Entry1 = entry; return true; }\n            if (!Entry2.IsValid) { Entry2 = entry; return true; }\n            if (!Entry3.IsValid) { Entry3 = entry; return true; }\n            if (!Entry4.IsValid) { Entry4 = entry; return true; }\n            if (!Entry5.IsValid) { Entry5 = entry; return true; }\n            if (!Entry6.IsValid) { Entry6 = entry; return true; }\n            if (!Entry7.IsValid) { Entry7 = entry; return true; }\n\n            return false;\n        }\n\n        public PvpProjectileAugmentEntry GetEntry(int index)\n        {\n            return index switch\n            {\n                0 => Entry0,\n                1 => Entry1,\n                2 => Entry2,\n                3 => Entry3,\n                4 => Entry4,\n                5 => Entry5,\n                6 => Entry6,\n                7 => Entry7,\n                _ => default\n            };\n        }\n\n        public void ForEach(Action<PvpProjectileAugmentEntry> action)\n        {\n            if (action == null)\n            {\n                return;\n            }\n\n            for (int i = 0; i < MaxEntries; i++)\n            {\n                PvpProjectileAugmentEntry entry = GetEntry(i);\n                if (entry.IsValid)\n                {\n                    action.Invoke(entry);\n                }\n            }\n        }\n\n        public static PvpProjectileAugmentPayload Empty => default;\n    }\n}\n", "Network/PvP/PvpWeaponActorIdentity.cs": "using Fusion;\nusing Shield_Shot.GameplayCore.Network.Match;\nusing UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Network.Pvp\n{\n    [RequireComponent(typeof(NetworkObject))]\n    public sealed class PvpWeaponActorIdentity : NetworkBehaviour\n    {\n        private const string PlayerHitboxName = \"Player\";\n\n        [Networked] public PlayerRef Owner { get; private set; }\n        [Networked] public int SideValue { get; private set; }\n        [Networked] public Vector3 SpawnPosition { get; private set; }\n        [Networked] public Vector3 SpawnEulerAngles { get; private set; }\n        [Networked] public float SpawnScale { get; private set; }\n        [Networked] public NetworkBool SpawnPoseInitialized { get; private set; }\n\n        public PlayerSide Side => (PlayerSide)SideValue;\n        public bool IsLocalActor => Object != null && Object.HasInputAuthority;\n\n        private bool _spawnPoseApplied;\n\n        public void Initialize(PlayerRef owner, PlayerSide side)\n        {\n            Initialize(owner, side, new Pose(transform.position, transform.rotation), transform.localScale.x);\n        }\n\n        public void Initialize(PlayerRef owner, PlayerSide side, Pose spawnPose)\n        {\n            Initialize(owner, side, spawnPose, transform.localScale.x);\n        }\n\n        public void Initialize(PlayerRef owner, PlayerSide side, Pose spawnPose, float spawnScale)\n        {\n            Owner = owner;\n            SideValue = (int)side;\n            SpawnPosition = spawnPose.position;\n            SpawnEulerAngles = spawnPose.rotation.eulerAngles;\n            SpawnScale = Mathf.Max(0.01f, spawnScale);\n            SpawnPoseInitialized = true;\n            transform.SetPositionAndRotation(spawnPose.position, spawnPose.rotation);\n            transform.localScale = Vector3.one * SpawnScale;\n            _spawnPoseApplied = true;\n        }\n\n        public override void Spawned()\n        {\n            ApplyPvpWeaponLayer();\n            ApplyNetworkSpawnPose();\n            RenameForDebug();\n\n            Debug.Log(\n                $\"[PvpWeaponActorIdentity] Spawned. \" +\n                $\"Owner: {Owner}, \" +\n                $\"Side: {Side}, \" +\n                $\"HasInputAuthority: {Object.HasInputAuthority}, \" +\n                $\"HasStateAuthority: {Object.HasStateAuthority}, \" +\n                $\"SpawnPoseInitialized: {SpawnPoseInitialized}, \" +\n                $\"Position: {transform.position}, \" +\n                $\"NetworkSpawnPosition: {SpawnPosition}\");\n\n            LogColliderDiagnostics();\n        }\n\n        public override void Render()\n        {\n            ApplyNetworkSpawnPose();\n        }\n\n        private void ApplyNetworkSpawnPose()\n        {\n            if (!SpawnPoseInitialized || _spawnPoseApplied)\n            {\n                return;\n            }\n\n            Quaternion rotation = Quaternion.Euler(SpawnEulerAngles);\n            transform.SetPositionAndRotation(SpawnPosition, rotation);\n            transform.localScale = Vector3.one * Mathf.Max(0.01f, SpawnScale);\n            _spawnPoseApplied = true;\n        }\n\n        private void ApplyPvpWeaponLayer()\n        {\n            int pvpWeaponLayer = LayerMask.NameToLayer(\"PvpWeapon\");\n            if (pvpWeaponLayer < 0)\n            {\n                Debug.LogWarning(\"[PvpWeaponActorIdentity] PvpWeapon layer is missing.\");\n                return;\n            }\n\n            gameObject.layer = pvpWeaponLayer;\n            ApplyPlayerHitboxLayer(pvpWeaponLayer);\n        }\n\n        private void ApplyPlayerHitboxLayer(int pvpWeaponLayer)\n        {\n            Transform[] transforms = GetComponentsInChildren<Transform>(true);\n            for (int i = 0; i < transforms.Length; i++)\n            {\n                Transform hitboxTransform = transforms[i];\n                if (hitboxTransform == null || hitboxTransform == transform)\n                {\n                    continue;\n                }\n\n                if (!IsPlayerHitbox(hitboxTransform))\n                {\n                    continue;\n                }\n\n                hitboxTransform.localPosition = Vector3.zero;\n                hitboxTransform.localRotation = Quaternion.identity;\n                hitboxTransform.localScale = Vector3.one;\n\n                Collider[] colliders = hitboxTransform.GetComponentsInChildren<Collider>(true);\n                for (int colliderIndex = 0; colliderIndex < colliders.Length; colliderIndex++)\n                {\n                    if (colliders[colliderIndex] == null)\n                    {\n                        continue;\n                    }\n\n                    colliders[colliderIndex].gameObject.layer = pvpWeaponLayer;\n                }\n\n                Debug.Log(\n                    $\"[PvpWeaponActorIdentity] Player hitbox normalized. Actor: {name}, Hitbox: {hitboxTransform.name}, WorldPosition: {hitboxTransform.position}\");\n            }\n        }\n\n        private static bool IsPlayerHitbox(Transform candidate)\n        {\n            return candidate.name == PlayerHitboxName || candidate.CompareTag(PlayerHitboxName);\n        }\n\n        private void LogColliderDiagnostics()\n        {\n            Collider[] colliders = GetComponentsInChildren<Collider>(true);\n            Debug.Log(\n                $\"[PvpWeaponActorIdentity] Collider diagnostics. Actor: {name}, Owner/Side: {Owner}/{Side}, Count: {colliders.Length}\");\n\n            for (int i = 0; i < colliders.Length; i++)\n            {\n                Collider collider = colliders[i];\n                if (collider == null)\n                {\n                    continue;\n                }\n\n                int layer = collider.gameObject.layer;\n                Debug.Log(\n                    $\"[PvpWeaponActorIdentity] Collider[{i}]. Actor: {name}, Collider: {collider.name}, Layer: {LayerMask.LayerToName(layer)}({layer}), IsTrigger: {collider.isTrigger}, Enabled: {collider.enabled}, BoundsCenter: {collider.bounds.center}, BoundsSize: {collider.bounds.size}\");\n            }\n        }\n\n        private void RenameForDebug()\n        {\n            string localLabel = IsLocalActor ? \"Local\" : \"Remote\";\n            gameObject.name = $\"PvpWeaponActor_{Side}_{Owner.PlayerId}_{localLabel}\";\n        }\n    }\n}\n", "Network/PvP/PvpWeaponHealth.cs": "using Fusion;\nusing Shield_Shot.GameplayCore.Common;\nusing Shield_Shot.GameplayCore.Monster.Status;\nusing Shield_Shot.GameplayCore.Network.Match;\nusing Shield_Shot.GameplayCore.Render;\nusing UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Network.Pvp\n{\n    [RequireComponent(typeof(NetworkObject))]\n    [RequireComponent(typeof(PvpWeaponActorIdentity))]\n    [RequireComponent(typeof(StatusEffectController))]\n    public sealed class PvpWeaponHealth : NetworkBehaviour, ITakeDamage\n    {\n        [Header(\"Health\")]\n        [SerializeField] private float _maxHealth = 100f;\n\n        [Header(\"References\")]\n        [SerializeField] private PvpMatchStateController _matchStateController;\n\n        [Networked] public float CurrentHealth { get; private set; }\n        [Networked] public NetworkBool IsDead { get; private set; }\n\n        public float HealthRatio => _maxHealth <= 0f\n    ? 0f\n    : Mathf.Clamp01(CurrentHealth / _maxHealth);\n\n        private PvpWeaponActorIdentity _identity;\n\n        private void Awake()\n        {\n            _identity = GetComponent<PvpWeaponActorIdentity>();\n\n            if (GetComponent<StatusEffectController>() == null)\n            {\n                gameObject.AddComponent<StatusEffectController>();\n            }\n\n            if (_matchStateController == null)\n            {\n                _matchStateController = FindFirstObjectByType<PvpMatchStateController>();\n            }\n        }\n\n        public override void Spawned()\n        {\n            if (Object.HasStateAuthority)\n            {\n                CurrentHealth = _maxHealth;\n                IsDead = false;\n            }\n\n            Debug.Log($\"[PvpWeaponHealth] Spawned. Owner: {_identity.Owner}, Side: {_identity.Side}, HP: {CurrentHealth}\");\n        }\n\n        public void ApplyDamage(float damage, NetworkProjectileIdentity sourceProjectile)\n        {\n            ApplyDamage(damage, sourceProjectile, transform.position, false);\n        }\n\n        public void TakeDamage(float damage)\n        {\n            ApplyDamage(damage, null, transform.position, false);\n        }\n\n        public void ApplyDamage(float damage, NetworkProjectileIdentity sourceProjectile, Vector3 hitPosition, bool isCritical)\n        {\n            if (!Object.HasStateAuthority || IsDead)\n            {\n                return;\n            }\n\n            if (damage <= 0f)\n            {\n                return;\n            }\n\n            if (_matchStateController == null)\n            {\n                _matchStateController = FindFirstObjectByType<PvpMatchStateController>();\n            }\n\n            if (_matchStateController != null &&\n                _matchStateController.CurrentState != PvpMatchState.Fighting)\n            {\n                return;\n            }\n\n            CurrentHealth = Mathf.Max(0f, CurrentHealth - damage);\n\n            Debug.Log($\"[PvpWeaponHealth] Damaged. Target: {_identity.Owner}/{_identity.Side}, Damage: {damage}, Critical: {isCritical}, HP: {CurrentHealth}\");\n            RPC_ShowDamagePopup(hitPosition, damage, isCritical);\n\n            if (CurrentHealth <= 0f)\n            {\n                Die(sourceProjectile);\n            }\n        }\n\n        [Rpc(RpcSources.StateAuthority, RpcTargets.All)]\n        private void RPC_ShowDamagePopup(Vector3 position, float damage, NetworkBool isCritical)\n        {\n            if (DamagePopupManager.Instance == null)\n            {\n                Debug.LogWarning(\"[PvpWeaponHealth] DamagePopupManager is missing.\");\n                return;\n            }\n\n            DamagePopupManager.Instance.Show(position, damage, isCritical);\n        }\n\n        private void Die(NetworkProjectileIdentity sourceProjectile)\n        {\n            if (IsDead)\n            {\n                return;\n            }\n\n            IsDead = true;\n\n            PlayerSide killerSide = ResolveKillerSide(sourceProjectile);\n\n            Debug.Log($\"[PvpWeaponHealth] Dead. Target: {_identity.Owner}/{_identity.Side}, KillerSide: {killerSide}\");\n\n            if (_matchStateController == null)\n            {\n                _matchStateController = FindFirstObjectByType<PvpMatchStateController>();\n            }\n\n            if (_matchStateController != null)\n            {\n                _matchStateController.AddScore(killerSide);\n            }\n            else\n            {\n                Debug.LogWarning(\"[PvpWeaponHealth] MatchStateController is missing.\");\n            }\n        }\n\n        public void ResetHealth()\n        {\n            if (!Object.HasStateAuthority)\n            {\n                return;\n            }\n\n            CurrentHealth = _maxHealth;\n            IsDead = false;\n\n            Debug.Log($\"[PvpWeaponHealth] Reset health. Owner: {_identity.Owner}, Side: {_identity.Side}, HP: {CurrentHealth}\");\n        }\n\n        private PlayerSide ResolveKillerSide(NetworkProjectileIdentity sourceProjectile)\n        {\n            if (sourceProjectile != null)\n            {\n                return sourceProjectile.OwnerSide;\n            }\n\n            return _identity.Side == PlayerSide.Bottom\n                ? PlayerSide.Top\n                : PlayerSide.Bottom;\n        }\n    }\n}\n", "Network/PvP/PvpWeaponHitTarget.cs": "using Fusion;\nusing Shield_Shot.GameplayCore.Weapon.Projectile;\nusing UnityEngine;\n\nnamespace Shield_Shot.GameplayCore.Network.Pvp\n{\n    [RequireComponent(typeof(PvpWeaponActorIdentity))]\n    public sealed class PvpWeaponHitTarget : NetworkBehaviour\n    {\n        [Header(\"Damage Rules\")]\n        [Tooltip(\"true = 자기 투사체도 데미지 / false = 상대 투사체만 데미지\")]\n        [SerializeField] private bool _allowSelfDamage = true;\n\n        [Tooltip(\"발사 후 이 시간(초) 동안은 자기 투사체에 무적 (자해 방지)\")]\n        [SerializeField] private float _selfDamageGracePeriod = 0.5f;\n\n        [SerializeField] private float _testDamage = 10f;\n\n        private PvpWeaponHealth _health;\n        private PvpWeaponActorIdentity _identity;\n\n        private void Awake()\n        {\n            _health = GetComponent<PvpWeaponHealth>();\n            _identity = GetComponent<PvpWeaponActorIdentity>();\n        }\n\n        public bool CanBeHitBy(NetworkProjectileIdentity projectileIdentity)\n        {\n            if (projectileIdentity == null || _identity == null)\n                return false;\n\n            bool isSelf = projectileIdentity.Owner == _identity.Owner;\n\n            if (!isSelf) return true; // 상대 투사체는 항상 데미지\n\n            if (!_allowSelfDamage) return false; // 자해 비활성화\n\n            // 발사 직후 유예 시간 동안 자기 투사체 무적\n            float elapsed = Time.time - projectileIdentity.SpawnTime;\n            if (elapsed < _selfDamageGracePeriod) return false;\n\n            return true;\n        }\n\n        public void NotifyHit(NetworkProjectileIdentity projectileIdentity, ProjectileBase projectile, Collider hitCollider)\n        {\n            if (!CanBeHitBy(projectileIdentity))\n                return;\n\n            float damage = projectile != null && projectile.ProjectileDamage > 0f\n                ? projectile.ProjectileDamage\n                : _testDamage;\n            bool isCritical = projectile != null && projectile.IsCritical;\n            Vector3 hitPosition = hitCollider != null\n                ? hitCollider.bounds.center\n                : transform.position;\n\n            Debug.Log($\"[PvpWeaponHitTarget] Hit. Target: {_identity.Owner}/{_identity.Side}, \" +\n                      $\"ProjectileOwner: {projectileIdentity?.Owner}/{projectileIdentity?.OwnerSide}, \" +\n                      $\"Damage: {damage}, Critical: {isCritical}\");\n\n            _health?.ApplyDamage(damage, projectileIdentity, hitPosition, isCritical);\n        }\n    }\n}\n"};

