const treeGroups = [
  { title: "Systems", ids: ["overview", "augment", "field", "pvpProjectile", "aimPrediction", "hitFeedback", "networkSpawn"] },
  { title: "Projectile / Augment", ids: ["ProjectileBehaviorSO", "ProjectileShooter", "ProjectileBase", "ProjectileBehaviorRegistry", "PvpProjectileAugmentPayload", "PvpProjectileAugmentEntry"] },
  { title: "ElementField / Arena", ids: ["ElementFieldGrid", "ElementFieldCellData", "ElementReactionResolver", "ElementFieldEffectSystem", "ElementFieldVisualController", "ArenaTerrainPainter", "ArenaRandomReflectWallBuilder"] },
  { title: "PvP Network", ids: ["NetworkProjectileFireHandler", "NetworkProjectileActor", "PvpWeaponActorIdentity", "PvpWeaponHitTarget", "PvpWeaponHealth", "PvpMatchStateController"] },
  { title: "Weapon / Shield / Aim", ids: ["NetworkWeaponManager", "NetworkShieldSpawnSetup", "NetworkShieldActor", "NetworkShieldColliderDetector", "AimLineRenderer", "IProjectileAimPredictionProvider", "WeaponBase"] },
];

let currentNodeId = "overview";
let currentCodeFiles = [];
let graphScale = 1;
let graphBaseSize = { width: 760, height: 420 };
const navStack = [];

const els = {
  tree: document.getElementById("tree"),
  title: document.getElementById("node-title"),
  summary: document.getElementById("node-summary"),
  graphWrap: document.getElementById("graph-wrap"),
  graph: document.getElementById("graph"),
  intent: document.getElementById("intent"),
  issue: document.getElementById("issue"),
  final: document.getElementById("final"),
  next: document.getElementById("next"),
  scripts: document.getElementById("script-list"),
  evidence: document.getElementById("evidence"),
  codePath: document.getElementById("code-path"),
  codeActions: document.getElementById("code-actions"),
  codePreview: document.getElementById("code-preview"),
};

mermaid.initialize({
  startOnLoad: false,
  securityLevel: "loose",
  theme: "base",
  flowchart: { htmlLabels: true, curve: "basis", nodeSpacing: 55, rankSpacing: 70 },
  themeVariables: {
    primaryColor: "#fff8e8",
    primaryTextColor: "#1d232d",
    primaryBorderColor: "#a56a22",
    lineColor: "#6f7785",
    secondaryColor: "#e8f7f5",
    tertiaryColor: "#f4f6fa",
    fontFamily: "Segoe UI, Noto Sans KR, Arial",
    fontSize: "16px",
  },
});

function classGraph(name, members, links) {
  const body = members.map((member) => `        ${member}`).join("\n");
  const relations = links.map((link) => `      ${name} --> ${link}`).join("\n");
  return `classDiagram
      class ${name} {
${body}
      }
${relations}`;
}

function renderTree() {
  els.tree.innerHTML = "";
  treeGroups.forEach((group) => {
    const wrapper = document.createElement("div");
    wrapper.className = "tree-group";
    const title = document.createElement("div");
    title.className = "tree-title";
    title.textContent = group.title;
    wrapper.appendChild(title);

    group.ids.forEach((id) => {
      const node = nodes[id];
      if (!node) return;
      const button = document.createElement("button");
      button.type = "button";
      button.className = `tree-item ${node.kind === "class" ? "child" : ""}`;
      button.dataset.id = id;
      button.textContent = node.title;
      button.addEventListener("click", () => selectNode(id));
      wrapper.appendChild(button);
    });

    els.tree.appendChild(wrapper);
  });
}

async function selectNode(id, options = {}) {
  const node = nodes[id];
  if (!node) return;
  const shouldPushHistory = options.pushHistory !== false && currentNodeId && currentNodeId !== id;
  if (shouldPushHistory) navStack.push(currentNodeId);
  currentNodeId = id;
  updateBackButton();
  graphScale = 1;
  document.querySelectorAll(".tree-item").forEach((item) => item.classList.toggle("active", item.dataset.id === id));
  els.title.textContent = node.title;
  els.summary.textContent = node.summary || "";
  els.intent.textContent = node.intent || "";
  els.issue.textContent = node.issue || "";
  els.final.textContent = node.final || "";
  els.next.textContent = node.next || "";
  renderScripts(node);
  renderEvidence(node);
  await renderGraph(node);
  if (node.code && node.code.length) {
    await loadCode(node.code[0], node.code[0].focus);
  } else {
    currentCodeFiles = [];
    els.codePath.textContent = "";
    els.codeActions.innerHTML = "";
    els.codePreview.innerHTML = "<code>이 노드는 구조 설명 중심입니다. Core Scripts에서 클래스를 선택하면 코드 스냅샷이 표시됩니다.</code>";
  }
}

function renderScripts(node) {
  els.scripts.innerHTML = "";
  (node.classes || []).forEach((id) => {
    const target = nodes[id];
    if (!target) return;
    const card = document.createElement("article");
    card.className = "script-card";
    const button = document.createElement("button");
    button.type = "button";
    button.textContent = target.title;
    button.addEventListener("click", () => selectNode(id));
    const desc = document.createElement("p");
    desc.textContent = target.summary || "핵심 스크립트";
    card.append(button, desc);
    els.scripts.appendChild(card);
  });
}

function renderEvidence(node) {
  els.evidence.innerHTML = "";
  (node.evidence || []).forEach((item) => {
    const button = document.createElement("button");
    button.type = "button";
    button.className = "evidence-item";
    button.innerHTML = `<img src="${item.src}" alt=""><span>${item.caption}</span>`;
    button.addEventListener("click", () => openMedia(item));
    els.evidence.appendChild(button);
  });
}

async function renderGraph(node) {
  els.graph.className = "mermaid";
  els.graph.removeAttribute("data-processed");
  els.graph.textContent = node.graph || "flowchart TD\nempty[No graph]";
  try {
    await mermaid.run({ nodes: [els.graph] });
    captureGraphBaseSize();
    applyGraphScale();
    attachGraphClicks(node);
  } catch (err) {
    els.graph.className = "graph-error";
    els.graph.innerHTML = `<strong>Mermaid diagram을 렌더링하지 못했습니다.</strong><pre>${escapeHtml(node.graph || "")}</pre>`;
  }
}

function attachGraphClicks(node) {
  const labels = new Map();
  Object.entries(nodes).forEach(([id, item]) => labels.set(normalizeLabel(item.title), id));
  (node.classes || []).forEach((id) => {
    if (nodes[id]) labels.set(normalizeLabel(nodes[id].title), id);
  });
  const systemAliases = {
    "projectile behavior augment": "augment",
    "elementfield grid": "field",
    "pvp network combat": "pvpProjectile",
    "aim prediction": "aimPrediction",
    "network weapon shield": "networkSpawn",
    "hit vfx popup sync": "hitFeedback",
  };
  Object.entries(systemAliases).forEach(([label, id]) => labels.set(label, id));

  els.graph.querySelectorAll("g.node, g.classGroup").forEach((group) => {
    const label = normalizeLabel(group.textContent || "");
    const target = labels.get(label);
    if (!target) return;
    group.classList.add("graph-clickable");
    group.addEventListener("click", () => selectNode(target));
  });

  const currentMethods = collectCurrentMethods();
  els.graph.querySelectorAll("text, span").forEach((textNode) => {
    const label = textNode.textContent || "";
    const method = currentMethods.find((name) => label.includes(name));
    if (!method) return;
    const clickable = textNode.closest("g") || textNode;
    clickable.classList.add("graph-method-clickable");
    clickable.addEventListener("click", (event) => {
      event.stopPropagation();
      jumpToMethod(method);
    });
  });
}

function normalizeLabel(value) {
  return value
    .replace(/[+#+\-()[\]{}:,]/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .toLowerCase()
    .replace(/\s*&\s*/g, " ")
    .replace(/\s*\/\s*/g, " ");
}

function collectCurrentMethods() {
  const node = nodes[currentNodeId];
  const methods = [];
  (node?.code || []).forEach((file) => methods.push(...(file.methods || [])));
  return [...new Set(methods)];
}

async function loadCode(file, focus) {
  currentCodeFiles = [file];
  els.codePath.innerHTML = `<a href="${repoBase}${sourceBase}${file.path}" target="_blank" rel="noreferrer">${sourceBase}${file.path}</a>`;
  els.codeActions.innerHTML = "";
  (file.methods || []).forEach((method) => {
    const button = document.createElement("button");
    button.type = "button";
    button.textContent = method;
    button.addEventListener("click", () => jumpToMethod(method));
    els.codeActions.appendChild(button);
  });

  const source = await getSource(file.path);
  renderSource(source, focus);
}

async function getSource(path) {
  if (sourceCache[path]) return sourceCache[path];
  try {
    const response = await fetch(sourceBase + path);
    if (response.ok) return response.text();
  } catch (err) {
    // file:// 환경에서는 fetch가 막힐 수 있어 sourceCache를 우선 사용합니다.
  }
  return `// 코드 스냅샷을 불러오지 못했습니다.\n// Expected: ${sourceBase}${path}`;
}

function renderSource(source, focus) {
  const lines = source.replace(/\r\n/g, "\n").split("\n");
  const focusLine = findLine(lines, focus);
  els.codePreview.innerHTML = lines.map((line, index) => {
    const lineNo = index + 1;
    const hit = focusLine && Math.abs(lineNo - focusLine) <= 1 ? " hit" : "";
    return `<div class="code-line${hit}" data-line="${lineNo}"><span class="line-no">${lineNo}</span><code>${highlight(line)}</code></div>`;
  }).join("");
  if (focusLine) scrollToLine(focusLine);
}

async function jumpToMethod(method) {
  const file = currentCodeFiles[0];
  if (!file) return;
  const source = await getSource(file.path);
  renderSource(source, method);
}

function findLine(lines, needle) {
  if (!needle) return 1;
  const pattern = new RegExp(`\\b${escapeRegExp(needle)}\\b`);
  const index = lines.findIndex((line) => pattern.test(line));
  return index >= 0 ? index + 1 : 1;
}

function scrollToLine(lineNo) {
  requestAnimationFrame(() => {
    const line = els.codePreview.querySelector(`[data-line="${lineNo}"]`);
    if (line) line.scrollIntoView({ block: "center" });
  });
}

function highlight(line) {
  let escaped = escapeHtml(line);
  if (/^\s*\/\//.test(line)) return `<span class="com">${escaped}</span>`;
  escaped = escaped.replace(/"([^"\\]|\\.)*"/g, (match) => `<span class="str">${match}</span>`);
  escaped = escaped.replace(/\b(public|private|protected|internal|static|readonly|override|virtual|sealed|class|struct|interface|enum|void|bool|int|float|string|var|return|if|else|for|foreach|while|switch|case|break|continue|new|using|namespace|async|await|ref|out|in)\b/g, '<span class="kw">$1</span>');
  escaped = escaped.replace(/\b(Vector2|Vector3|Quaternion|Transform|GameObject|NetworkObject|NetworkBehaviour|NetworkRunner|PlayerRef|List|Dictionary|HashSet)\b/g, '<span class="type">$1</span>');
  return escaped;
}

function escapeHtml(value) {
  return String(value).replace(/[&<>"']/g, (ch) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" }[ch]));
}

function escapeRegExp(value) {
  return String(value).replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function openMedia(item) {
  const modal = document.getElementById("media-modal");
  document.getElementById("modal-image").src = item.src;
  document.getElementById("modal-caption").textContent = item.caption;
  modal.showModal();
}

function captureGraphBaseSize() {
  const svg = els.graph.querySelector("svg");
  if (!svg) return;
  const viewBox = svg.viewBox && svg.viewBox.baseVal;
  const width = viewBox && viewBox.width ? viewBox.width : parseFloat(svg.getAttribute("width")) || svg.getBoundingClientRect().width || 760;
  const height = viewBox && viewBox.height ? viewBox.height : parseFloat(svg.getAttribute("height")) || svg.getBoundingClientRect().height || 420;
  graphBaseSize = { width: Math.max(width, 320), height: Math.max(height, 220) };
}

function applyGraphScale() {
  const svg = els.graph.querySelector("svg");
  if (svg) {
    svg.style.width = `${graphBaseSize.width * graphScale}px`;
    svg.style.height = `${graphBaseSize.height * graphScale}px`;
  }
  els.graph.style.width = `${graphBaseSize.width * graphScale}px`;
  els.graph.style.height = `${graphBaseSize.height * graphScale}px`;
  document.getElementById("zoom-reset").textContent = `${Math.round(graphScale * 100)}%`;
}

function setGraphScale(next) {
  graphScale = Math.max(0.55, Math.min(2.4, next));
  applyGraphScale();
}

document.getElementById("zoom-out").addEventListener("click", () => setGraphScale(graphScale - 0.15));
document.getElementById("zoom-in").addEventListener("click", () => setGraphScale(graphScale + 0.15));
document.getElementById("zoom-reset").addEventListener("click", () => setGraphScale(1));
els.graphWrap.addEventListener("wheel", (event) => {
  if (!event.ctrlKey && !event.shiftKey) return;
  event.preventDefault();
  setGraphScale(graphScale + (event.deltaY < 0 ? 0.12 : -0.12));
}, { passive: false });

function updateBackButton() {
  const button = document.getElementById("nav-back");
  if (!button) return;
  button.disabled = navStack.length === 0;
}

document.getElementById("nav-back").addEventListener("click", () => {
  const previous = navStack.pop();
  if (previous) selectNode(previous, { pushHistory: false });
  updateBackButton();
});

document.getElementById("theme-toggle").addEventListener("click", () => {
  const enabled = document.body.classList.toggle("light-theme");
  document.getElementById("theme-toggle").textContent = enabled ? "Black" : "White";
});

document.getElementById("modal-close").addEventListener("click", () => document.getElementById("media-modal").close());

window.selectNode = selectNode;
renderTree();
selectNode("overview", { pushHistory: false });
